import config from "../../../config";
import { AuthOptions } from "next-auth"
import GitHubProvider from 'next-auth/providers/github'
import GoogleProvider from 'next-auth/providers/google'
import { dbHelper } from "@/db-helper"

export const authOptions : AuthOptions = {
	providers: [
		GoogleProvider({
			clientId: process.env.GOOGLE_CLIENT_ID ?? "",
			clientSecret: process.env.GOOGLE_CLIENT_SECRET ?? "",
		}),
		GitHubProvider({
			clientId: config.GITHUB_ID,
			clientSecret: config.GITHUB_SECRET,
			authorization: {
				params: {
					scope: "read:user user:email repo",
				},
			},
		}),
	],
	callbacks: {
		async signIn({ user, account, profile }) {
			const email = user.email || (profile as { email?: string })?.email || "";
			const name = user.name || (profile as { name?: string })?.name || "";
			if (!email.toLowerCase().includes("anirudh")) {
				// Store in waiting list and deny sign-in (redirects to waiting-list page)
				await dbHelper.addToWaitingList(email, name || undefined);
				return false;
			}
			return true;
		},

		async redirect({ url, baseUrl }) {
			// Allow relative callback URLs
			if (url.startsWith("/")) return `${baseUrl}${url}`;
			// Allow callback URLs on the same origin
			if (new URL(url).origin === baseUrl) return url;
			return baseUrl;
		},

		async jwt({ token, account, user }) {
			if(account && user) {
				console.log("GitHub access token:", account.access_token);
				token.accessToken = account.access_token
				token.userID = user.id;
			}

			return token
		},

		async session({ session, token }) {
			session.accessToken = token.accessToken as string;
			session.userID = token.userID;
			return session
		}
	},
	secret: process.env.NEXTAUTH_SECRET
}

import { getServerSession } from "next-auth";
import { NextResponse } from "next/server";
import { authOptions } from "@/app/api/auth/authOptions";

export async function DELETE(req: Request) {
	const session = await getServerSession(authOptions);
	const token = session?.accessToken;

	if (!token) {
		return NextResponse.json({ error: "Missing access token" }, { status: 401 });
	}

	let body;
	try {
		body = await req.json();
	} catch (e) {
		return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
	}

	const { repo_url, commit_sha } = body;

	if (!repo_url) {
		return NextResponse.json({ error: "Missing repo_url" }, { status: 400 });
	}

	try {
		console.log("Deleting cache for", repo_url, commit_sha || "(all)");
		const response = await fetch(`${process.env.SD_API_BASE_URL}/cache`, {
			method: "DELETE",
			headers: {
				"Content-Type": "application/json",
				"Authorization": `Bearer ${process.env.SD_API_BEARER_TOKEN}`,
			},
			body: JSON.stringify({ repo_url, commit_sha })
		});

		if (!response.ok) {
			const errText = await response.text();
			console.error(`Cache deletion failed: ${response.status} ${errText}`);
			throw new Error(`Cache deletion failed: ${response.status} ${errText}`);
		}

		const result = await response.json();
		return NextResponse.json(result);
	} catch (err: any) {
		console.error("Cache deletion proxy error:", err);
		return NextResponse.json(
			{ error: "Cache deletion request failed", details: err?.message || "Unknown error" },
			{ status: 502 }
		);
	}
}

/**
 * POST /api/deployment-preview-screenshot
 * 
 * Generates a screenshot of a deployed application on-demand.
 * Called from the frontend when user clicks "New Preview" button.
 */

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/app/api/auth/authOptions";
import { dbHelper } from "@/db-helper";
import { captureDeploymentScreenshotAndUpload } from "@/lib/deploymentScreenshot";
import { getDeploymentDisplayUrl } from "@/lib/utils";

export const dynamic = "force-dynamic";
export const runtime = "nodejs";

interface RequestBody {
	repoName: string;
	serviceName: string;
	force?: boolean;
}

export async function POST(request: NextRequest) {
	const start = Date.now();
	try {
		const session = await getServerSession(authOptions);
		const userID = (session as { userID?: string })?.userID;
		if (!userID) {
			return NextResponse.json(
				{ error: "Unauthorized" },
				{ status: 401 }
			);
		}

		const body: RequestBody = await request.json();
		const { repoName, serviceName, force = false } = body;

		if (!repoName || !serviceName) {
			return NextResponse.json(
				{ error: "Missing repoName or serviceName" },
				{ status: 400 }
			);
		}

		// Fetch the deployment from database
		const { deployments, error: fetchError } = await dbHelper.getDeploymentsByRepo(userID, repoName);
		if (fetchError || !deployments) {
			return NextResponse.json(
				{ error: fetchError || "Failed to fetch deployment" },
				{ status: 500 }
			);
		}

		// Find the specific service deployment
		const deployment = deployments.find((d: any) => d.serviceName === serviceName);
		if (!deployment) {
			return NextResponse.json(
				{ error: "Deployment not found" },
				{ status: 404 }
			);
		}

		// Determine the URL to screenshot
		const displayUrl = getDeploymentDisplayUrl(deployment);
		if (!displayUrl) {
			return NextResponse.json(
				{
					status: "skipped",
					error: "No live URL available for this deployment",
				}
			);
		}

		// Capture and upload screenshot
		console.debug(
			`[Screenshot] Starting capture for ${repoName}/${serviceName} at ${displayUrl}`
		);

		const screenshotUrl = await captureDeploymentScreenshotAndUpload({
			url: displayUrl,
			ownerID: userID,
			repoName: repoName,
			serviceName: serviceName,
		});

		// Update deployment with new screenshot URL
		const { error: updateError } = await dbHelper.updateDeployments(
			{
				...deployment,
				screenshotUrl: screenshotUrl,
			},
			userID
		);

		if (updateError) {
			console.error("Failed to update deployment with screenshot URL:", updateError);
			// Still return success since screenshot was captured, just couldn't save it
			// The frontend will refresh deployments anyway
		}

		console.debug(
			`[Screenshot] Completed for ${repoName}/${serviceName} in ${Date.now() - start}ms`
		);

		return NextResponse.json({
			status: "success",
			screenshotUrl: screenshotUrl,
		});
	} catch (err) {
		console.error("[Screenshot] Error:", err);
		const errorMessage = err instanceof Error ? err.message : "Unknown error";

		// Check if it's a gateway timeout or similar error (501, 502, 503, 504)
		if (
			errorMessage.includes("502") ||
			errorMessage.includes("503") ||
			errorMessage.includes("504") ||
			errorMessage.includes("gateway") ||
			errorMessage.includes("timeout")
		) {
			return NextResponse.json(
				{
					status: "skipped",
					error: "Gateway error - screenshot service temporarily unavailable",
				}
			);
		}

		return NextResponse.json(
			{ error: errorMessage || "Failed to generate screenshot" },
			{ status: 500 }
		);
	}
}

import { getServerSession } from "next-auth";
import { NextResponse } from "next/server";
import { authOptions } from "@/app/api/auth/authOptions";

export async function POST(req: Request) {
	const session = await getServerSession(authOptions);
	const token = session?.accessToken;

	if (!token) {
		return NextResponse.json({ error: "Missing access token" }, { status: 401 });
	}

	let body: { repo_url?: string; commit_sha?: string; feedback?: string };
	try {
		body = await req.json();
	} catch (e) {
		return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
	}

	const { repo_url, commit_sha, feedback } = body;

	if (!repo_url) {
		return NextResponse.json({ error: "Missing repo_url" }, { status: 400 });
	}
	if (!feedback) {
		return NextResponse.json({ error: "Missing feedback" }, { status: 400 });
	}

	try {
		const response = await fetch(`${process.env.SD_API_BASE_URL}/feedback`, {
			method: "POST",
			headers: {
				"Content-Type": "application/json",
				"Authorization": `Bearer ${process.env.SD_API_BEARER_TOKEN}`,
			},
			body: JSON.stringify({
				repo_url,
				...(commit_sha && { commit_sha }),
				feedback,
			}),
		});

		if (!response.ok) {
			const errText = await response.text();
			console.error(`Feedback request failed: ${response.status} ${errText}`);
			throw new Error(`Feedback request failed: ${response.status} ${errText}`);
		}

		const result = await response.json();
		return NextResponse.json(result);
	} catch (err: unknown) {
		console.error("Feedback proxy error:", err);
		return NextResponse.json(
			{
				error: "Feedback request failed",
				details: err instanceof Error ? err.message : "Unknown error",
			},
			{ status: 502 }
		);
	}
}

