import { NextRequest, NextResponse } from "next/server";
import { getSupabaseServer } from "@/lib/supabaseServer";

// Force dynamic rendering - prevents Next.js from analyzing this route during build
export const dynamic = 'force-dynamic';
export const runtime = 'nodejs';

export async function GET(req: NextRequest) {
	try {
		const timestamp = new Date().toISOString();

		let dbStatus = 'unknown';
		try {
			const supabase = getSupabaseServer();
			await supabase.from("_health").select("id").limit(1).maybeSingle();
			dbStatus = 'connected';
		} catch {
			dbStatus = 'disconnected';
		}

		return NextResponse.json({
			status: 'healthy',
			timestamp,
			service: 'smart-deploy',
			database: dbStatus,
		}, { status: 200 });

	} catch (error) {
		console.error("Health check error:", error);
		return NextResponse.json({
			status: 'unhealthy',
			timestamp: new Date().toISOString(),
			error: error instanceof Error ? error.message : 'Unknown error'
		}, { status: 503 });
	}
}

import { getServerSession } from "next-auth";
import { NextResponse } from "next/server";
import { authOptions } from "../auth/authOptions";
import { getRepoFilePaths } from "@/github-helper";
import { BedrockRuntimeClient, InvokeModelCommand } from "@aws-sdk/client-bedrock-runtime";
import { GoogleGenerativeAI } from "@google/generative-ai";

export async function POST(req: Request) {
	const session = await getServerSession(authOptions);

	const token = session?.accessToken;

	if (!token) {
		return NextResponse.json({ error: "Missing access token" }, { status: 401 });
	}

	const body = await req.json();
	const { full_name, branch, target_workdir } = body;
	let { include_extra_info } = body;

	if (include_extra_info === undefined) include_extra_info = false;

	const { filePaths, fileContents } = await getRepoFilePaths(full_name, branch, token);
	const prompt = createPrompt(filePaths, fileContents, include_extra_info, target_workdir);

	try {
		const text = await callLLMWithFallback(prompt);
		return NextResponse.json({ response: text, filePaths, fileContents });
	} catch (error: unknown) {
		console.error("LLM error (Gemini and local fallback failed):", error);
		return NextResponse.json(
			{
				error: "LLM request failed",
				details: error instanceof Error ? error.message : "Unknown error",
			},
			{ status: 502 }
		);
	}
}

/** Try Gemini first; if it fails, run the same prompt on the local LLM. */
async function callLLMWithFallback(prompt: string): Promise<string> {
	const hasGemini = !!process.env.GEMINI_API_KEY?.trim();
	const hasLocal = !!process.env.LOCAL_LLM_BASE_URL?.trim();

	if (hasGemini) {
		try {
			return await callGemini(prompt);
		} catch (geminiError) {
			console.warn("Gemini failed, falling back to local LLM:", geminiError);
			if (hasLocal) {
				return await callLocalLLM(prompt);
			}
			throw geminiError;
		}
	}
	if (hasLocal) {
		return await callLocalLLM(prompt);
	}
	throw new Error("No LLM configured. Set GEMINI_API_KEY and/or LOCAL_LLM_BASE_URL.");
}

async function callBedrock(prompt: string): Promise<string> {
	console.log("Calling Bedrock API");
	const region = process.env.AWS_REGION || "us-west-2";
	const accessKeyId = process.env.AWS_BEDROCK_ACCESS_KEY_ID;
	const secretAccessKey = process.env.AWS_BEDROCK_SECRET_ACCESS_KEY;

	if (!accessKeyId || !secretAccessKey) {
		throw new Error("Missing AWS credentials (AWS_BEDROCK_ACCESS_KEY_ID and AWS_BEDROCK_SECRET_ACCESS_KEY required when NODE_ENV=prod)");
	}

	const client = new BedrockRuntimeClient({
		region,
		credentials: {
			accessKeyId,
			secretAccessKey,
		},
	});

	// Claude Opus 4.5 model ID on Bedrock
	// Default model ID - can be overridden via BEDROCK_MODEL_ID env var
	// Common formats: "anthropic.claude-opus-4-5-v1:0" or check AWS Bedrock console for exact ID
	const modelId = process.env.BEDROCK_MODEL_ID || "anthropic.claude-opus-4-5-v1:0";

	const command = new InvokeModelCommand({
		modelId,
		contentType: "application/json",
		accept: "application/json",
		body: JSON.stringify({
			anthropic_version: "bedrock-2023-05-31",
			max_tokens: 8192,
			temperature: 0.2,
			messages: [
				{
					role: "user",
					content: [
						{
							type: "text",
							text: prompt,
						},
					],
				},
			],
		}),
	});

	const response = await client.send(command);
	const responseBody = JSON.parse(new TextDecoder().decode(response.body));

	if (!responseBody.content || !responseBody.content[0]?.text) {
		throw new Error("Invalid response from Bedrock API");
	}

	console.log("Bedrock response:", responseBody.content[0].text);

	return responseBody.content[0].text;
}

async function callGemini(prompt: string): Promise<string> {
	const geminiApiKey = process.env.GEMINI_API_KEY;
	if (!geminiApiKey?.trim()) {
		throw new Error("Missing GEMINI_API_KEY env var");
	}
	const genAI = new GoogleGenerativeAI(geminiApiKey);
	const model = genAI.getGenerativeModel({
		model: "gemini-2.5-flash",
		generationConfig: {
			temperature: 0.2,
			maxOutputTokens: 8192,
		},
	});
	const result = await model.generateContent(prompt);
	const response = await result.response;
	return response.text();
}

async function callLocalLLM(prompt: string): Promise<string> {
	const baseUrl = process.env.LOCAL_LLM_BASE_URL || "";
	if (!baseUrl?.trim()) {
		throw new Error("Missing LOCAL_LLM_BASE_URL env var");
	}
	const model = process.env.LOCAL_LLM_MODEL || "mistral";
	let res: Response;
	try {
		res = await fetch(baseUrl, {
			method: "POST",
			headers: { "Content-Type": "application/json" },
			body: JSON.stringify({
				model,
				prompt: prompt,
				stream: false,
				temperature: 0.2,
				max_tokens: 8192,
			}),
		});
	} catch (err: unknown) {
		const cause = err instanceof Error && "cause" in err ? (err.cause as NodeJS.ErrnoException) : null;
		if (cause?.code === "ECONNREFUSED") {
			throw new Error(
				`Local LLM server unreachable at ${baseUrl}. Is Ollama or your LLM server running? (ECONNREFUSED)`
			);
		}
		throw err;
	}
	if (!res.ok) {
		const errText = await res.text();
		throw new Error(`Local LLM returned ${res.status}: ${errText.slice(0, 200)}`);
	}
	const data = await res.json();
	const text = data.response as string;
	console.log("Local LLM response:", text);

	if (text == null) {
		throw new Error("Local LLM response missing text");
	}
	return text;
}


function createPrompt(filePaths: string[], fileContents: Record<string, string>, include_extra_info: boolean, target_workdir?: string) {
	const targetDirInstruction = target_workdir ?
		`\n\nCRITICAL CONTEXT FOR SINGLE SERVICE DIRECTORY:\nThe user is deploying a specific service located at "${target_workdir}". You MUST analyze ONLY the code and configuration within this directory, ignoring the rest of the monorepo root (unless standard workspace files like package.json or lockfiles are needed for global context of how it runs). DO NOT return deployment data for the monorepo root; you MUST output the framework, language, and run commands relating SPECIFICALLY to the service at "${target_workdir}". `
		: "";

	const prompt = `Analyze this repo for deployment.${targetDirInstruction}

Output rules: Return ONLY a single JSON object. No text, explanation, or markdown before or after. No code fences (\`\`\`). No comments inside the JSON (no // or /* */). No trailing commas. The response must be parseable by JSON.parse().

Repository file list:
${filePaths.join("\n")}

File contents:
${Object.entries(fileContents)
			.map(([file, content]) => `\n--- ${file} ---\n${content}`)
			.join("\n")}

Required JSON keys:
  IMPORTANT: If the repo has NO deployable code (empty, only docs/README, only config files, only mobile code with no backend), set language to null or empty string, and run_cmd to null.
${target_workdir ?
			`  IMPORTANT FOR THIS SERVICE: Even though this is a monorepo, analyze strictly the service at "${target_workdir}".`
			:
			`  IMPORTANT FOR MONOREPOS: If the repo is a monorepo (has pnpm-workspace.yaml, workspaces in package.json, turbo.json, nx.json, or lerna.json), individual service details should go in monorepo_services.`}
${include_extra_info ? `
- features_infrastructure: { uses_websockets, uses_cron, uses_mobile, uses_server, is_library, cloud_run_compatible, requires_build_but_missing_cmd } (all boolean; cloud_run_compatible = true only if stateless HTTP, no long-lived WebSockets, no mobile/lib)
  IMPORTANT: 
  - Set uses_mobile=true ONLY if the repo contains mobile code (React Native, Flutter, iOS, Android). 
  - Set uses_server=true ONLY if there's actual server/backend code that runs on a server (Express, FastAPI, Django, Flask, NestJS, etc.). Next.js with server-side rendering is a server-based framework, so uses_server=true for full Next.js apps.
  - Static SPAs (Create React App, Vite, Angular, Vue CLI, Svelte) have uses_server=false because they are client-side only and don't need a server runtime.
  - Firebase, Supabase client SDKs, and other BaaS (Backend-as-a-Service) clients are NOT server code - they run in the browser. Static SPAs using Firebase/Supabase should have uses_server=false.
  - If mobile-only with no server code, set uses_mobile=true and uses_server=false.
  - If mobile-only with no server code, set uses_mobile=true and uses_server=false.
- deployment_hints: { has_dockerfile (boolean), is_multi_service (boolean), is_monorepo (boolean), has_database (boolean), nextjs_static_export (boolean; true only if Next.js and next.config has output: "export") }
  IMPORTANT: is_monorepo = true if the repo uses workspace tooling (pnpm-workspace.yaml, npm/yarn workspaces in package.json, turbo.json, nx.json, or lerna.json) with multiple apps/services in subdirectories (apps/, packages/, services/). A monorepo is automatically is_multi_service=true if it has 2+ deployable services. Mobile-only packages (React Native, Expo, Flutter) should NOT count as deployable services.
- monorepo_services: (array, only if is_monorepo=true, otherwise omit or set to []) Each entry: { name (string), path (relative path e.g. "apps/web"), language (e.g. "TypeScript"), framework (e.g. "Next.js", "Express"), port (number or null), is_deployable (boolean - false for mobile-only, shared libs, config packages) }
  For each workspace package/app, identify if it's a deployable server-side service. Skip shared library packages (e.g. packages/config, packages/eslint-config) and mobile-only packages.
  - ec2: true for complex apps requiring full OS-level control, custom infrastructure, or when other platforms don't fit (NOT a fallback for mobile-only or empty repos)
  - cloud_run: true only if stateless HTTP service, no long-lived WebSockets, not mobile/lib; same as cloud_run_compatible
  IMPORTANT: If the repo contains ONLY mobile code (React Native, Flutter, iOS, Android) with no server/backend, set ALL platforms to false. If the repo has no deployable code (empty, docs-only, etc.), set ALL platforms to false.
  Prefer the simplest compatible platform.
- final_notes: { comment (1–2 sentences on structure and deploy readiness) }` : ""}
`;
	return prompt;
}

import { getServerSession } from "next-auth";
import { NextResponse } from "next/server";
import { authOptions } from "@/app/api/auth/authOptions";

export const dynamic = "force-dynamic";

export async function POST(req: Request) {
	const session = await getServerSession(authOptions);
	const token = session?.accessToken;

	if (!token) {
		return NextResponse.json({ error: "Missing access token" }, { status: 401 });
	}

	let body;
	try {
		body = await req.json();
	} catch (e) {
		return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
	}

	const { full_name, package_path } = body;

	if (!full_name) {
		return NextResponse.json({ error: "Missing full_name" }, { status: 400 });
	}

	const payload = {
		repo_url: `https://github.com/${full_name}`,
		github_token: token,
		...(package_path && { package_path }),
	};

	try {
		console.log("Starting analyze stream for", payload.repo_url);
		const response = await fetch(`${process.env.SD_API_BASE_URL}/analyze/stream`, {
			method: "POST",
			headers: {
				"Content-Type": "application/json",
				"Authorization": `Bearer ${process.env.SD_API_BEARER_TOKEN}`,
			},
			body: JSON.stringify(payload)
		});

		if (!response.ok) {
			const errText = await response.text();
			console.error(`Analyze stream failed: ${response.status} ${errText}`);
			throw new Error(`Analyze stream failed: ${response.status} ${errText}`);
		}

		// Stream directly to the client
		return new Response(response.body, {
			headers: {
				"Content-Type": "text/event-stream",
				"Cache-Control": "no-cache",
				"Connection": "keep-alive"
			}
		});
	} catch (err: any) {
		console.error("Stream proxy error:", err);
		return NextResponse.json(
			{ error: "Stream API request failed", details: err?.message || "Unknown error" },
			{ status: 502 }
		);
	}
}

"use client";

import { DeployConfig, repoType } from "@/app/types";
import { EllipsisVertical, ExternalLink, GitBranch } from "lucide-react";
import {
	DropdownMenu,
	DropdownMenuContent,
	DropdownMenuItem,
	DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { formatTimestamp, getDeploymentDisplayUrl } from "@/lib/utils";
import Link from "next/link";
import { useAppData } from "@/store/useAppData";
import { useState } from "react";
import { toast } from "sonner";
import { controlDeployment, deleteDeployment } from "@/lib/graphqlClient";

const statusStyles: Record<string, string> = {
	running: "bg-primary/20 text-primary border-primary/40",
	paused: "bg-amber-400/20 text-amber-400 border-amber-400/40",
	stopped: "bg-muted/40 text-muted-foreground border-muted-foreground/30",
};

export default function DashboardDeploymentItem({
	deployConfig,
	repo,
}: {
	deployConfig: DeployConfig;
	repo: repoType | undefined;
}) {
	const { removeDeployment, updateDeploymentById } = useAppData();
	const [isDeleting, setIsDeleting] = useState(false);

	async function changeStatus(action: string) {
		// Delete = full remove: Cloud Run + DB, no traces left
		if (action === "stop") {
			setIsDeleting(true);
			const loadingId = toast.loading("Deleting deployment…");
			try {
			await deleteDeployment(deployConfig.repoName, deployConfig.serviceName);
			removeDeployment(deployConfig.repoName, deployConfig.serviceName);
				toast.dismiss(loadingId);
				toast.success("Deployment deleted.");
			} catch (err: any) {
				toast.dismiss(loadingId);
				toast.error(err?.message || "Failed to delete deployment.");
			} finally {
				setIsDeleting(false);
			}
			return;
		}

		try {
			const actionKey = action === "pause" ? "pause" : "resume";
			await controlDeployment(actionKey as "pause" | "resume" | "stop", deployConfig.repoName, deployConfig.serviceName);
			const nextStatus = action === "pause" ? "paused" : "running";
			void updateDeploymentById({ ...deployConfig, status: nextStatus });
			toast.success(
				nextStatus === "paused" ? "Deployment paused (instance stopping)." : "Deployment resumed (instance starting)."
			);
		} catch (err: any) {
			toast.error(err?.message || "Failed to update deployment.");
		}
	}

	const statusStyle = statusStyles[deployConfig.status ?? "stopped"] ?? statusStyles.stopped;

	return (
		<div className="rounded-xl border border-border bg-card flex flex-col p-4 hover:border-border transition-colors">
			<div className="flex items-start justify-between gap-2">
				<div className="min-w-0 flex-1">
					<Link
						href={`/services/${deployConfig.serviceName}?repoName=${encodeURIComponent(deployConfig.repoName)}`}
						className="font-semibold text-foreground hover:text-primary transition-colors truncate block"
					>
						{deployConfig.serviceName}
					</Link>
					<span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium border mt-2 ${statusStyle}`}>
						{deployConfig.status ?? "stopped"}
					</span>
				</div>
				<DropdownMenu>
					<DropdownMenuTrigger className="p-1.5 rounded-lg border border-transparent hover:bg-secondary hover:border-border text-muted-foreground hover:text-foreground transition-colors">
						<EllipsisVertical className="size-4" />
					</DropdownMenuTrigger>
					<DropdownMenuContent align="end" className="border-border bg-card">
						<DropdownMenuItem
							onClick={() => changeStatus(deployConfig.status === "running" ? "pause" : "resume")}
							className="text-foreground focus:bg-secondary focus:text-foreground"
						>
							{deployConfig.status === "running" ? "Pause" : "Resume"}
						</DropdownMenuItem>
						<DropdownMenuItem
							onClick={() => changeStatus("stop")}
							disabled={isDeleting}
							className="text-foreground focus:bg-destructive/20 focus:text-destructive/80"
						>
							{isDeleting ? "Deleting…" : "Delete"}
						</DropdownMenuItem>
					</DropdownMenuContent>
				</DropdownMenu>
			</div>
			{(() => {
				const displayUrl = getDeploymentDisplayUrl(deployConfig);
				return displayUrl ? (
					<a
						href={displayUrl}
						target="_blank"
						rel="noopener noreferrer"
						className="flex items-center gap-1.5 text-xs text-primary hover:underline mt-2 truncate"
					>
						<ExternalLink className="size-3.5 shrink-0" />
						<span className="truncate">{displayUrl}</span>
					</a>
				) : null;
			})()}
			{repo && (
				<div className="mt-4 pt-4 border-t border-border">
					<a
						href={repo.html_url}
						target="_blank"
						rel="noopener noreferrer"
						className="inline-flex truncate items-center gap-1.5 text-sm text-muted-foreground hover:text-primary transition-colors"
					>
						<GitBranch className="size-4 shrink-0" />
						<span className="truncate">{repo.full_name}</span>
					</a>
					{deployConfig.commitSha ? (
						<>
							<div className="flex items-center gap-2 mt-2">
								<span className="text-xs text-muted-foreground/70">Deployed commit:</span>
								<code className="text-xs bg-muted/50 px-2 py-0.5 rounded border border-border/50 font-mono text-foreground">
									{deployConfig.commitSha.substring(0, 7)}
								</code>
							</div>
							<p className="text-xs text-muted-foreground/70 mt-1">
								on <strong className="text-muted-foreground">{deployConfig.branch}</strong>
							</p>
						</>
					) : repo.latest_commit ? (
						<>
							<p className="text-xs text-muted-foreground/70 mt-2 line-clamp-2" title={repo.latest_commit.message}>
								{repo.latest_commit.message}
							</p>
							<p className="text-xs text-muted-foreground/70 mt-1">
								{formatTimestamp(repo.latest_commit.date)} on <strong className="text-muted-foreground">{repo.default_branch}</strong>
							</p>
						</>
					) : null}
				</div>
			)}
		</div>
	);
}

"use client";

import * as React from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table";
import { Download, Loader2, Search } from "lucide-react";
import { useActiveDeployment } from "@/components/ActiveDeploymentProvider";
import type { DeployStep } from "@/app/types";
import { fetchDeploymentHistoryAllPage } from "@/lib/graphqlClient";
import { useQuery } from "@tanstack/react-query";

const statusOptions = ["all", "success", "failed"] as const;
const envOptions = ["all", "production", "staging", "development"] as const;

type DeploymentHistoryRow = {
	id: string;
	repo_name: string;
	service_name: string;
	timestamp: string;
	success: boolean;
	commitSha?: string;
	commitMessage?: string;
	branch?: string;
	durationMs?: number;
	steps: DeployStep[];
	configSnapshot: Record<string, unknown>;
};

function toRelativeTime(timestamp: string): string {
	const now = Date.now();
	const then = new Date(timestamp).getTime();
	if (Number.isNaN(then)) return "--";
	const diff = Math.max(0, now - then);
	const minute = 60 * 1000;
	const hour = 60 * minute;
	const day = 24 * hour;

	if (diff < minute) return "just now";
	if (diff < hour) return `${Math.floor(diff / minute)}m ago`;
	if (diff < day) return `${Math.floor(diff / hour)}h ago`;
	return `${Math.floor(diff / day)}d ago`;
}

function deriveEnvironment(branch?: string): string {
	const value = (branch || "").toLowerCase();
	if (value.includes("stag")) return "Staging";
	if (value.includes("dev") || value.includes("test")) return "Development";
	return "Production";
}

function downloadCsv(rows: DeploymentHistoryRow[]) {
	const headers = ["Status", "Service", "Environment", "Commit", "Message", "Branch", "Age", "Timestamp"];
	const lines = rows.map((row) => {
		const status = row.success ? "SUCCESS" : "FAILED";
		const env = deriveEnvironment(row.branch);
		const commit = row.commitSha ? row.commitSha.substring(0, 7) : "";
		const age = toRelativeTime(row.timestamp);
		return [status, row.service_name, env, commit, row.commitMessage ?? "", row.branch ?? "", age, row.timestamp]
			.map((cell) => `"${String(cell).replace(/"/g, '""')}"`)
			.join(",");
	});
	const csv = [headers.join(","), ...lines].join("\n");
	const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
	const url = URL.createObjectURL(blob);
	const link = document.createElement("a");
	link.href = url;
	link.download = "deployment-history.csv";
	link.click();
	URL.revokeObjectURL(url);
}

export default function DeploymentHistoryTable() {
	const { openLogsModal } = useActiveDeployment();
	const [query, setQuery] = React.useState("");
	const [statusFilter, setStatusFilter] = React.useState<(typeof statusOptions)[number]>("all");
	const [envFilter, setEnvFilter] = React.useState<(typeof envOptions)[number]>("all");
	const [page, setPage] = React.useState(1);
	const limit = 10;

	const historyQuery = useQuery({
		queryKey: ["deployment-history-table", page, limit],
		queryFn: async () => fetchDeploymentHistoryAllPage(page, limit),
	});

	const history = (historyQuery.data?.history ?? []) as DeploymentHistoryRow[];
	const total = historyQuery.data?.total ?? 0;
	const loading = historyQuery.isLoading;

	const filtered = React.useMemo(() => {
		return history.filter((row) => {
			const matchQuery = query
				? `${row.service_name} ${row.repo_name ?? ""} ${row.branch ?? ""} ${row.commitSha ?? ""} ${row.commitMessage ?? ""}`
					.toLowerCase()
					.includes(query.toLowerCase())
				: true;
			const matchStatus =
				statusFilter === "all" ||
				(statusFilter === "success" && row.success) ||
				(statusFilter === "failed" && !row.success);
			const env = deriveEnvironment(row.branch).toLowerCase();
			const matchEnv = envFilter === "all" || env === envFilter;
			return matchQuery && matchStatus && matchEnv;
		});
	}, [history, query, statusFilter, envFilter]);

	return (
		<div className="rounded-xl border border-border bg-card/60 p-4">
			<div className="flex flex-wrap items-center gap-3">
				<div className="relative flex-1 min-w-56">
					<Search className="size-4 text-muted-foreground absolute left-3 top-1/2 -translate-y-1/2" />
					<Input
						placeholder="Filter deployments..."
						value={query}
						onChange={(e) => setQuery(e.target.value)}
						className="pl-9 border-border bg-background/60"
					/>
				</div>
				<Select value={statusFilter} onValueChange={(value) => setStatusFilter(value as typeof statusOptions[number])}>
					<SelectTrigger className="w-40 border-border bg-background/60">
						<SelectValue placeholder="All Statuses" />
					</SelectTrigger>
					<SelectContent>
						{statusOptions.map((option) => (
							<SelectItem key={option} value={option}>
								{option === "all" ? "All Statuses" : option}
							</SelectItem>
						))}
					</SelectContent>
				</Select>
				<Select value={envFilter} onValueChange={(value) => setEnvFilter(value as typeof envOptions[number])}>
					<SelectTrigger className="w-44 border-border bg-background/60">
						<SelectValue placeholder="All Environments" />
					</SelectTrigger>
					<SelectContent>
						{envOptions.map((option) => (
							<SelectItem key={option} value={option}>
								{option === "all" ? "All Environments" : option}
							</SelectItem>
						))}
					</SelectContent>
				</Select>
				<Button
					variant="outline"
					className="border-border bg-background/60"
					onClick={() => downloadCsv(filtered)}
					disabled={filtered.length === 0}
				>
					<Download className="size-4 mr-2" />
					Export CSV
				</Button>
			</div>

			<div className="mt-4">
				{loading ? (
					<div className="flex items-center gap-2 text-muted-foreground py-6">
						<Loader2 className="size-4 animate-spin" />
						Loading deployment history...
					</div>
				) : filtered.length === 0 ? (
					<div className="text-sm text-muted-foreground py-6">No deployments match your filters.</div>
				) : (
					<Table>
						<TableHeader>
							<TableRow>
								<TableHead>Status</TableHead>
								<TableHead>Service</TableHead>
								<TableHead>Environment</TableHead>
								<TableHead>Commit</TableHead>
								<TableHead>Age</TableHead>
							</TableRow>
						</TableHeader>
						<TableBody>
							{filtered.map((row) => (
								<TableRow
									key={row.id}
									onClick={() =>
										openLogsModal(row.repo_name, row.service_name, undefined, {
											steps: row.steps,
											status: row.success ? "success" : "error",
											error: row.success ? null : "Deployment failed",
										})
									}
									className="cursor-pointer"
								>
									<TableCell>
										<Badge
											variant="outline"
											className={
												row.success
													? "border-emerald-500/60 text-emerald-400 bg-emerald-500/10"
													: "border-rose-500/60 text-rose-400 bg-rose-500/10"
											}
										>
											{row.success ? "SUCCESS" : "FAILED"}
										</Badge>
									</TableCell>
									<TableCell>
										<div className="text-foreground font-medium">{row.service_name}</div>
										{row.repo_name && (
											<div className="text-xs text-muted-foreground truncate max-w-60">{row.repo_name}</div>
										)}
									</TableCell>
									<TableCell>
										<span className="text-sm text-muted-foreground">
											{deriveEnvironment(row.branch)}
										</span>
									</TableCell>
									<TableCell>
										<div className="text-sm text-foreground">
											{row.commitSha ? row.commitSha.substring(0, 7) : "--"}
										</div>
										{row.commitMessage && (
											<div className="text-xs text-muted-foreground truncate max-w-48" title={row.commitMessage}>
												{row.commitMessage}
											</div>
										)}
										{row.branch && (
											<div className="text-xs text-muted-foreground">{row.branch}</div>
										)}
									</TableCell>
									<TableCell>
										<span className="text-sm text-muted-foreground">
											{toRelativeTime(row.timestamp)}
										</span>
									</TableCell>
								</TableRow>
							))}
						</TableBody>
					</Table>
				)}
			</div>
			<div className="mt-4 flex items-center justify-between">
				<p className="text-xs text-muted-foreground">
					Page {page} of {Math.max(1, Math.ceil(total / limit))}
				</p>
				<div className="flex items-center gap-2">
					<Button
						variant="outline"
						className="border-border bg-background/60"
						disabled={page === 1 || loading}
						onClick={() => setPage((current) => Math.max(1, current - 1))}
					>
						Previous
					</Button>
					<Button
						variant="outline"
						className="border-border bg-background/60"
						disabled={page >= Math.ceil(total / limit) || loading}
						onClick={() => setPage((current) => current + 1)}
					>
						Next
					</Button>
				</div>
			</div>
		</div>
	);
}

"use client";

import * as React from "react";
import {
	Sheet,
	SheetContent,
	SheetDescription,
	SheetHeader,
	SheetTitle,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Plus, Trash2, Upload, FileText, X } from "lucide-react";
import { parseEnvLinesToEntries } from "@/lib/utils";
import { toast } from "sonner";

type EnvVarEntry = {
	name: string;
	value: string;
}

type EnvVarSheetProps = {
	open: boolean;
	onOpenChange: (open: boolean) => void;
	entries: EnvVarEntry[];
	onEntriesChange: (entries: EnvVarEntry[]) => void;
}

export default function EnvVarSheet({
	open,
	onOpenChange,
	entries,
	onEntriesChange,
}: EnvVarSheetProps) {
	const fileInputRef = React.useRef<HTMLInputElement>(null);
	const [focusedIndex, setFocusedIndex] = React.useState<number | null>(null);


	const handleAddVariable = () => {
		onEntriesChange([...entries, { name: "", value: "" }]);
	};

	const handleRemoveVariable = (index: number) => {
		const newEntries = entries.filter((_, i) => i !== index);
		onEntriesChange(newEntries);
	};

	const handleUpdateVariable = (
		index: number,
		field: keyof EnvVarEntry,
		value: string
	) => {
		const newEntries = [...entries];
		if (field === "name") {
			newEntries[index].name = value.toUpperCase().replace(/[^A-Z0-9_]/g, "");
		} else {
			newEntries[index].value = value;
		}
		onEntriesChange(newEntries);
	};

	const handlePaste = (index: number, e: React.ClipboardEvent<HTMLInputElement>) => {
		// Only autofill if pasting into the first empty key or if it looks like a multi-line .env content
		const pastedText = e.clipboardData.getData("text");
		if (pastedText.includes("=") || pastedText.includes("\n")) {
			e.preventDefault();
			const parsed = parseEnvLinesToEntries(pastedText);
			if (parsed.length > 0) {
				// If we are at index and it's the only one or we want to append/replace
				// For simplicity, let's replace empty entries or append
				const baseEntries = entries.filter(e => e.name || e.value);
				// If the current entry being pasted into is empty, we can replace it
				const currentEntry = entries[index];
				let newEntries: EnvVarEntry[] = [];

				if (!currentEntry.name && !currentEntry.value) {
					// Replace the empty one at index
					const before = entries.slice(0, index);
					const after = entries.slice(index + 1);
					newEntries = [...before, ...parsed, ...after];
				} else {
					// Append
					newEntries = [...entries, ...parsed];
				}

				// Remove duplicates (keep last)
				const uniqueEntriesMap = new Map<string, string>();
				newEntries.forEach(e => {
					if (e.name) uniqueEntriesMap.set(e.name, e.value);
				});

				const finalEntries = Array.from(uniqueEntriesMap.entries()).map(([name, value]) => ({ name, value }));
				onEntriesChange(finalEntries.length > 0 ? finalEntries : [{ name: "", value: "" }]);
				toast.success(`Imported ${parsed.length} environment variables`);
			}
		}
	};

	const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
		const file = e.target.files?.[0];
		if (!file) return;

		const reader = new FileReader();
		reader.onload = (event) => {
			const content = event.target?.result as string;
			const parsed = parseEnvLinesToEntries(content);
			if (parsed.length > 0) {
				// Merge with existing, priority to new
				const entryMap = new Map<string, string>();
				entries.forEach(e => { if (e.name) entryMap.set(e.name, e.value) });
				parsed.forEach(e => { if (e.name) entryMap.set(e.name, e.value) });

				const merged = Array.from(entryMap.entries()).map(([name, value]) => ({ name, value }));
				onEntriesChange(merged);
				toast.success(`Imported ${parsed.length} variables from ${file.name}`);
			} else {
				toast.error("No valid environment variables found in file");
			}
		};
		reader.readAsText(file);
		// Reset input
		if (fileInputRef.current) fileInputRef.current.value = "";
	};

	return (
		<Sheet open={open} onOpenChange={onOpenChange}>
			<SheetContent side="right" className="w-full sm:max-w-xl bg-[#0a0a0f] border-white/5 p-0 flex flex-col">
				<div className="p-6 border-b border-white/5">
					<SheetHeader>
						<SheetTitle className="text-xl font-bold bg-gradient-to-r from-white to-white/60 bg-clip-text text-transparent">
							Environment Variables
						</SheetTitle>
						<SheetDescription className="text-muted-foreground/60">
							Manage your application&apos;s environment variables. You can add them manually, upload a .env file, or paste content into the key field.
						</SheetDescription>
					</SheetHeader>

					<div className="flex items-center gap-3 mt-6">
						<Button
							onClick={() => fileInputRef.current?.click()}
							variant="outline"
							size="sm"
							className="bg-white/5 border-white/10 hover:bg-white/10 text-xs h-9"
						>
							<Upload className="size-3.5 mr-2" />
							Upload .env
						</Button>
						<input
							type="file"
							ref={fileInputRef}
							onChange={handleFileUpload}
							className="hidden"
							accept=".env,text/plain"
						/>
						<div className="h-4 w-px bg-white/10 mx-1" />
						<Button
							onClick={handleAddVariable}
							variant="default"
							size="sm"
							className="bg-primary hover:bg-primary/90 text-xs h-9"
						>
							<Plus className="size-3.5 mr-2" />
							Add Variable
						</Button>
					</div>
				</div>

				<div className="flex-1 overflow-hidden">
					<ScrollArea className="h-full">
						<div className="px-6 py-4 space-y-4">
							{entries.length === 0 ? (
								<div className="flex flex-col items-center justify-center py-12 px-4 border border-dashed border-white/10 rounded-xl bg-white/[0.02]">
									<FileText className="size-10 text-muted-foreground/20 mb-3" />
									<p className="text-sm text-muted-foreground/60 text-center">
										No environment variables added yet.<br />
										Add one or upload a .env file.
									</p>
								</div>
							) : (
								<div className="space-y-2">
									<div className="flex flex-row gap-4 px-1 mb-2">
										<span className="text-[10px] w-1/2 font-bold text-muted-foreground/40 uppercase tracking-wider">Key</span>
										<span className="text-[10px] w-1/2 font-bold text-muted-foreground/40 uppercase tracking-wider">Value</span>
									</div>
									<div className="space-y-2">
										{entries.map((entry, index) => (
											<div key={index} className="flex flex-row gap-2 items-center animate-in fade-in slide-in-from-right-2 duration-200">
												<Input
													value={entry.name}
													onPaste={(e) => handlePaste(index, e)}
													onChange={(e) => handleUpdateVariable(index, "name", e.target.value)}
													placeholder="NAME"
													className="bg-white/[0.03] border-white/5 h-9 text-xs font-mono focus-visible:ring-primary/20"
												/>
												<Input
													value={entry.value}
													onChange={(e) => handleUpdateVariable(index, "value", e.target.value)}
													onFocus={() => setFocusedIndex(index)}
													onBlur={() => setFocusedIndex(null)}
													placeholder="VALUE"
													type={focusedIndex === index ? "text" : "password"}
													className="bg-white/[0.03] border-white/5 h-9 text-xs font-mono focus-visible:ring-primary/20"
												/>
												<Button
													variant="ghost"
													size="icon"
													onClick={() => handleRemoveVariable(index)}
													className="h-9 w-9 text-muted-foreground/40 hover:text-destructive hover:bg-destructive/10 shrink-0"
												>
													<Trash2 className="size-3.5" />
												</Button>
											</div>
										))}
									</div>
								</div>
							)}
						</div>
					</ScrollArea>
				</div>

				<div className="p-6 border-t border-white/5 bg-white/[0.01]">
					<Button
						className="w-full h-11 bg-primary hover:bg-primary/90 text-sm font-bold shadow-lg shadow-primary/10"
						onClick={() => onOpenChange(false)}
					>
						Done
					</Button>
				</div>
			</SheetContent>
		</Sheet>
	);
}

import * as React from "react";
import { useEffect, useRef, useState } from "react";
import { CheckCircle2, Circle, Loader2, XCircle, Terminal, RefreshCw } from "lucide-react";
import { SDArtifactsResponse } from "@/app/types";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";

export type FeedbackProgressPayload = {
	repoUrl: string;
	commitSha?: string;
	feedback: string;
};

type FeedbackProgressProps = {
	payload: FeedbackProgressPayload;
	onComplete: (data: SDArtifactsResponse) => void;
	onCancel: () => void;
};

const NODES = [
	{ id: "feedback_coordinator", label: "Feedback Coordinator", desc: "Orchestrating improvements" },
	{ id: "dockerfile_improver", label: "Dockerfile Improver", desc: "Optimizing Dockerfiles" },
	{ id: "compose_improver", label: "Compose Improver", desc: "Updating compose configuration" },
	{ id: "nginx_improver", label: "Nginx Improver", desc: "Improving routing and proxy" },
	{ id: "feedback_verifier", label: "Feedback Verifier", desc: "Validating improved artifacts" },
];

export default function FeedbackProgress({ payload, onComplete, onCancel }: FeedbackProgressProps) {
	const { repoUrl, commitSha, feedback } = payload;
	const [activeNode, setActiveNode] = useState<string>("feedback_coordinator");
	const [completedNodes, setCompletedNodes] = useState<string[]>([]);
	const [failedNode, setFailedNode] = useState<string | null>(null);
	const [logs, setLogs] = useState<string[]>([]);
	const [progress, setProgress] = useState(0);
	const logsEndRef = useRef<HTMLDivElement>(null);
	const abortControllerRef = useRef<AbortController | null>(null);

	useEffect(() => {
		abortControllerRef.current = new AbortController();

		const startStream = async () => {
			try {
				const response = await fetch("/api/feedback/stream", {
					method: "POST",
					headers: { "Content-Type": "application/json" },
					body: JSON.stringify({
						repo_url: repoUrl,
						...(commitSha && { commit_sha: commitSha }),
						feedback,
					}),
					signal: abortControllerRef.current?.signal,
				});

				if (!response.ok) {
					const data = await response.json().catch(() => ({}));
					throw new Error(data.error || data.details || "Failed to start feedback stream");
				}

				if (!response.body) {
					throw new Error("No response body");
				}

				const reader = response.body.getReader();
				const decoder = new TextDecoder();
				let buffer = "";

				const appendLog = (msg: string) => {
					setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);
					window.requestAnimationFrame(() => {
						logsEndRef.current?.scrollIntoView({ behavior: "smooth" });
					});
				};

				appendLog("info: feedback workflow started");

				const processMessage = (message: string) => {
					const lines = message.split(/\r?\n/);
					let eventType = "message";
					let dataStr = "";

					for (const line of lines) {
						if (!line.trim()) continue;
						const colonIndex = line.indexOf(":");
						if (colonIndex === -1) continue;
						const field = line.slice(0, colonIndex).trim();
						const value = line.slice(colonIndex + 1).replace(/^ /, "");
						if (field === "event") eventType = value;
						else if (field === "data") dataStr += (dataStr ? "\n" : "") + value;
					}

					if (dataStr) {
						try {
							const data = JSON.parse(dataStr);
							if (eventType === "progress") {
								const { node, status } = data;
								appendLog(`event: progress data: {"node": "${node}", "status": "${status}"}`);
								if (status === "started") {
									setActiveNode(node);
								} else if (status === "completed") {
									setCompletedNodes(prev => [...new Set([...prev, node])]);
									const nodeIndex = NODES.findIndex(n => n.id === node);
									if (nodeIndex >= 0) {
										setProgress(Math.round(((nodeIndex + 1) / NODES.length) * 100));
									}
								} else if (status === "error") {
									setFailedNode(node);
									appendLog(`error: ${data.message || "Unknown error in node " + node}`);
								}
							} else if (eventType === "complete") {
								appendLog("event: feedback complete");
								setProgress(100);
								onComplete(data as SDArtifactsResponse);
							} else if (eventType === "error") {
								const errorMsg = data.detail || data.message || "Unknown error";
								appendLog(`error: ${errorMsg}`);
								setFailedNode(activeNode);
							}
						} catch (e) {
							console.error("Failed to parse SSE JSON data", e, dataStr);
							appendLog(`error: JSON parse failed for ${eventType}`);
						}
					}
				};

				while (true) {
					const { done, value } = await reader.read();
					if (value) {
						const chunk = decoder.decode(value, { stream: true });
						buffer += chunk;
						const messages = buffer.split("\n\n");
						buffer = messages.pop() || "";
						for (const msg of messages) {
							if (msg.trim()) processMessage(msg);
						}
					}
					if (done) {
						if (buffer.trim()) processMessage(buffer);
						break;
					}
				}
			} catch (error: unknown) {
				if (error instanceof Error && error.name !== "AbortError") {
					console.error("Feedback stream error:", error);
					setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] error: ${error.message}`]);
				}
			}
		};

		startStream();

		return () => {
			if (abortControllerRef.current) {
				abortControllerRef.current.abort();
			}
		};
	}, [repoUrl, commitSha, feedback]);

	return (
		<div className="w-full flex-1 flex flex-col min-h-[600px] bg-background/50 animate-in fade-in duration-500">
			<div className="flex items-center gap-3 mb-6">
				<div className="p-2 bg-primary/10 rounded-lg">
					<RefreshCw className="size-5 text-primary" />
				</div>
				<div>
					<h2 className="text-xl font-semibold text-foreground tracking-tight">Improving Scan Results</h2>
					<p className="text-sm text-muted-foreground">SmartDeploy is applying your feedback to improve Dockerfiles, compose, and nginx</p>
				</div>
			</div>

			<div className="flex flex-col lg:flex-row gap-6 h-full">
				<div className="w-full lg:w-1/3 flex flex-col gap-4">
					<h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-2">Workflow Chain</h3>
					<div className="flex flex-col gap-3">
						{NODES.map((node) => {
							const isCompleted = completedNodes.includes(node.id);
							const isActive = activeNode === node.id && !isCompleted && !failedNode;
							const isFailed = failedNode === node.id;
							return (
								<Card
									key={node.id}
									className={`p-4 border transition-all duration-300 ${
										isActive
											? "border-primary/50 shadow-[0_0_15px_rgba(var(--primary),0.1)] bg-card/80"
											: isCompleted
												? "border-emerald-500/20 bg-background/40"
												: isFailed
													? "border-destructive/50 bg-destructive/10"
													: "border-border/30 bg-background/20 opacity-60"
									}`}
								>
									<div className="flex items-center justify-between">
										<div className="flex items-center gap-3">
											{isCompleted ? (
												<CheckCircle2 className="size-5 text-emerald-500" />
											) : isActive ? (
												<Loader2 className="size-5 text-primary animate-spin" />
											) : isFailed ? (
												<XCircle className="size-5 text-destructive" />
											) : (
												<Circle className="size-5 text-muted-foreground/50" />
											)}
											<div className="flex flex-col">
												<span
													className={`font-medium text-sm ${isActive ? "text-primary" : isCompleted ? "text-foreground" : "text-muted-foreground"}`}
												>
													{node.label}
												</span>
												<span className="text-xs text-muted-foreground/80">{node.desc}</span>
											</div>
										</div>
										{isCompleted && (
											<span className="text-[10px] uppercase font-bold text-emerald-500/80 bg-emerald-500/10 px-2 py-0.5 rounded">
												Done
											</span>
										)}
									</div>
								</Card>
							);
						})}
					</div>
				</div>

				<div className="w-full lg:w-2/3 flex flex-col flex-1">
					<div className="flex items-center justify-between mb-2">
						<h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Feedback Stream</h3>
						<div className="flex items-center gap-2">
							<span className="relative flex h-2 w-2">
								<span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75" />
								<span className="relative inline-flex rounded-full h-2 w-2 bg-red-500" />
							</span>
							<span className="text-[10px] text-muted-foreground uppercase tracking-wider">Live Feed</span>
						</div>
					</div>

					<Card className="flex-1 min-h-[400px] flex flex-col bg-[#0d0d0d] border-[#1e1e1e] overflow-hidden">
						<div
							className="flex-1 p-4 font-mono text-xs md:text-sm text-gray-300 overflow-y-auto space-y-1.5 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent"
							data-logs-scroll
						>
							{logs.map((log, i) => (
								<div key={i} className="break-words">
									{log.includes("info:") ? (
										<span className="text-blue-400">{log}</span>
									) : log.includes("error:") ? (
										<span className="text-red-400">{log}</span>
									) : log.includes("event: progress") ? (
										<span className="text-purple-400">{log}</span>
									) : (
										<span className="text-gray-400">{log}</span>
									)}
								</div>
							))}
							<div ref={logsEndRef} />
						</div>

						<div className="p-4 border-t border-[#1e1e1e]/50 bg-[#0a0a0a]">
							<div className="flex items-center justify-between mb-2">
								<span className="text-xs text-gray-400 font-medium">Total Progress</span>
								<span className="text-xs text-white font-mono">{progress}%</span>
							</div>
							<div className="h-1.5 w-full bg-gray-800 rounded-full overflow-hidden">
								<div
									className="h-full bg-primary transition-all duration-500 ease-out"
									style={{ width: `${progress}%` }}
								/>
							</div>
						</div>
					</Card>
				</div>
			</div>

			<div className="flex items-center justify-end gap-3 mt-8 pt-6 border-t border-border/30">
				<Button variant="outline" onClick={onCancel} className="text-muted-foreground hover:text-foreground">
					Cancel
				</Button>
				<Button disabled className="bg-primary/20 text-primary-foreground opacity-50">
					Improving…
				</Button>
			</div>
		</div>
	);
}

