													</div>
													<div className="relative group">
														<div className="pointer-events-none absolute left-2.5 top-1/2 -translate-y-1/2 font-mono text-[10px] text-muted-foreground/30 transition-colors group-focus-within:text-primary/50">
															https://
														</div>
														<Input
															value={getCurrentFieldValue(selectedNode, "url")}
															placeholder="my-cool-app"
															className="h-11 rounded-xl border-white/10 bg-white/[0.02] pl-14 pr-32 text-sm font-medium text-foreground placeholder:text-muted-foreground/20"
															onChange={(event) => setDraftData((current) => ({ ...current, url: event.target.value }))}
														/>
														<div className="pointer-events-none absolute right-3.5 top-1/2 -translate-y-1/2">
															<span className="font-mono text-[10px] text-muted-foreground/20">.{DOMAIN_SUFFIX}</span>
														</div>
													</div>
												</div>
											) : null}
											{BLUEPRINT_NODE_FIELDS[selectedNode.kind]
												.filter((field) => !(selectedNode.kind === "envVars" && field.key === "value"))
												.filter((field) => !(selectedNode.kind === "customDomain" && field.key === "url"))
												.filter((field) => {
													const value = selectedNode.data?.[field.key];
													return field.editable || (value !== null && value !== undefined && value !== "");
												})
												.map((field) => {
													const value = selectedNode.data?.[field.key];
													const fieldId = `${selectedNode.id}:${field.key}`;
													const disabled = savingFieldId === fieldId;

													return (
														<div key={field.key} className="rounded-2xl border border-white/8 bg-white/[0.03] px-4 py-3">
															<div className="mb-2 text-xs font-medium uppercase tracking-wide text-muted-foreground">
																{field.label}
															</div>
															{field.editable ? (
																field.type === "textarea" ? (
																	<Textarea
																		value={getCurrentFieldValue(selectedNode, field.key)}
																		disabled={disabled}
																		placeholder={field.placeholder}
																		className="min-h-28 rounded-xl border-white/10 bg-white/[0.02] text-sm text-foreground"
																		onChange={(event) => setDraftData((current) => ({ ...current, [field.key]: event.target.value }))}
																	/>
																) : field.type === "select" ? (
																	<Select
																		value={getCurrentFieldValue(selectedNode, field.key)}
																		onValueChange={(next) => setDraftData((current) => ({ ...current, [field.key]: next }))}
																		disabled={disabled}
																	>
																		<SelectTrigger className="h-11 rounded-xl border-white/10 bg-white/[0.02] text-sm text-foreground">
																			<SelectValue placeholder={field.placeholder || field.label} />
																		</SelectTrigger>
																		<SelectContent>
																			{getFieldOptions(selectedNode, field.key).map((option) => (
																				<SelectItem key={option.value} value={option.value}>
																					{option.label}
																				</SelectItem>
																			))}
																		</SelectContent>
																	</Select>
																) : (
																	<Input
																		type={field.type === "number" ? "number" : "text"}
																		value={getCurrentFieldValue(selectedNode, field.key)}
																		disabled={disabled}
																		placeholder={field.placeholder}
																		className="h-11 rounded-xl border-white/10 bg-white/[0.02] text-sm text-foreground"
																		onChange={(event) => setDraftData((current) => ({ ...current, [field.key]: event.target.value }))}
																	/>
																)
															) : (
																<div className="text-sm text-foreground/90">
																	{formatFieldValue(value)}
																</div>
															)}
														</div>
													);
												})}
										</div>
									</div>
								) : null}
							</div>
						</>
					) : null}
				</SheetContent>
			</Sheet>
			<AlertDialog open={showUnsavedDialog} onOpenChange={setShowUnsavedDialog}>
				<AlertDialogContent className="border-white/8 bg-[#0b0d12] text-foreground">
					<AlertDialogHeader>
						<AlertDialogTitle>Save changes?</AlertDialogTitle>
						<AlertDialogDescription>
							This sheet has unsaved changes. You can save them before closing or discard them.
						</AlertDialogDescription>
					</AlertDialogHeader>
					<AlertDialogFooter>
						<Button
							type="button"
							variant="ghost"
							onClick={() => setShowUnsavedDialog(false)}
							className="text-muted-foreground"
						>
							Keep Editing
						</Button>
						<AlertDialogCancel
							onClick={() => {
								setShowUnsavedDialog(false);
								resetDrafts(selectedNode);
								setIsDetailOpen(false);
							}}
							className="border-white/10 bg-white/[0.03] text-foreground hover:bg-white/[0.06]"
						>
							Discard
						</AlertDialogCancel>
						<AlertDialogAction
							onClick={async () => {
								await saveDraftChanges();
								setShowUnsavedDialog(false);
								setIsDetailOpen(false);
							}}
							className="bg-primary text-primary-foreground hover:bg-primary/90"
						>
							Save
						</AlertDialogAction>
					</AlertDialogFooter>
				</AlertDialogContent>
			</AlertDialog>
		</>
	);
}

"use client";

import * as React from "react";
import { useRef } from "react";
import ServiceLogs from "@/components/ServiceLogs";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Loader2, HelpCircle, CheckCircle2, XCircle, Clock, GitCommit, User, Calendar, RefreshCw } from "lucide-react";
import { DeployStep } from "@/app/types";

export type DeployStatus = "not-started" | "running" | "success" | "error";

type LogEntry = { timestamp?: string; message?: string };
type CommitInfo = { sha: string; message: string; author: string; date: string };

type DeployLogsViewProps = {
	showDeployLogs: boolean;
	deployLogEntries: LogEntry[];
	serviceLogs: LogEntry[];
	deployStatus: DeployStatus;
	deployError?: string | null;
	deployingCommitInfo?: CommitInfo | null;
	steps?: DeployStep[];
	configSnapshot?: any;
	repoUrl?: string;
	commitSha?: string;
	onStartImproveScan?: (payload: { repoUrl: string; commitSha?: string; feedback: string }) => void;
	repoNameForLogs?: string;
	serviceNameForLogs?: string;
};

export default function DeployLogsView({
	showDeployLogs,
	deployLogEntries,
	serviceLogs,
	deployStatus,
	deployError,
	deployingCommitInfo,
	steps,
	configSnapshot,
	repoUrl,
	commitSha,
	onStartImproveScan,
	repoNameForLogs,
	serviceNameForLogs,
}: DeployLogsViewProps) {
	const logsContainerRef = useRef<HTMLDivElement>(null);
	const [analyzing, setAnalyzing] = React.useState(false);
	const [analysisResult, setAnalysisResult] = React.useState<string | null>(null);

	const handleWhyDidItFail = async () => {
		if (!steps || !configSnapshot) return;
		setAnalyzing(true);
		setAnalysisResult(null);
		try {
			const res = await fetch("/api/llm/analyze-failure", {
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: JSON.stringify({ steps, configSnapshot }),
			});
			const data = await res.json();
			if (data.response) {
				setAnalysisResult(data.response);
			} else {
				setAnalysisResult(data.error || data.details || "Analysis failed.");
			}
		} catch (err) {
			setAnalysisResult(err instanceof Error ? err.message : "Request failed.");
		} finally {
			setAnalyzing(false);
		}
	};

	function handleImproveScanResults() {
		if (!analysisResult || !repoUrl || !onStartImproveScan) return;
		onStartImproveScan({ repoUrl, commitSha, feedback: analysisResult });
	}

	// While deploying (or viewing completed deploy logs): show deployment (step) logs.
	// After deployment completes and on page refresh: show service logs (history + live).
	const showingDeployLogs = deployStatus === "running" || (showDeployLogs && deployLogEntries.length > 0 && (deployStatus === "success" || deployStatus === "error"));
	const logsToRender = showingDeployLogs ? deployLogEntries : serviceLogs;
	const showDeploymentHeader = showDeployLogs;

	const completedSteps = showDeploymentHeader ? (steps?.filter(s => s.status === "success").length || 0) : 0;
	const totalSteps = showDeploymentHeader ? (steps?.length || 1) : 1;
	const progress = showDeploymentHeader ? (completedSteps / totalSteps) * 100 : 0;

	const headerTitle = showDeploymentHeader
		? deployStatus === "running"
			? "Deployment in Progress"
			: deployStatus === "success"
				? "Deployment Successful"
				: deployStatus === "error"
					? "Deployment Failed"
					: "Awaiting Deployment"
		: "Service Logs";

	const headerSubtitle = showDeploymentHeader
		? deployStatus === "running"
			? `Step ${completedSteps + 1} of ${totalSteps}`
			: deployStatus === "success"
				? "All steps completed successfully"
				: deployStatus === "error"
					? "An error occurred during deployment"
					: "Ready to deploy"
		: "Historical + live service output";

	return (
		<div className="flex h-full min-h-0 flex-col gap-6 overflow-hidden">
			{/* Live Status Header */}
			<div className="rounded-2xl border border-white/5 bg-white/2 p-6 shadow-xl backdrop-blur-sm overflow-hidden relative group">
				{showDeploymentHeader && (
					<div className="absolute top-0 left-0 w-full h-[2px] bg-white/5">
						<div
							className={`h-full transition-all duration-1000 ease-out ${deployStatus === "error" ? "bg-destructive" : "bg-primary"}`}
							style={{ width: `${progress}%` }}
						/>
					</div>
				)}

				<div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
					<div className="space-y-4 flex-1">
						<div className="flex items-center gap-3">
								<div
									className={`p-2 rounded-xl ${
										!showDeploymentHeader
											? "bg-muted text-muted-foreground"
											: deployStatus === "running"
												? "bg-primary/10 text-primary animate-pulse"
												: deployStatus === "success"
													? "bg-emerald-500/10 text-emerald-500"
													: deployStatus === "error"
														? "bg-destructive/10 text-destructive"
														: "bg-muted text-muted-foreground"
									}`}
								>
									{showDeploymentHeader ? (
										<>
											{deployStatus === "running" && <Loader2 className="size-6 animate-spin" />}
											{deployStatus === "success" && <CheckCircle2 className="size-6" />}
											{deployStatus === "error" && <XCircle className="size-6" />}
											{deployStatus === "not-started" && <Clock className="size-6" />}
										</>
									) : (
										<Clock className="size-6" />
									)}
								</div>
							<div>
								<h3 className="text-lg font-bold text-foreground flex items-center gap-2">
										{headerTitle}
								</h3>
									<p className="text-sm text-muted-foreground/60 flex items-center gap-2">{headerSubtitle}</p>
							</div>
						</div>

						{deployingCommitInfo && (
							<div className="grid grid-cols-1 sm:grid-cols-3 gap-4 pt-2">
								<div className="flex items-center gap-2 text-xs font-medium text-muted-foreground/80 bg-white/5 border border-white/5 rounded-lg px-3 py-2">
									<GitCommit className="size-3.5 text-primary" />
									<span className="font-mono">{deployingCommitInfo.sha.substring(0, 7)}</span>
								</div>
								<div className="flex items-center gap-2 text-xs font-medium text-muted-foreground/80 bg-white/5 border border-white/5 rounded-lg px-3 py-2">
									<User className="size-3.5 text-primary" />
									<span className="truncate">{deployingCommitInfo.author}</span>
								</div>
								<div className="flex items-center gap-2 text-xs font-medium text-muted-foreground/80 bg-white/5 border border-white/5 rounded-lg px-3 py-2">
									<Calendar className="size-3.5 text-primary" />
									<span>{new Date(deployingCommitInfo.date).toLocaleTimeString()}</span>
								</div>
							</div>
						)}
					</div>

					<div className="flex flex-col items-end gap-3 shrink-0">
						{showDeploymentHeader && steps && (
							<div className="flex items-center gap-2">
								{steps.map((step) => (
									<div
										key={step.id}
										className={`size-2 rounded-full transition-all duration-300 ${
											step.status === "success"
												? "bg-emerald-500"
												: step.status === "in_progress"
													? "bg-primary animate-pulse scale-125"
													: step.status === "error"
														? "bg-destructive shadow-[0_0_8px_rgba(239,68,68,0.5)]"
														: "bg-white/10"
										}`}
										title={step.label}
									/>
								))}
							</div>
						)}
						{deployStatus === "running" && (
							<span className="text-[10px] font-bold text-primary uppercase tracking-widest animate-pulse">Live</span>
						)}
					</div>
				</div>
			</div>

			{showDeployLogs && deployError && (
				<Alert className="border-destructive/50 bg-destructive/10 text-foreground flex flex-col gap-3">
					<div>
						<AlertTitle className="text-destructive/80 font-bold">Deployment failed</AlertTitle>
						<AlertDescription className="overflow-x-auto text-sm">{deployError}</AlertDescription>
					</div>
					{steps && configSnapshot && (
						<div className="mt-2 text-right">
							<Button
								variant="outline"
								size="sm"
								className="border-destructive/30 bg-background/50 text-foreground hover:bg-destructive/20 font-semibold"
								onClick={handleWhyDidItFail}
								disabled={analyzing}
							>
								{analyzing ? (
									<>
										<Loader2 className="size-4 animate-spin mr-2" />
										Analyzing logs…
									</>
								) : (
									<>
										<HelpCircle className="size-4 mr-2" />
										Explain root cause
									</>
								)}
							</Button>
							{analysisResult && (
								<>
									<Alert className="mt-3 border-destructive/30 bg-background/50 text-foreground text-left transition-all">
										<AlertDescription className="text-sm pb-0 whitespace-pre-wrap leading-relaxed">
											{analysisResult}
										</AlertDescription>
									</Alert>
									{repoUrl && onStartImproveScan && (
										<div className="mt-3 flex justify-end">
											<Button
												variant="outline"
												size="sm"
												className="border-primary/30 bg-background/50 text-foreground hover:bg-primary/20 font-semibold"
												onClick={handleImproveScanResults}
											>
												<RefreshCw className="size-4 mr-2" />
												Improve Scan Results
											</Button>
										</div>
									)}
								</>
							)}
						</div>
					)}
				</Alert>
			)}

			<div ref={logsContainerRef} className="min-h-0 flex-1 rounded-2xl border border-white/5 bg-[#0A0A0F] overflow-hidden shadow-2xl">
			<ServiceLogs
				key={`${repoNameForLogs ?? ""}:${serviceNameForLogs ?? ""}`}
				{...((
					{
						logs: logsToRender,
						repoName: repoNameForLogs,
						serviceName: serviceNameForLogs,
						deployStatus,
						displayLimit: 14,
						scrollable: false,
					} as unknown) as any)}
			/>
			</div>
		</div>
	);
}

import { ExternalLink, Link2, RefreshCw, Settings } from "lucide-react";
import { Button } from "@/components/ui/button";
import { DeployConfig, EC2Details, repoType } from "@/app/types";
import {
	formatTimestamp,
	formatDeploymentTargetName,
	getDeploymentDisplayUrl,
	isDeploymentDisabled,
} from "@/lib/utils";
import { resolveWorkspaceBranch } from "@/lib/repoBranch";
import DeployOptions from "@/components/DeployOptions";
import { DEFAULT_EC2_INSTANCE_TYPE, formatApproxEc2PriceCompact } from "@/lib/aws/ec2InstanceTypes";

type DeployOverviewProps = {
	deployment: DeployConfig;
	region?: string;
	isDeploying?: boolean;
	isRefreshingPreview?: boolean;
	onRedeploy?: (commitSha?: string) => void;
	onRefreshPreview?: () => void;
	onEditConfiguration?: () => void;
	repo?: repoType;
};

const IPV4_RE = /^(?:\d{1,3}\.){3}\d{1,3}$/;

function hrefForEndpoint(raw: string): string | undefined {
	const t = raw.trim();
	if (!t) return undefined;
	if (/^https?:\/\//i.test(t)) return t;
	if (IPV4_RE.test(t)) return `http://${t}`;
	return undefined;
}

function EndpointRow({ label, value }: { label: string; value: string | undefined }) {
	const v = value?.trim();
	if (!v) {
		return (
			<div className="flex flex-col gap-0.5 sm:flex-row sm:items-baseline sm:justify-between sm:gap-4">
				<span className="shrink-0 text-[11px] font-medium uppercase tracking-wide text-muted-foreground">{label}</span>
				<span className="text-sm text-muted-foreground/70">—</span>
			</div>
		);
	}
	const href = hrefForEndpoint(v);
	return (
		<div className="flex flex-col gap-0.5 sm:flex-row sm:items-baseline sm:justify-between sm:gap-4">
			<span className="shrink-0 text-[11px] font-medium uppercase tracking-wide text-muted-foreground">{label}</span>
			{href ? (
				<a
					href={href}
					target="_blank"
					rel="noopener noreferrer"
					className="min-w-0 break-all text-right text-sm font-medium text-primary hover:underline sm:text-left"
				>
					<span className="inline-flex items-start justify-end gap-1 sm:justify-start">
						<span className="min-w-0">{v}</span>
						<ExternalLink className="mt-0.5 size-3.5 shrink-0 opacity-70" aria-hidden />
					</span>
				</a>
			) : (
				<span className="break-all text-sm text-foreground">{v}</span>
			)}
		</div>
	);
}

function DeploymentTargetSummary({
	deployDisabled,
	deploymentTarget,
	showEc2InstanceType,
	ec2TypeDisplay,
}: {
	deployDisabled: boolean;
	deploymentTarget: DeployConfig["deploymentTarget"];
	showEc2InstanceType: boolean;
	ec2TypeDisplay: string;
}) {
	const showService = !deployDisabled;
	if (!showService && !showEc2InstanceType) return null;

	return (
		<div className="rounded-xl border border-border bg-card p-4">
			<p className="text-xs uppercase tracking-wider text-muted-foreground">Platform</p>
			<dl className="mt-3 space-y-3 text-sm">
				{showService && (
					<div>
						<dt className="text-[11px] font-medium uppercase tracking-wide text-muted-foreground">Deployed service</dt>
						<dd className="mt-0.5 font-medium text-foreground">
							{deploymentTarget ? formatDeploymentTargetName(deploymentTarget) : "Pending"}
						</dd>
					</div>
				)}
				{showEc2InstanceType && (
					<div>
						<dt className="text-[11px] font-medium uppercase tracking-wide text-muted-foreground">Instance type</dt>
						<dd className="mt-0.5 font-mono text-xs text-foreground">{ec2TypeDisplay}</dd>
					</div>
				)}
			</dl>
		</div>
	);
}

export default function DeployOverview({
	deployment,
	region = "us-west-2",
	isDeploying = false,
	isRefreshingPreview = false,
	onRedeploy,
	onRefreshPreview,
	onEditConfiguration,
	repo,
}: DeployOverviewProps) {
	const hasStoredLiveUrl = Boolean(deployment.liveUrl);
	// If a DB row says "running" but we don't have a stored live URL, treat it as not deployed.
	const effectiveStatus =
		deployment.status === "running" && !hasStoredLiveUrl ? "didnt_deploy" : (deployment.status ?? "didnt_deploy");
	const displayUrl = effectiveStatus === "running" ? getDeploymentDisplayUrl(deployment) : undefined;
	const screenshotUrl = deployment.screenshotUrl;
	const customUrlRaw = deployment.liveUrl?.trim();
	const instanceIpRaw = ((deployment.ec2 || {}) as EC2Details)?.publicIp?.trim?.();
	const hasAnyEndpoint = Boolean(customUrlRaw || instanceIpRaw);
	const deployDisabled = isDeploymentDisabled(deployment);
	const ec2Casted = (deployment.ec2 || {}) as EC2Details;
	const showEc2InstanceType =
		deployment.deploymentTarget === "ec2" || !!ec2Casted.instanceId;
	const ec2TypeDisplay =
		ec2Casted.instanceType?.trim() || DEFAULT_EC2_INSTANCE_TYPE;
	const ec2PriceEstimate = showEc2InstanceType
		? formatApproxEc2PriceCompact(ec2TypeDisplay)
		: null;

	const regionDisplay = (deployment.awsRegion || region).trim() || region;

	return (
		<div className="space-y-6">
			<div className="flex flex-wrap items-center justify-between gap-4">
				<div className="flex items-center gap-3">
					<p className="text-2xl font-semibold text-foreground">{deployment.serviceName}</p>
					<span className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-3 py-1 text-xs font-semibold uppercase tracking-wide text-primary">
						<span className="h-2 w-2 rounded-full bg-primary" />
						{effectiveStatus}
					</span>
				</div>
				<div className="flex items-center gap-2">
					{onEditConfiguration && (
						<Button
							onClick={onEditConfiguration}
							variant="outline"
							className="inline-flex items-center gap-2 rounded-md border-border bg-transparent text-foreground hover:bg-secondary/50 hover:text-foreground"
						>
							<Settings className="size-4" />
							Edit Configuration
						</Button>
					)}
					{onRedeploy && (
						<DeployOptions
							onDeploy={onRedeploy}
							disabled={isDeploying || deployDisabled}
							repo={repo}
							branch={resolveWorkspaceBranch(repo, deployment.branch) || ""}
						/>
					)}
					{displayUrl && (
						<a
							href={displayUrl}
							target="_blank"
							rel="noopener noreferrer"
							className="inline-flex items-center gap-2 rounded-md bg-primary px-4 py-2 text-sm font-semibold text-primary-foreground hover:bg-primary/90"
						>
							Visit Site
							<ExternalLink className="size-4" />
						</a>
					)}
				</div>
			</div>

			<div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,2fr)_minmax(0,1fr)]">
				<div className="space-y-6">
					<div className="rounded-xl border border-border bg-card">
						<div className="flex items-center justify-between border-b border-border px-4 py-3 text-xs uppercase tracking-wider text-muted-foreground">
							<span>Front page preview</span>
							<div className="flex items-center gap-2">
								<span className="text-muted-foreground/70">Live topology</span>
								{onRefreshPreview && displayUrl && (
									<Button
										variant="outline"
										size="sm"
										onClick={onRefreshPreview}
										disabled={isRefreshingPreview}
										className="h-7 gap-1.5 px-2 text-[10px] font-semibold tracking-normal normal-case"
									>
										<RefreshCw className={`size-3 ${isRefreshingPreview ? "animate-spin" : ""}`} />
										{isRefreshingPreview ? "Creating..." : "New Preview"}
									</Button>
								)}
							</div>
						</div>
						{screenshotUrl ? (
							<div className="relative h-80 md:h-96">
								<img
									src={screenshotUrl}
									alt={`Screenshot of ${deployment.serviceName}`}
									className="absolute inset-0 h-full w-full pointer-events-none object-cover overflow-hidden rounded-b-lg"
								/>
							</div>
						) : displayUrl ? (
							<div className="relative h-80 md:h-96">
								<iframe
									src={displayUrl}
									title={`Snapshot of ${deployment.serviceName}`}
									className="absolute inset-0 h-full w-full pointer-events-none overflow-hidden rounded-b-lg"
									loading="lazy"
								/>
							</div>
						) : (
							<div className="p-6 text-sm text-muted-foreground">
								No live URL yet. Deploy to generate a preview snapshot.
							</div>
						)}
					</div>

					<div className="rounded-xl border border-border bg-card">
						<div className="grid grid-cols-1 divide-y divide-border text-sm text-muted-foreground">
							{ec2PriceEstimate && (
								<div className="flex items-center justify-between px-4 py-3">
									<span>On-demand estimate (Linux, {regionDisplay})</span>
										<span className="text-right text-xs text-muted-foreground max-w-56">
										{ec2PriceEstimate}
									</span>
								</div>
							)}
							<div className="space-y-3 px-4 py-3">
								<div className="flex items-center gap-2 text-xs font-medium uppercase tracking-wider text-muted-foreground">
									<Link2 className="size-3.5 opacity-70" aria-hidden />
									<span>Live URLs & access</span>
								</div>
								{hasAnyEndpoint ? (
									<div className="space-y-3 border-t border-border/60 pt-3">
										<EndpointRow label="Custom URL" value={customUrlRaw} />
										<EndpointRow label="Instance IP" value={instanceIpRaw} />
									</div>
								) : (
									<p className="border-t border-border/60 pt-3 text-sm text-muted-foreground/70">Not available</p>
								)}
							</div>
						</div>
					</div>
				</div>

				<div className="space-y-4">
					<DeploymentTargetSummary
						deployDisabled={deployDisabled}
						deploymentTarget={deployment.deploymentTarget}
						showEc2InstanceType={showEc2InstanceType}
						ec2TypeDisplay={ec2TypeDisplay}
					/>
					<div className="rounded-xl border border-border bg-card p-4">
						<p className="text-xs uppercase tracking-wider text-muted-foreground">Last Deployment</p>
						<p className="mt-2 text-lg font-semibold text-foreground">
						{formatTimestamp(deployment.lastDeployment || undefined)}
