async function ensureAlb(
	albName: string,
	subnetIds: string[],
	albSgId: string,
	region: string,
	ws: any
): Promise<{ albArn: string; dnsName: string }> {
	try {
		const albArn = (
			await runAWSCommand(
				[
					"elbv2",
					"describe-load-balancers",
					"--names",
					albName,
					"--query",
					"LoadBalancers[0].LoadBalancerArn",
					"--output",
					"text",
					"--region",
					region,
				],
				ws,
				"deploy"
			)
		).trim();
		const dnsName = (
			await runAWSCommand(
				[
					"elbv2",
					"describe-load-balancers",
					"--names",
					albName,
					"--query",
					"LoadBalancers[0].DNSName",
					"--output",
					"text",
					"--region",
					region,
				],
				ws,
				"deploy"
			)
		).trim();
		if (albArn && albArn !== "None") return { albArn, dnsName };
	} catch {
		// does not exist
	}

	const albArn = (
		await runAWSCommand(
			[
				"elbv2",
				"create-load-balancer",
				"--name",
				albName,
				"--type",
				"application",
				"--scheme",
				"internet-facing",
				"--subnets",
				...subnetIds,
				"--security-groups",
				albSgId,
				"--query",
				"LoadBalancers[0].LoadBalancerArn",
				"--output",
				"text",
				"--region",
				region,
			],
			ws,
			"deploy"
		)
	).trim();

	const dnsName = (
		await runAWSCommand(
			[
				"elbv2",
				"describe-load-balancers",
				"--load-balancer-arns",
				albArn,
				"--query",
				"LoadBalancers[0].DNSName",
				"--output",
				"text",
				"--region",
				region,
			],
			ws,
			"deploy"
		)
	).trim();

	return { albArn, dnsName };
}

