export async function ensureHostRule(
	listenerArn: string,
	hostname: string,
	targetGroupArn: string,
	region: string,
	ws: any
): Promise<void> {
	const rulesRaw = await runAWSCommand([
		"elbv2",
		"describe-rules",
		"--listener-arn",
		listenerArn,
		"--output",
		"json",
		"--region",
		region,
	], ws, "deploy");

	let rules: Array<{
		RuleArn?: string;
		Priority?: string;
		Conditions?: Array<{ Field?: string; HostHeaderConfig?: { Values?: string[] } }>;
		Actions?: Array<{ Type?: string; TargetGroupArn?: string }>;
	}> = [];
	try {
		const parsed = JSON.parse(rulesRaw);
		rules = Array.isArray(parsed?.Rules) ? parsed.Rules : [];
	} catch {
		rules = [];
	}

	const existingRule = rules.find((rule) =>
		(rule.Conditions || []).some((cond) =>
			cond.Field === "host-header" && (cond.HostHeaderConfig?.Values || []).includes(hostname)
		)
	);
	if (existingRule?.RuleArn) {
		const currentTargetGroup = (existingRule.Actions || []).find((a) => a.Type === "forward")?.TargetGroupArn;
		if (currentTargetGroup === targetGroupArn) return;
		await runAWSCommand([
			"elbv2",
			"modify-rule",
			"--rule-arn",
			existingRule.RuleArn,
			"--actions",
			`Type=forward,TargetGroupArn=${targetGroupArn}`,
			"--region",
			region,
		], ws, "deploy");
		return;
	}

	const numericPriorities = rules
		.map((r) => r.Priority)
		.filter((p): p is string => typeof p === "string" && p !== "default")
		.map((p) => Number(p))
		.filter((n) => Number.isFinite(n));

	const maxPriority = numericPriorities.length ? Math.max(...numericPriorities) : 100;
	let priority = maxPriority + 1;
	if (priority > 50000) priority = 50000;

	await runAWSCommand([
		"elbv2",
		"create-rule",
		"--listener-arn",
		listenerArn,
		"--priority",
		String(priority),
		"--conditions",
		`Field=host-header,HostHeaderConfig={Values=${hostname}}`,
		"--actions",
		`Type=forward,TargetGroupArn=${targetGroupArn}`,
		"--region",
		region,
	], ws, "deploy");
}

/**
 * Delete a host-based routing rule from an ALB listener for a specific hostname.
 * Used when removing an old custom domain during domain update.
 */
export async function deleteHostRule(
	listenerArn: string,
	hostname: string,
	region: string,
	ws: any
): Promise<boolean> {
	try {
		const rulesRaw = await runAWSCommand([
			"elbv2",
			"describe-rules",
			"--listener-arn",
			listenerArn,
			"--output",
			"json",
			"--region",
			region,
		], ws, "deploy");

		let rules: Array<{
			RuleArn?: string;
			IsDefault?: boolean;
			Priority?: string;
			Conditions?: Array<{ Field?: string; HostHeaderConfig?: { Values?: string[] } }>;
		}> = [];
		try {
			const parsed = JSON.parse(rulesRaw);
			rules = Array.isArray(parsed?.Rules) ? parsed.Rules : [];
		} catch {
			return false;
		}

		// Find the rule matching the hostname
		const ruleToDelete = rules.find((rule) =>
			!rule.IsDefault && rule.Priority !== "default" &&
			(rule.Conditions || []).some((cond) =>
				cond.Field === "host-header" && (cond.HostHeaderConfig?.Values || []).includes(hostname)
			)
		);

		if (!ruleToDelete?.RuleArn) {
			return false; // Rule not found
		}

		// Delete the rule
		await runAWSCommand(
			["elbv2", "delete-rule", "--rule-arn", ruleToDelete.RuleArn, "--region", region],
			ws,
			"deploy"
		);

		return true;
	} catch (error) {
		// Log but don't throw - deletion failures should not break the domain update
		console.error(`Failed to delete host rule for ${hostname}:`, error);
		return false;
	}
}

export async function registerInstanceToTargetGroup(
	targetGroupArn: string,
	instanceId: string,
	port: number,
	region: string,
	ws: any
): Promise<void> {
	await runAWSCommand([
		"elbv2",
		"register-targets",
		"--target-group-arn",
		targetGroupArn,
		"--targets",
		`Id=${instanceId},Port=${port}`,
		"--region",
		region,
	], ws, "deploy");
}

/**
 * When ACM is configured, the HTTP listener's default action must redirect to HTTPS.
 * Host-based *forward* rules on port 80 match before the default and would still serve plain HTTP — remove them
 * so app traffic uses TLS on 443 (host rules belong on the HTTPS listener only).
 */
async function stripForwardRulesFromListener(listenerArn: string, region: string, ws: any): Promise<void> {
	const send = createWebSocketLogger(ws);
	let rulesRaw: string;
	try {
		rulesRaw = await runAWSCommand(
			["elbv2", "describe-rules", "--listener-arn", listenerArn, "--output", "json", "--region", region],
			ws,
			"deploy"
		);
	} catch {
		return;
	}
	let rules: Array<{ RuleArn?: string; Priority?: string; IsDefault?: boolean; Actions?: Array<{ Type?: string }> }> = [];
	try {
		rules = JSON.parse(rulesRaw).Rules || [];
	} catch {
		return;
	}
	let removed = 0;
	for (const rule of rules) {
		if (rule.IsDefault || rule.Priority === "default") continue;
		const hasForward = (rule.Actions || []).some((a) => a.Type === "forward");
		if (!hasForward || !rule.RuleArn) continue;
		try {
			await runAWSCommand(["elbv2", "delete-rule", "--rule-arn", rule.RuleArn, "--region", region], ws, "deploy");
			removed++;
		} catch {
			// already deleted or race
		}
	}
	if (removed > 0) {
		send(`Removed ${removed} legacy HTTP forward rule(s); app routes now use HTTPS (443) only.`, "deploy");
	}
}

export async function ensureSharedAlb(
	params: {
		vpcId: string;
		subnetIds: string[];
		region: string;
		ws: any;
		certificateArn?: string;
	}
): Promise<{ albArn: string; dnsName: string; albSgId: string; httpListenerArn: string; httpsListenerArn?: string }> {
	const send = createWebSocketLogger(params.ws);
	const accountId = await getAccountId(params.ws);
	const suffix = accountId ? accountId.slice(-6) : "shared";
	const albName = `smartdeploy-${suffix}-alb`.slice(0, 32);
	const albSgName = `smartdeploy-${suffix}-alb-sg`.slice(0, 255);
	const certificateArn = params.certificateArn?.trim() || "";

	send(`Ensuring shared ALB (${albName})...`, "deploy");
	const albSgId = await ensureAlbSecurityGroup(albSgName, params.vpcId, params.ws);
	const { albArn, dnsName } = await ensureAlb(albName, params.subnetIds, albSgId, params.region, params.ws);
	const httpListenerArn = await ensureHttpListener(albArn, params.region, params.ws, {
		redirectToHttps: !!certificateArn,
	});
	const httpsListenerArn = certificateArn
		? await ensureHttpsListener(albArn, certificateArn, params.region, params.ws)
		: undefined;

	if (certificateArn) {
		await stripForwardRulesFromListener(httpListenerArn, params.region, params.ws);
	}

	return { albArn, dnsName, albSgId, httpListenerArn, httpsListenerArn };
}

import {
	CodeBuildClient,
	CreateProjectCommand,
	StartBuildCommand,
	BatchGetProjectsCommand,
	BatchGetBuildsCommand,
} from "@aws-sdk/client-codebuild";
import {
	CloudWatchLogsClient,
	GetLogEventsCommand,
} from "@aws-sdk/client-cloudwatch-logs";
import {
	IAMClient,
	GetRoleCommand,
	CreateRoleCommand,
	PutRolePolicyCommand,
} from "@aws-sdk/client-iam";
import { getAwsClientConfig } from "./sdkClients";
import { getAwsAccountId } from "./ecrHelpers";
import type { SDArtifactsResponse } from "../../app/types";

type SendFn = (msg: string, stepId: string) => void;

const CODEBUILD_PROJECT_NAME = "smartdeploy-builder";
const CODEBUILD_ROLE_NAME = "smartdeploy-codebuild-role";
const LOG_GROUP = `/aws/codebuild/${CODEBUILD_PROJECT_NAME}`;

// ─── IAM Role ─────────────────────────────────────────────────────────────

export async function ensureCodeBuildRole(
	region: string,
	send: SendFn,
): Promise<string> {
	const iam = new IAMClient(getAwsClientConfig(region));

	try {
		const resp = await iam.send(new GetRoleCommand({ RoleName: CODEBUILD_ROLE_NAME }));
		return resp.Role!.Arn!;
	} catch (e: any) {
		if (e.name !== "NoSuchEntity" && e.name !== "NoSuchEntityException") throw e;
	}

	send("Creating CodeBuild service role...", "build");
	const accountId = await getAwsAccountId(region);

	const trustPolicy = JSON.stringify({
		Version: "2012-10-17",
		Statement: [{
			Effect: "Allow",
			Principal: { Service: "codebuild.amazonaws.com" },
			Action: "sts:AssumeRole",
		}],
	});

	const createResp = await iam.send(new CreateRoleCommand({
		RoleName: CODEBUILD_ROLE_NAME,
		AssumeRolePolicyDocument: trustPolicy,
	}));
	const roleArn = createResp.Role!.Arn!;

	const permissionsPolicy = JSON.stringify({
		Version: "2012-10-17",
		Statement: [
			{
				Effect: "Allow",
				Action: ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"],
				Resource: `arn:aws:logs:${region}:${accountId}:log-group:/aws/codebuild/*`,
			},
			{
				Effect: "Allow",
				Action: [
					"ecr:CreateRepository",
					"ecr:DescribeRepositories",
					"ecr:GetAuthorizationToken",
					"ecr:BatchCheckLayerAvailability",
					"ecr:GetDownloadUrlForLayer",
					"ecr:BatchGetImage",
					"ecr:PutImage",
					"ecr:InitiateLayerUpload",
					"ecr:UploadLayerPart",
					"ecr:CompleteLayerUpload",
				],
				Resource: "*",
			},
		],
	});

	await iam.send(new PutRolePolicyCommand({
		RoleName: CODEBUILD_ROLE_NAME,
		PolicyName: "smartdeploy-codebuild-permissions",
		PolicyDocument: permissionsPolicy,
	}));

	// IAM is eventually consistent
	await new Promise((r) => setTimeout(r, 10_000));
	send("CodeBuild service role created.", "build");
	return roleArn;
}

// ─── CodeBuild Project ────────────────────────────────────────────────────

export async function ensureCodeBuildProject(
	region: string,
	roleArn: string,
	send: SendFn,
): Promise<string> {
	const cb = new CodeBuildClient(getAwsClientConfig(region));

	try {
		const resp = await cb.send(new BatchGetProjectsCommand({ names: [CODEBUILD_PROJECT_NAME] }));
		if (resp.projects && resp.projects.length > 0 && resp.projects[0].name) {
			return CODEBUILD_PROJECT_NAME;
		}
	} catch { /* project doesn't exist */ }

	send("Creating CodeBuild project...", "build");

	await cb.send(new CreateProjectCommand({
		name: CODEBUILD_PROJECT_NAME,
		source: {
			type: "NO_SOURCE",
			buildspec: "version: 0.2\nphases:\n  build:\n    commands:\n      - echo placeholder",
		},
		artifacts: { type: "NO_ARTIFACTS" },
		environment: {
			type: "LINUX_CONTAINER",
			computeType: "BUILD_GENERAL1_SMALL",
			image: "aws/codebuild/amazonlinux-x86_64-standard:5.0",
			privilegedMode: true,
			environmentVariables: [],
		},
		serviceRole: roleArn,
		logsConfig: {
			cloudWatchLogs: { status: "ENABLED", groupName: LOG_GROUP },
		},
	}));

	send("CodeBuild project created.", "build");
	return CODEBUILD_PROJECT_NAME;
}

// ─── Buildspec Generation ─────────────────────────────────────────────────

function yamlListEntry(line: string, spaces: number): string {
	// Quote commands to avoid YAML parsing issues when the command contains ":" or other special chars.
	const quoted = JSON.stringify(line);
	return " ".repeat(spaces) + "- " + quoted;
}

export function generateBuildspec(params: {
	ecrRegistry: string;
	ecrRepoName: string;
	imageTag: string;
	region: string;
	scanResults?: SDArtifactsResponse;
}): string {
	const { ecrRegistry, ecrRepoName, imageTag, region, scanResults } = params;
	const fullUri = `${ecrRegistry}/${ecrRepoName}:${imageTag}`;
	const services = scanResults?.services || [];
	const dockerfiles = scanResults?.dockerfiles || {};
	const hasCompose = !!scanResults?.docker_compose;

	const preBuildCmds: string[] = [
		"echo Logging in to Amazon ECR...",
		'REGION="${AWS_DEFAULT_REGION:-${AWS_REGION}}"',
		`if [ -z "$REGION" ]; then REGION="${region}"; fi`,
		`aws ecr get-login-password --region "$REGION" | docker login --username AWS --password-stdin ${ecrRegistry}`,
		// When DOCKERHUB_USERNAME + DOCKERHUB_TOKEN are passed as CodeBuild env overrides, authenticate to Docker Hub before docker build (avoids anonymous 429 rate limits).
		'if [ -n "$DOCKERHUB_USERNAME" ] && [ -n "$DOCKERHUB_TOKEN" ]; then echo "Logging in to Docker Hub..."; echo "$DOCKERHUB_TOKEN" | docker login --username "$DOCKERHUB_USERNAME" --password-stdin; fi',
		"echo Cloning source repository...",
		"git clone -b $BRANCH_NAME https://${GITHUB_TOKEN}@github.com/${REPO_FULL_NAME}.git src",
		"cd src",
		'if [ -n "$COMMIT_SHA" ]; then git checkout $COMMIT_SHA; fi',
	];

	// Write Dockerfiles from scan_results
	for (const [relPath, content] of Object.entries(dockerfiles)) {
		const safePath = relPath.replace(/\\/g, "/").replace(/^\.\//, "");
		if (!safePath || safePath.includes("..")) continue;
		const dir = safePath.includes("/") ? safePath.substring(0, safePath.lastIndexOf("/")) : "";
		const b64 = Buffer.from(content, "utf8").toString("base64");
		if (dir) preBuildCmds.push(`mkdir -p "${dir}"`);
		preBuildCmds.push(`echo "${b64}" | base64 -d > "${safePath}"`);
	}

	if (hasCompose) {
		const b64 = Buffer.from(scanResults!.docker_compose, "utf8").toString("base64");
		preBuildCmds.push(`echo "${b64}" | base64 -d > docker-compose.yml`);
	}

	preBuildCmds.push(
		'if [ -n "$APP_ENV_VARS_B64" ]; then echo "$APP_ENV_VARS_B64" | base64 -d > .env; fi',
	);

	let buildCmds: string[];
	let postBuildCmds: string[];

	if (hasCompose && services.length > 1) {
		buildCmds = [
			"echo Building with docker-compose...",
			"docker-compose build",
		];
		postBuildCmds = ["echo Tagging and pushing images to ECR..."];
		for (const svc of services) {
			const svcUri = `${ecrRegistry}/${ecrRepoName}-${svc.name}:${imageTag}`;
			postBuildCmds.push(
				`IMAGE_ID=$(docker-compose images ${svc.name} -q 2>/dev/null | head -1); ` +
					`if [ -z "$IMAGE_ID" ]; then IMAGE_ID=$(docker images -q --filter "reference=*${svc.name}*" | head -1); fi; ` +
					`if [ -n "$IMAGE_ID" ]; then docker tag "$IMAGE_ID" "${svcUri}"; docker push "${svcUri}" || echo "Warning: could not push ${svc.name}"; ` +
					`else echo "Warning: could not find image for ${svc.name}"; fi`,
			);
		}
		postBuildCmds.push(
			`IMAGE_ID=$(docker-compose images ${services[0].name} -q 2>/dev/null | head -1); ` +
				`if [ -z "$IMAGE_ID" ]; then IMAGE_ID=$(docker images -q --filter "reference=*${services[0].name}*" | head -1); fi; ` +
				`if [ -n "$IMAGE_ID" ]; then docker tag "$IMAGE_ID" "${fullUri}"; docker push "${fullUri}"; ` +
				`else echo "Warning: could not find image for ${services[0].name}"; fi`,
		);
	} else {
		const dockerfilePath = services[0]?.dockerfile_path || Object.keys(dockerfiles)[0] || "Dockerfile";
		const buildContext = services[0]?.build_context || ".";
		buildCmds = [
			`echo Building Docker image from ${dockerfilePath}...`,
			`docker build -f ${dockerfilePath} -t ${fullUri} ${buildContext}`,
		];
		postBuildCmds = [
			"echo Pushing image to ECR...",
			`docker push ${fullUri}`,
		];
	}

	const SP = 6;
	const lines = [
		"version: 0.2",
		"phases:",
		"  pre_build:",
		"    commands:",
		...preBuildCmds.map((c) => yamlListEntry(c, SP)),
		"  build:",
		"    commands:",
		...buildCmds.map((c) => yamlListEntry(c, SP)),
		"  post_build:",
		"    commands:",
		...postBuildCmds.map((c) => yamlListEntry(c, SP)),
	];
	return lines.join("\n") + "\n";
}

// ─── Start Build ──────────────────────────────────────────────────────────

export async function startBuild(params: {
	region: string;
	projectName: string;
	repoFullName: string;
	branch: string;
	commitSha?: string;
	githubToken: string;
	buildspec: string;
	envVarsBase64?: string;
	/** Optional: Docker Hub PAT + user so CodeBuild can pull public bases (e.g. node:20-alpine) without anonymous rate limits. */
	dockerHub?: { username: string; token: string };
	send: SendFn;
}): Promise<string> {
	const cb = new CodeBuildClient(getAwsClientConfig(params.region));

	params.send(`Starting CodeBuild for ${params.repoFullName}@${params.branch}...`, "build");

	const envOverrides: { name: string; value: string; type: "PLAINTEXT" }[] = [
		{ name: "GITHUB_TOKEN", value: params.githubToken, type: "PLAINTEXT" },
		{ name: "REPO_FULL_NAME", value: params.repoFullName, type: "PLAINTEXT" },
		{ name: "BRANCH_NAME", value: params.branch, type: "PLAINTEXT" },
		{ name: "COMMIT_SHA", value: params.commitSha || "", type: "PLAINTEXT" },
		{ name: "AWS_DEFAULT_REGION", value: params.region, type: "PLAINTEXT" },
		{ name: "AWS_REGION", value: params.region, type: "PLAINTEXT" },
	];

	if (params.envVarsBase64) {
		envOverrides.push({ name: "APP_ENV_VARS_B64", value: params.envVarsBase64, type: "PLAINTEXT" });
	}

	if (params.dockerHub?.username && params.dockerHub?.token) {
		envOverrides.push(
			{ name: "DOCKERHUB_USERNAME", value: params.dockerHub.username, type: "PLAINTEXT" },
			{ name: "DOCKERHUB_TOKEN", value: params.dockerHub.token, type: "PLAINTEXT" },
		);
	}

	const resp = await cb.send(new StartBuildCommand({
		projectName: params.projectName,
		buildspecOverride: params.buildspec,
		environmentVariablesOverride: envOverrides,
	}));

	const buildId = resp.build!.id!;
	params.send(`Build started: ${buildId}`, "build");
	return buildId;
}

// ─── Stream Build Logs ────────────────────────────────────────────────────

export async function waitForBuildAndStreamLogs(params: {
	buildId: string;
	region: string;
	send: SendFn;
}): Promise<{ success: boolean }> {
	const { buildId, region, send } = params;
	const cb = new CodeBuildClient(getAwsClientConfig(region));
	const cwl = new CloudWatchLogsClient(getAwsClientConfig(region));

	let logGroupName: string | undefined = LOG_GROUP;
	let logStreamName: string | undefined;
	let nextToken: string | undefined;
	let logStreamAvailable = false;
	let sentLogLocation = false;
	const terminalStatuses = new Set(["SUCCEEDED", "FAILED", "FAULT", "STOPPED", "TIMED_OUT"]);

	while (true) {
		await new Promise((r) => setTimeout(r, 500));

		// Stream logs from CloudWatch
		if (!logStreamAvailable && logStreamName && logGroupName) {
			try {
				const resp = await cwl.send(new GetLogEventsCommand({
					logGroupName,
					logStreamName,
					startFromHead: true,
				}));
				logStreamAvailable = true;
				for (const event of resp.events || []) {
					if (event.message?.trim()) send(event.message.trimEnd(), "build");
				}
				nextToken = resp.nextForwardToken;
			} catch {
				// Log stream not ready yet
			}
		} else if (logStreamName && logGroupName) {
			try {
				const resp = await cwl.send(new GetLogEventsCommand({
					logGroupName,
					logStreamName,
					...(nextToken ? { nextToken } : { startFromHead: true }),
				}));
				for (const event of resp.events || []) {
					if (event.message?.trim()) send(event.message.trimEnd(), "build");
				}
				if (resp.nextForwardToken && resp.nextForwardToken !== nextToken) {
					nextToken = resp.nextForwardToken;
				}
			} catch {
				// Transient error, retry next iteration
			}
		}

		// Check build status
		try {
			const buildResp = await cb.send(new BatchGetBuildsCommand({ ids: [buildId] }));
			const build = buildResp.builds?.[0];
			if (!build) continue;

			// Prefer log stream/group from the build response when available
			if (!logStreamName && build.logs?.streamName) logStreamName = build.logs.streamName;
			if (build.logs?.groupName) logGroupName = build.logs.groupName;
			if (!sentLogLocation && (build.logs?.deepLink || build.logs?.groupName || build.logs?.streamName)) {
				const parts: string[] = [];
				if (build.logs?.groupName) parts.push(`group=${build.logs.groupName}`);
				if (build.logs?.streamName) parts.push(`stream=${build.logs.streamName}`);
				if (build.logs?.deepLink) parts.push(`link=${build.logs.deepLink}`);
				send(`CodeBuild logs: ${parts.join(" | ")}`, "build");
				sentLogLocation = true;
			}

			const status = build.buildStatus;
			if (status && terminalStatuses.has(status)) {
				// Drain remaining logs
				if (logStreamAvailable && logStreamName && logGroupName) {
					try {
						const finalResp = await cwl.send(new GetLogEventsCommand({
							logGroupName,
							logStreamName,
							...(nextToken ? { nextToken } : {}),
						}));
						for (const event of finalResp.events || []) {
							if (event.message?.trim()) send(event.message.trimEnd(), "build");
						}
					} catch { /* OK */ }
				}

				const success = status === "SUCCEEDED";
				if (!success) {
					const lastPhase = build.phases?.slice(-1)[0];
					send(`❌ CodeBuild ${status}: ${lastPhase?.phaseStatus || "See logs above"}`, "build");
				} else {
					send("✅ Docker image built and pushed to ECR", "build");
				}
				return { success };
			}
		} catch {
			// Transient error
		}
	}
}

import { DeployConfig, EC2Details } from "../../app/types";
import config from "../../config";
import {
	EC2Client,
	TerminateInstancesCommand,
} from "@aws-sdk/client-ec2";
import {
	ElasticLoadBalancingV2Client,
	DescribeTargetGroupsCommand,
	DescribeLoadBalancersCommand,
	DescribeListenersCommand,
	DescribeRulesCommand,
	DeleteRuleCommand,
	DeleteTargetGroupCommand,
	DeleteLoadBalancerCommand,
} from "@aws-sdk/client-elastic-load-balancing-v2";
import { STSClient, GetCallerIdentityCommand } from "@aws-sdk/client-sts";

function getClientConfig(region: string) {
	const conf: { region: string; credentials?: { accessKeyId: string; secretAccessKey: string } } = { region };
	if (config.AWS_ACCESS_KEY_ID && config.AWS_SECRET_ACCESS_KEY) {
		conf.credentials = {
			accessKeyId: config.AWS_ACCESS_KEY_ID,
			secretAccessKey: config.AWS_SECRET_ACCESS_KEY,
		};
	}
	return conf;
}

function isNotFoundError(err: unknown): boolean {
	const msg = err instanceof Error ? err.message : String(err);
	return (
		msg.includes("does not exist") ||
		msg.includes("NotFound") ||
		msg.includes("No Environment found") ||
		msg.includes("No Application found") ||
		msg.includes("InvalidParameterValue") ||
		msg.includes("ClusterNotFoundException") ||
		msg.includes("InvalidInstanceID")
	);
}



/**
 * Deletes an AWS EC2 instance using stored instanceId.
 * When shared ALB is enabled, also removes target group and listener rules.
 */
export async function deleteEC2Instance(
	deployConfig: DeployConfig
): Promise<void> {
	const region = deployConfig.awsRegion || config.AWS_REGION || "us-west-2";
	const repoName = deployConfig.url.split("/").pop()?.replace(".git", "") || "app";
	const sharedAlbEnabled = !!config.EC2_ACM_CERTIFICATE_ARN && !!config.NEXT_PUBLIC_DEPLOYMENT_DOMAIN;

	const ec2Client = new EC2Client(getClientConfig(region));

	if (sharedAlbEnabled) {
		const elbClient = new ElasticLoadBalancingV2Client(getClientConfig(region));
		const stsClient = new STSClient(getClientConfig(region));
		const targetGroupName = `${repoName}-tg`
			.toLowerCase()
			.replace(/[^a-z0-9-]/g, "-")
			.replace(/-+/g, "-")
			.replace(/^-|-$/g, "")
			.slice(0, 32) || "smartdeploy-tg";

		try {
			const tgResult = await elbClient.send(
				new DescribeTargetGroupsCommand({ Names: [targetGroupName] })
			);
			const targetGroups = tgResult.TargetGroups || [];
			const targetGroupArn = targetGroups[0]?.TargetGroupArn;

			if (targetGroupArn) {
				let albName = "";
				let albArn: string | undefined = undefined;

				try {
					const identity = await stsClient.send(new GetCallerIdentityCommand({}));
					const accountId = identity.Account || "";
					const suffix = accountId ? accountId.slice(-6) : "shared";
					albName = `smartdeploy-${suffix}-alb`.slice(0, 32);

					const albResult = await elbClient.send(
						new DescribeLoadBalancersCommand({ Names: [albName] })
					);
					const loadBalancers = albResult.LoadBalancers || [];
					albArn = loadBalancers[0]?.LoadBalancerArn;

					if (albArn) {
						const listenersResult = await elbClient.send(
							new DescribeListenersCommand({ LoadBalancerArn: albArn })
						);
						const listeners = listenersResult.Listeners || [];

						for (const listener of listeners) {
							const listenerArn = listener.ListenerArn;
							if (!listenerArn) continue;

							const rulesResult = await elbClient.send(
								new DescribeRulesCommand({ ListenerArn: listenerArn })
							);
							const rules = rulesResult.Rules || [];

							for (const rule of rules) {
								const forwardsTarget = (rule.Actions || []).some(
									(action) =>
										action.Type === "forward" &&
										action.TargetGroupArn === targetGroupArn
								);
								if (forwardsTarget && rule.RuleArn) {
									try {
										await elbClient.send(
											new DeleteRuleCommand({ RuleArn: rule.RuleArn })
										);
									} catch {
										// Ignore rule delete errors
									}
								}
							}
						}
					}
				} catch {
					// Ignore listener/rule cleanup errors
				}

				try {
					await elbClient.send(
						new DeleteTargetGroupCommand({ TargetGroupArn: targetGroupArn })
					);

					// Check if there are any other target groups connected to the ALB
					if (albArn) {
						const remainingListeners = await elbClient.send(
							new DescribeListenersCommand({ LoadBalancerArn: albArn })
						);
						let hasOtherRoutes = false;
						for (const listener of remainingListeners.Listeners || []) {
							if (!listener.ListenerArn) continue;
							const rulesResult = await elbClient.send(
								new DescribeRulesCommand({ ListenerArn: listener.ListenerArn })
							);
							const rules: any[] = (rulesResult as any).Rules || [];
							// If any rule forwards to a different target group, there are still active apps
							hasOtherRoutes = hasOtherRoutes || rules.some((r: any) =>
								(r.Actions || []).some((a: any) => a.Type === "forward" && a.TargetGroupArn !== targetGroupArn)
							);
						}

						// Also ensure we check other target groups that might be attached to this ALB
						if (!hasOtherRoutes) {
							console.log(`No other routes on ALB ${albName}. Deleting ALB...`);
							await elbClient.send(
								new DeleteLoadBalancerCommand({ LoadBalancerArn: albArn })
							);
						}
					}
				} catch (err) {
					console.error("Error during target group/ALB cleanup", err);
				}
			}
		} catch {
			// Ignore missing or in-use target groups
		}
	}

	const instanceId = ((deployConfig.ec2 || {}) as EC2Details)?.instanceId;
	if (instanceId) {
		try {
			await ec2Client.send(
				new TerminateInstancesCommand({ InstanceIds: [instanceId] })
			);
		} catch (err) {
			if (!isNotFoundError(err)) throw err;
		}
	} else {
		console.warn("deleteEC2Instance: no instanceId found in deployConfig.ec2 — nothing to delete");
	}

	// Note: Security Groups, Key Pairs, and other resources are not automatically deleted
}

/**
 * Main function to delete AWS deployment based on deploymentTarget.
 * Uses stored service details (ec2) from DeployConfig
 * to identify the exact resources to delete.
 */
export async function deleteAWSDeployment(
	deployConfig: DeployConfig,
	deploymentTarget: string
): Promise<void> {
	if (deploymentTarget === "ec2") {
		await deleteEC2Instance(deployConfig);
	} else {
		throw new Error(`Unsupported AWS deployment target: ${deploymentTarget}`);
	}
}

import config from "../../config";
import { EC2Client, GetConsoleOutputCommand } from "@aws-sdk/client-ec2";
import {
	SSMClient,
	SendCommandCommand,
	GetCommandInvocationCommand,
} from "@aws-sdk/client-ssm";

type LogEntry = { timestamp?: string; message?: string };

type StreamParams = {
	instanceId: string;
	region: string;
	serviceName?: string;
	ws: any;
};

function getClientConfig(region: string) {
	const clientConfig: {
		region: string;
		credentials?: { accessKeyId: string; secretAccessKey: string };
	} = { region };

	if (config.AWS_ACCESS_KEY_ID && config.AWS_SECRET_ACCESS_KEY) {
		clientConfig.credentials = {
			accessKeyId: config.AWS_ACCESS_KEY_ID,
			secretAccessKey: config.AWS_SECRET_ACCESS_KEY,
		};
	}

	return clientConfig;
}

function sanitizeConsoleOutput(raw: string): string {
	return raw
		.replace(/\x1b\[[0-9;]*[a-zA-Z]/g, "")
		.replace(/\x1b\][^\x07]*\x07/g, "")
		.replace(/\x1b[()][AB012]/g, "")
		.replace(/\x1b[^[\]()a-zA-Z]?[a-zA-Z]/g, "")
		.replace(/[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]/g, "")
		.replace(/[\u2190-\u21FF]/g, "")
		.replace(/[\u2600-\u26FF]/g, "")
		.replace(/[\u2700-\u27BF]/g, "")
		.replace(/\r\n/g, "\n")
		.replace(/\r/g, "\n")
		.replace(/\n{3,}/g, "\n\n");
}

function parseLogLines(raw: string): LogEntry[] {
	const lines = sanitizeConsoleOutput(raw)
		.split("\n")
		.map((line) => line.trim())
		.filter(Boolean);

	const parsed: LogEntry[] = [];
	for (const line of lines) {
		const withoutComposePrefix = line.includes("|") ? line.split("|").slice(1).join("|").trim() : line;
		const m = withoutComposePrefix.match(/^(\d{4}-\d{2}-\d{2}T[^\s]+)\s+(.*)$/);
		if (m) {
			parsed.push({ timestamp: m[1], message: m[2] });
		} else {
			parsed.push({ timestamp: new Date().toISOString(), message: line });
		}
	}

	return parsed;
}

async function runSsmShell(instanceId: string, region: string, shellCommand: string): Promise<string> {
	const client = new SSMClient(getClientConfig(region));
	const sendRes = await client.send(
		new SendCommandCommand({
			InstanceIds: [instanceId],
			DocumentName: "AWS-RunShellScript",
			Parameters: { commands: [shellCommand] },
		})
	);

	const commandId = sendRes.Command?.CommandId;
	if (!commandId) throw new Error("SSM did not return command id");

	const deadline = Date.now() + 60_000;
	const terminalStates = new Set(["Success", "Failed", "Cancelled", "TimedOut"]);

	while (Date.now() < deadline) {
		await new Promise((r) => setTimeout(r, 1500));
		const invocation = await client.send(
			new GetCommandInvocationCommand({ CommandId: commandId, InstanceId: instanceId })
		);
		const status = invocation.Status;
		if (status && terminalStates.has(status)) {
			const stdout = invocation.StandardOutputContent ?? "";
			const stderr = invocation.StandardErrorContent ?? "";
			if (status !== "Success" && stderr) {
				throw new Error(stderr.trim());
			}
			return stdout + (stderr ? `\n${stderr}` : "");
		}
	}

	throw new Error("Timed out waiting for SSM command output");
}

async function getConsoleOutput(instanceId: string, region: string): Promise<string> {
	const client = new EC2Client(getClientConfig(region));
	const response = await client.send(new GetConsoleOutputCommand({ InstanceId: instanceId, Latest: true }));
	const output = response.Output;
	if (!output) return "";
	return Buffer.from(output, "base64").toString("utf8");
}

function buildDockerLogsCommand(serviceName?: string, sinceIso?: string, tail: number = 150): string {
	const serviceArg = serviceName?.trim() ? ` ${serviceName.trim()}` : "";
	const sinceArg = sinceIso?.trim() ? ` --since '${sinceIso.trim()}'` : "";

	return [
		"set -e",
		"COMPOSE_DIR=$(dirname $(find /home/ec2-user/app -name 'docker-compose.yml' | head -1))",
		"if [ -z \"$COMPOSE_DIR\" ]; then COMPOSE_DIR=\"/home/ec2-user/app\"; fi",
		"cd \"$COMPOSE_DIR\"",
		`docker compose logs --no-color --timestamps --tail ${tail}${sinceArg}${serviceArg} 2>/dev/null || true`,
		`docker-compose logs --no-color --timestamps --tail ${tail}${sinceArg}${serviceArg} 2>/dev/null || true`,
	].join("; ");
}

export async function getInitialEc2ServiceLogs(params: {
	instanceId: string;
	region: string;
	serviceName?: string;
	limit?: number;
}): Promise<LogEntry[]> {
	const { instanceId, region, serviceName, limit = 200 } = params;
	try {
		const raw = await runSsmShell(instanceId, region, buildDockerLogsCommand(serviceName, undefined, limit));
		const logs = parseLogLines(raw);
		if (logs.length > 0) return logs;
	} catch {
		// Fall back to console output if SSM/docker logs are unavailable
	}

	const consoleOut = await getConsoleOutput(instanceId, region);
	return parseLogLines(consoleOut).slice(-Math.max(1, limit));
}

export function streamEc2ServiceLogs(params: StreamParams): () => void {
	const { instanceId, region, serviceName, ws } = params;
	let stopped = false;
	let isPolling = false;
	let sinceIso = new Date(Date.now() - 60_000).toISOString();
	const sentKeys = new Set<string>();

	const sendStreamLog = (entry: LogEntry) => {
		if (!entry.message?.trim()) return;
		const key = `${entry.timestamp || ""}|${entry.message}`;
		if (sentKeys.has(key)) return;
		sentKeys.add(key);
		if (sentKeys.size > 5000) {
			const first = sentKeys.values().next().value;
			if (first) sentKeys.delete(first);
		}

		if (ws?.readyState === ws?.OPEN) {
			ws.send(
				JSON.stringify({
					type: "stream_logs",
					payload: {
						log: {
							timestamp: entry.timestamp || new Date().toISOString(),
							message: entry.message,
						},
					},
				})
			);
		}

		if (entry.timestamp && !Number.isNaN(new Date(entry.timestamp).getTime())) {
			sinceIso = entry.timestamp;
		}
	};

	const poll = async () => {
		if (stopped || isPolling) return;
		isPolling = true;
		try {
			const raw = await runSsmShell(instanceId, region, buildDockerLogsCommand(serviceName, sinceIso, 100));
			const entries = parseLogLines(raw);
			for (const e of entries) sendStreamLog(e);
		} catch {
			try {
				const fallback = await getConsoleOutput(instanceId, region);
				const entries = parseLogLines(fallback).slice(-20);
				for (const e of entries) sendStreamLog(e);
			} catch {
				// Ignore poll errors and retry on next interval
			}
		} finally {
			isPolling = false;
		}
	};

	const interval = setInterval(poll, 5000);
	poll().catch(() => undefined);

	const stop = () => {
		stopped = true;
		clearInterval(interval);
	};

	ws.on("close", stop);
	return stop;
}

import fs from "fs";
import os from "os";
import path from "path";
import config from "../../config";
import { createWebSocketLogger } from "../websocketLogger";
import { runAWSCommand } from "./awsHelpers";
import {
	SSMClient,
	SendCommandCommand,
	GetCommandInvocationCommand,
} from "@aws-sdk/client-ssm";
import { EC2Client, DescribeInstancesCommand } from "@aws-sdk/client-ec2";
import { githubAuthenticatedCloneUrl } from "../githubGitAuth";
import { canonicalDockerfileDeployPath, inferSingleDockerfileBuild } from "../dockerfileDeployPath";

const SSM_ROLE_NAME = "smartdeploy-ec2-ssm-role";
export const SSM_PROFILE_NAME = "smartdeploy-ec2-ssm-profile";
const SSM_MANAGED_POLICY_ARN =
	"arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore";

function getClientConfig(region: string) {
	const conf: {
		region: string;
		credentials?: { accessKeyId: string; secretAccessKey: string };
	} = { region };
	if (config.AWS_ACCESS_KEY_ID && config.AWS_SECRET_ACCESS_KEY) {
		conf.credentials = {
			accessKeyId: config.AWS_ACCESS_KEY_ID,
			secretAccessKey: config.AWS_SECRET_ACCESS_KEY,
		};
	}
	return conf;
}

/**
 * Ensures an IAM role and instance profile exist for EC2 instances to be managed by SSM.
 * Returns the instance profile name to pass to run-instances.
 */
export async function ensureSSMInstanceProfile(
	region: string,
	ws: any
): Promise<string> {
	const send = createWebSocketLogger(ws);

	try {
		await runAWSCommand(
			[
				"iam",
				"get-instance-profile",
				"--instance-profile-name",
				SSM_PROFILE_NAME,
			],
			ws,
			"setup"
		);
		send(`SSM instance profile ${SSM_PROFILE_NAME} already exists`, "setup");
		return SSM_PROFILE_NAME;
	} catch {
		// Profile does not exist; create role and profile
	}

	send(`Creating IAM role and instance profile for SSM...`, "setup");

	const trustPolicy = JSON.stringify({
		Version: "2012-10-17",
		Statement: [
			{
				Effect: "Allow",
				Principal: { Service: "ec2.amazonaws.com" },
				Action: "sts:AssumeRole",
			},
		],
	});

	// Write policy to temp file to avoid Windows PowerShell JSON escaping issues
	const policyFile = path.join(os.tmpdir(), `iam-trust-policy-${Date.now()}.json`);
	const policyFileUri = "file://" + path.resolve(policyFile).replace(/\\/g, "/");

	try {
		fs.writeFileSync(policyFile, trustPolicy, "utf8");
		await runAWSCommand(
			[
				"iam",
				"create-role",
				"--role-name",
				SSM_ROLE_NAME,
				"--assume-role-policy-document",
				policyFileUri,
			],
			ws,
			"setup"
		);
	} finally {
		try {
			fs.unlinkSync(policyFile);
		} catch {
			// ignore cleanup errors
		}
	}

	await runAWSCommand(
		[
			"iam",
			"attach-role-policy",
			"--role-name",
			SSM_ROLE_NAME,
			"--policy-arn",
			SSM_MANAGED_POLICY_ARN,
		],
		ws,
		"setup"
	);

	await runAWSCommand(
		["iam", "create-instance-profile", "--instance-profile-name", SSM_PROFILE_NAME],
		ws,
		"setup"
	);

	await runAWSCommand(
		[
			"iam",
			"add-role-to-instance-profile",
			"--instance-profile-name",
			SSM_PROFILE_NAME,
			"--role-name",
			SSM_ROLE_NAME,
		],
		ws,
		"setup"
	);

	// IAM is eventually consistent; brief wait before using the profile
	await new Promise((r) => setTimeout(r, 5000));
	send(`SSM instance profile ${SSM_PROFILE_NAME} created`, "setup");
	return SSM_PROFILE_NAME;
}

/**
 * Returns the current EC2 instance state (e.g. "running", "stopped") or undefined if not found.
 * Uses the AWS SDK instead of CLI text output so we never mis-read AWS CLI's literal "None"
 * (printed when JMESPath returns null for empty Reservations).
 */
export async function getInstanceState(
	instanceId: string,
	region: string,
	_ws: unknown
): Promise<string | undefined> {
	const client = new EC2Client(getClientConfig(region));
	try {
		const resp = await client.send(
			new DescribeInstancesCommand({ InstanceIds: [instanceId] })
		);
		for (const reservation of resp.Reservations ?? []) {
			for (const inst of reservation.Instances ?? []) {
				if (inst.InstanceId === instanceId) {
					const name = inst.State?.Name;
					if (name) return name;
				}
			}
		}
	} catch (e: unknown) {
		const err = e as { name?: string; Code?: string };
		const code = err.name || err.Code;
		if (
			code === "InvalidInstanceID.NotFound" ||
			code === "InvalidInstanceID.Malformed" ||
			(typeof e === "object" &&
				e !== null &&
				String((e as Error).message || "").includes("InvalidInstanceID"))
		) {
			return undefined;
		}
		throw e;
	}
	return undefined;
}

/** Reject path traversal in Dockerfile keys from scan_results. */
function isSafeDockerfileRelPath(p: string): boolean {
	if (!p || p.includes("..")) return false;
	if (path.isAbsolute(p)) return false;
	return true;
}

/**
 * Align docker-compose `dockerfile:` values with canonicalDockerfileDeployPath so validation and builds match written files.
 */
function normalizeDockerfilePathsInCompose(compose: string): string {
	return compose.replace(/^([ \t]*dockerfile:\s*)([^\n]*)$/gim, (full, prefix: string, rhs: string) => {
		const hashIdx = rhs.indexOf("#");
		const valuePart = hashIdx >= 0 ? rhs.slice(0, hashIdx) : rhs;
		const comment = hashIdx >= 0 ? rhs.slice(hashIdx) : "";
		const trimmedRhs = valuePart.trimEnd();
		if (!trimmedRhs) return full;
		const qDouble = trimmedRhs.startsWith('"') && trimmedRhs.endsWith('"');
		const qSingle = trimmedRhs.startsWith("'") && trimmedRhs.endsWith("'");
		const inner = (qDouble || qSingle ? trimmedRhs.slice(1, -1) : trimmedRhs).trim();
		if (inner.includes("..")) return full;
		if (path.isAbsolute(inner)) return full;
		const normalized = canonicalDockerfileDeployPath(inner.replace(/^\.\//, ""));
		if (normalized === inner) return full;
		if (qDouble) return `${prefix}"${normalized}"${comment}`;
		if (qSingle) return `${prefix}'${normalized}'${comment}`;
		return `${prefix}${normalized}${comment}`;
	});
}

/**
 * Ensures every service in a compose YAML has `env_file` referencing `.env`,
 * so that env vars written to the repo root are available inside containers.
 */
/**
 * Generates bash commands to write Dockerfiles from scan_results.dockerfiles
 * into the cloned repo at the paths given by each key (e.g. client/Dockerfile, apps/web/Dockerfile).
 * Keys that name a directory only (e.g. "client") are written to client/Dockerfile.
 */
function buildDockerfileWriteScript(dockerfiles: Record<string, string>): string {
	const entries = Object.entries(dockerfiles || {})
		.map(([filePath, content]) => {
			const raw = filePath.replace(/^\.\//, "").replace(/\\/g, "/");
			const safePath = canonicalDockerfileDeployPath(raw);
			return [safePath, content] as [string, string];
		})
		.filter(([safePath]) => isSafeDockerfileRelPath(safePath));

	if (entries.length === 0) return "";

	return entries
		.map(([safePath, content]) => {
			const lastSlash = safePath.lastIndexOf("/");
			const dir = lastSlash >= 0 ? safePath.slice(0, lastSlash) : "";
			const mkdirLine =
				dir.length > 0
					? `mkdir -p "${dir.replace(/"/g, '\\"')}"\n`
					: "";
			return `
echo "Writing Dockerfile from scan_results to ${safePath}..."
${mkdirLine}cat > "${safePath.replace(/"/g, '\\"')}" << 'DOCKERFILEEOF'
${content}
DOCKERFILEEOF
`;
		})
		.join("\n");
}

/**
 * Generates bash commands to write docker-compose.yml from scan_results.docker_compose
 * into the cloned repo.
 */
function buildComposeWriteScript(dockerCompose: string): string {
	if (!dockerCompose) return "";
	const normalizedCompose = normalizeDockerfilePathsInCompose(dockerCompose);
	return `
echo "Writing docker-compose.yml from scan_results..."
cat > docker-compose.yml << 'COMPOSEEOF'
${normalizedCompose}
COMPOSEEOF
`;
}

function bashSingleQuoted(s: string): string {
	return "'" + s.replace(/'/g, "'\\''") + "'";
}

/**
 * Generates bash commands to build and run Docker containers.
 * Uses docker-compose if a compose file exists; otherwise falls back to
 * single-service docker build + docker run.
 */
function buildDockerRunScript(
	mainPort: string,
	singleDocker?: { dockerfile: string; context: string } | null,
): string {
	const singleBuildLines =
		singleDocker != null
			? `
    echo "No docker-compose found. Building single-service image from ${singleDocker.dockerfile} (context: ${singleDocker.context})..."
    if [ ! -f ${bashSingleQuoted(singleDocker.dockerfile)} ]; then
        echo "ERROR: Dockerfile not found at ${singleDocker.dockerfile}"
        echo "Repo root: $(pwd)"
        ls -la
        exit 1
    fi
    docker build -f ${bashSingleQuoted(singleDocker.dockerfile)} -t smartdeploy-app ${bashSingleQuoted(singleDocker.context)}
`
			: `
    echo "No docker-compose found. Building single-service Docker image..."
    if [ ! -f Dockerfile ]; then
        echo "ERROR: No Dockerfile found in repository root."
        exit 1
    fi
    docker build -t smartdeploy-app .
`;

	return `
if [ -f docker-compose.yml ] || [ -f docker-compose.yaml ] || [ -f compose.yml ] || [ -f compose.yaml ]; then
    echo "Building and starting containers with docker-compose..."
    COMPOSE_FILE=""
    if [ -f docker-compose.yml ]; then COMPOSE_FILE="docker-compose.yml"; fi
    if [ -z "$COMPOSE_FILE" ] && [ -f docker-compose.yaml ]; then COMPOSE_FILE="docker-compose.yaml"; fi
    if [ -z "$COMPOSE_FILE" ] && [ -f compose.yml ]; then COMPOSE_FILE="compose.yml"; fi
    if [ -z "$COMPOSE_FILE" ] && [ -f compose.yaml ]; then COMPOSE_FILE="compose.yaml"; fi

    echo "Using compose file: $COMPOSE_FILE"

    echo "Validating dockerfile paths referenced by compose..."
    DOCKERFILES=$(awk '/^[[:space:]]*dockerfile:[[:space:]]*/{print $2}' "$COMPOSE_FILE" | tr -d '\r' | sort -u)
    if [ -n "$DOCKERFILES" ]; then
        for df in $DOCKERFILES; do
            if [ ! -f "$df" ]; then
                echo "ERROR: dockerfile path referenced by compose does not exist: $df"
                echo "Repo root: $(pwd)"
                echo "Top-level listing:"
                ls -la
                echo "apps/ listing (if exists):"
                ls -la apps 2>/dev/null || true
                exit 1
            fi
        done
    else
        echo "No explicit dockerfile: entries found in compose."
    fi
    docker-compose up -d --build
else
${singleBuildLines}
    docker rm -f smartdeploy-app 2>/dev/null || true
    docker run -d --name smartdeploy-app --env-file .env -p ${mainPort || "8080"}:${mainPort || "8080"} --restart unless-stopped smartdeploy-app
fi

docker system prune -af --volumes 2>/dev/null || true
`;
}

/**
 * Builds the bash script for the FIRST deploy of containers via SSM.
 * Called after user-data has finished (packages installed, repo cloned, SSM ready).
 * Writes Dockerfiles + docker-compose.yml from scan_results if missing, then builds/runs.
 */
type ScanServiceForDocker = { dockerfile_path?: string; build_context?: string };

export function buildFirstDeployScript(params: {
	envFileContentBase64: string;
	dockerCompose: string;
	dockerfiles: Record<string, string>;
	mainPort: string;
	scanServices?: ScanServiceForDocker[] | null;
}): string {
	const { envFileContentBase64, dockerCompose, dockerfiles, mainPort, scanServices } = params;

	const dockerfileScript = buildDockerfileWriteScript(dockerfiles);
	const composeScript = buildComposeWriteScript(dockerCompose);
	const singleDocker = inferSingleDockerfileBuild(dockerfiles, scanServices);
	const runScript = buildDockerRunScript(mainPort, singleDocker);

	return `set -e
echo "=== SSM first deploy: writing artifacts and building ==="

cd /home/ec2-user/app

${envFileContentBase64 ? `echo '${envFileContentBase64}' | base64 -d > .env` : ""}

${dockerfileScript}

${composeScript}

${runScript}

echo "====================================== Deployment script complete! ======================================"
`;
}

/**
 * Builds the bash script run on the instance for redeploy (git pull + rebuild).
 * Uses scan_results to write Dockerfiles and docker-compose.yml if missing.
 */
export function buildRedeployScript(params: {
	repoUrl: string;
	branch: string;
	token: string;
	commitSha?: string;
	envFileContentBase64: string;
	dockerCompose: string;
	dockerfiles: Record<string, string>;
	mainPort: string;
	scanServices?: ScanServiceForDocker[] | null;
}): string {
	const {
		repoUrl,
		branch,
		token,
		commitSha,
		envFileContentBase64,
		dockerCompose,
		dockerfiles,
		mainPort,
		scanServices,
	} = params;
	const authenticatedUrl = githubAuthenticatedCloneUrl(repoUrl, token);

	const dockerfileScript = buildDockerfileWriteScript(dockerfiles);
	const composeScript = buildComposeWriteScript(dockerCompose);
	const singleDocker = inferSingleDockerfileBuild(dockerfiles, scanServices);
	const runScript = buildDockerRunScript(mainPort, singleDocker);

	return `set -e
echo "=== Disk space before redeploy ==="
df -h /

cd /home/ec2-user/app

docker-compose down 2>/dev/null || docker rm -f smartdeploy-app 2>/dev/null || true
docker system prune -af --volumes 2>/dev/null || true
git gc --aggressive --prune=now 2>/dev/null || true

git remote set-url origin '${authenticatedUrl}'
git fetch origin
git checkout ${branch}
git reset --hard origin/${branch}
${commitSha ? `git checkout ${commitSha}` : ""}
git gc --aggressive --prune=now 2>/dev/null || true

${envFileContentBase64 ? `echo '${envFileContentBase64}' | base64 -d > .env` : ""}

${dockerfileScript}

${composeScript}

${runScript}

echo "====================================== Redeploy complete! ======================================"
`;
}

/**
 * Returns true if the instance is registered with SSM (agent reporting).
 */
export async function isInstanceSsmManaged(
	instanceId: string,
	region: string,
	ws: any
): Promise<boolean> {
	try {
		const out = await runAWSCommand(
			[
				"ssm",
				"describe-instance-information",
				"--filters",
				`Key=InstanceIds,Values=${instanceId}`,
				"--query",
				"InstanceInformationList[0].InstanceId",
				"--output",
				"text",
				"--region",
				region,
			],
			ws,
			"deploy"
		);
		return (out || "").trim() === instanceId;
	} catch {
		return false;
	}
}

const SSM_REGISTRATION_TIMEOUT_MS = 3 * 60 * 1000;
const SSM_REGISTRATION_POLL_MS = 15 * 1000;

/**
 * Gathers network diagnostics for SSM registration failures (public IP, subnet, route to internet).
 */
async function getSsmRegistrationDiagnostics(
	instanceId: string,
	region: string,
	ws: any
): Promise<string> {
	try {
		const instRaw = await runAWSCommand(
			[
				"ec2",
				"describe-instances",
				"--instance-ids",
				instanceId,
				"--query",
				"Reservations[0].Instances[0].{PublicIp:PublicIpAddress,SubnetId:SubnetId,VpcId:VpcId,State:State.Name}",
				"--output",
				"json",
				"--region",
				region,
			],
			ws,
			"deploy"
		);
		const inst = JSON.parse(instRaw.trim()) as { PublicIp: string | null; SubnetId: string | null; VpcId: string | null; State: string };
		const publicIp = inst?.PublicIp ?? "none";
		const subnetId = inst?.SubnetId ?? "";
		const vpcId = inst?.VpcId ?? "";
		if (!subnetId) return ` Instance: ${publicIp}; subnet unknown.`;

		// Get route table for this subnet (explicit association or VPC main)
		const routesRaw = await runAWSCommand(
			[
				"ec2",
				"describe-route-tables",
				"--filters",
				`Name=association.subnet-id,Values=${subnetId}`,
				"--query",
				"RouteTables[*].Routes[?DestinationCidrBlock=='0.0.0.0/0'].[GatewayId,NatGatewayId]",
				"--output",
				"json",
				"--region",
				region,
			],
			ws,
			"deploy"
		);
		const parsed = JSON.parse(routesRaw.trim());
		const routesArray = Array.isArray(parsed) ? parsed : [parsed];
		let flat = routesArray.flat(2).filter(Boolean) as string[];
		if (flat.length === 0 && vpcId) {
			const rtMain = await runAWSCommand(
				[
					"ec2",
					"describe-route-tables",
					"--filters",
					`Name=vpc-id,Values=${vpcId}`,
					"Name=association.main,Values=true",
					"--query",
					"RouteTables[*].Routes[?DestinationCidrBlock=='0.0.0.0/0'].[GatewayId,NatGatewayId]",
					"--output",
					"json",
					"--region",
					region,
				],
				ws,
				"deploy"
			);
			const mainParsed = JSON.parse(rtMain.trim());
			flat = (Array.isArray(mainParsed) ? mainParsed : [mainParsed]).flat(2).filter(Boolean) as string[];
		}
		const hasIgw = flat.some((id) => id?.startsWith("igw-"));
		const hasNat = flat.some((id) => id?.startsWith("nat-"));
		const hasOutbound = hasIgw || hasNat;

		if (publicIp === "none" && !hasOutbound) {
			return ` Instance has no public IP and subnet has no 0.0.0.0/0 route to IGW/NAT — add a NAT Gateway or create VPC endpoints for SSM (ssm, ec2messages, ssmmessages) in this VPC.`;
		}
		if (publicIp === "none" && hasOutbound) {
			return ` Instance has no public IP (private subnet). Subnet has default route (NAT/IGW). If using private subnet, create VPC endpoints for SSM (ssm, ec2messages, ssmmessages) so the instance can reach SSM without internet.`;
		}
		if (hasOutbound) {
			return ` Instance has public IP ${publicIp} and subnet has internet route. SSM agent may not be running — reboot the instance in EC2 console (Instance state → Reboot), wait 2–3 min, then redeploy.`;
		}
		return ` Instance has public IP ${publicIp} but subnet has no 0.0.0.0/0 route — check subnet route table and add IGW or NAT.`;
	} catch {
		return "";
	}
}

/**
 * Ensures the instance is registered with SSM. If it is not (e.g. "Unidentified" in console),
 * attaches the SmartDeploy SSM instance profile and waits for the agent to register.
 */
export async function ensureInstanceSsmReady(
	instanceId: string,
	region: string,
	ws: any,
	send: (msg: string, stepId: string) => void
): Promise<void> {
	if (await isInstanceSsmManaged(instanceId, region, ws)) {
		send("Instance is registered with SSM.", "deploy");
		return;
	}


	// Get current IAM instance profile (ARN or "None")
	const currentProfileOut = await runAWSCommand(
		[
			"ec2",
			"describe-instances",
			"--instance-ids",
			instanceId,
			"--query",
			"Reservations[0].Instances[0].IamInstanceProfile.Arn",
			"--output",
			"text",
			"--region",
			region,
		],
		ws,
		"deploy"
	);
	const currentArn = (currentProfileOut || "").trim();
	const hasOurProfile = currentArn !== "None" && currentArn !== "" && currentArn.includes(SSM_PROFILE_NAME);

	if (!hasOurProfile) {
		send("Instance is not SSM-managed. Attaching SSM instance profile...", "deploy");
		await runAWSCommand(
			[
				"ec2",
				"modify-instance-attribute",
				"--instance-id",
				instanceId,
				"--iam-instance-profile",
				`Name=${SSM_PROFILE_NAME}`,
				"--region",
				region,
			],
			ws,
			"deploy"
		);
		send("SSM profile attached. Waiting for agent to register (up to 3 min)...", "deploy");
	} else {
		send("Instance has SSM profile but not yet registered. Waiting for agent (up to 3 min)...", "deploy");
	}

	const deadline = Date.now() + SSM_REGISTRATION_TIMEOUT_MS;
	while (Date.now() < deadline) {
		await new Promise((r) => setTimeout(r, SSM_REGISTRATION_POLL_MS));
		if (await isInstanceSsmManaged(instanceId, region, ws)) {
			send("Instance is now registered with SSM.", "deploy");
			return;
		}
		send("Still waiting for SSM agent to register...", "deploy");
	}

	// If instance has our profile but still not registered, try one reboot (helps when profile was attached after launch)
	if (hasOurProfile) {
		send("Trying one reboot to let SSM agent pick up the instance profile...", "deploy");
		try {
			await runAWSCommand(
				["ec2", "reboot-instances", "--instance-ids", instanceId, "--region", region],
				ws,
				"deploy"
			);
			await new Promise((r) => setTimeout(r, 60_000)); // wait for reboot
			const rebootDeadline = Date.now() + SSM_REGISTRATION_TIMEOUT_MS;
			while (Date.now() < rebootDeadline) {
				await new Promise((r) => setTimeout(r, SSM_REGISTRATION_POLL_MS));
				if (await isInstanceSsmManaged(instanceId, region, ws)) {
					send("Instance is now registered with SSM after reboot.", "deploy");
					return;
				}
				send("Still waiting for SSM agent after reboot...", "deploy");
			}
		} catch {
			// ignore reboot errors, fall through to final error
		}
	}

	const diagnostics = await getSsmRegistrationDiagnostics(instanceId, region, ws);
	if (diagnostics) send("SSM diagnostic:" + diagnostics, "deploy");
	throw new Error(
		"Instance did not register with SSM. Common causes: (1) Instance has no outbound internet (e.g. private subnet without NAT). Add a NAT Gateway or create VPC endpoints for SSM (ssm, ec2messages, ssmmessages). (2) SSM agent not running — in EC2 console, reboot the instance and redeploy. (3) Wrong account/region. Fix network or reboot the instance in EC2 console, then redeploy." +
		(diagnostics ? diagnostics : "")
	);
}

