/**
 * Save deployment to database and record history
 * Called after deployment completes (success or failure)
 */
async function saveDeploymentToDB(
	deployConfig: DeployConfig,
	deployUrl: string | undefined,
	success: boolean,
	steps: DeployStep[],
	userID: string | undefined,
	serviceDetails: ServiceDeployDetails | null | undefined,
	customUrl?: string | null,
	durationMs?: number
): Promise<void> {
	if (!userID) {
		console.warn("No userID provided - skipping database save");
		return;
	}

	try {
		// Prepare minimal deployment config for DB
		const minimalDeployment: DeployConfig = {
			...deployConfig,
			status: success ? "running" : "failed",
			...(deployUrl && { liveUrl: deployUrl }),
			...(customUrl && { liveUrl: customUrl }),
			...(serviceDetails?.ec2 && { ec2: serviceDetails.ec2 }),
		};

		// Update deployment document (creates if doesn't exist)
		const updateResponse = await dbHelper.updateDeployments(minimalDeployment, userID);
		if (updateResponse.error) {
			console.error("Failed to update deployment:", updateResponse.error);
		} else {
			console.log("Deployment saved to DB:", updateResponse.success);

			// Kick off screenshot generation in the background so deploy completion isn't delayed.
			if (success) {
				const screenshotTargetUrl = (customUrl ?? deployUrl) || "";
				if (screenshotTargetUrl.trim()) {
					void (async () => {
						try {
							const screenshotPublicUrl = await captureDeploymentScreenshotAndUpload({
								url: screenshotTargetUrl,
								ownerID: userID!,
								repoName: deployConfig.repoName,
								serviceName: deployConfig.serviceName,
							});
							
							// Update deployment with screenshot URL
							await dbHelper.updateDeployments(
								{
									...minimalDeployment,
									screenshotUrl: screenshotPublicUrl,
								},
								userID
							);
						} catch (err) {
							console.error("Screenshot generation failed:", err);
						}
					})();
				}
			}
		}

		// Record deployment history using repo_name + service_name
		const historyEntry = {
			timestamp: new Date().toISOString(),
			success,
			steps,
			configSnapshot: configSnapshotFromDeployConfig(deployConfig),
			...(deployConfig.commitSha && { commitSha: deployConfig.commitSha }),
			...(deployConfig.branch && { branch: deployConfig.branch }),
			...(durationMs && { durationMs }),
		};

		const historyResponse = await dbHelper.addDeploymentHistory(
			deployConfig.repoName,
			deployConfig.serviceName,
			userID,
			historyEntry
		);

		if (historyResponse.error) {
			console.error("Failed to record deployment history:", historyResponse.error);
		} else {
			console.log("Deployment history recorded:", historyResponse.id);
		}
	} catch (error) {
		console.error("Error saving deployment to DB:", error);
	}
}

/** Per-service details to persist after deploy */
type ServiceDeployDetails = {
	ec2?: EC2Details;
};

async function sendDeployComplete(
	ws: any,
	deployUrl: string | undefined = "",
	success: boolean,
	deployConfig: DeployConfig,
	deploySteps: DeployStep[],
	userID: string | undefined,
	deploymentTarget?: string,
	vercelDns?: AddVercelDnsResult | null,
	serviceDetails?: ServiceDeployDetails | null,
	durationMs?: number
) {
	// Persist before notifying the client so refetches and retries see instanceId (e.g. failed EC2 deploy).
	console.log("Saving deployment result to database...");
	try {
		await saveDeploymentToDB(
			deployConfig,
			deployUrl,
			success,
			deploySteps,
			userID,
			serviceDetails,
			vercelDns?.success ? vercelDns.customUrl : null,
			durationMs
		);
	} catch (err) {
		console.error("Failed to save deployment to DB:", err);
	}

	if (ws?.readyState === ws?.OPEN) {
		const payload: {
			deployUrl: string | null;
			success: boolean;
			deploymentTarget: string | null;
			vercelDnsAdded?: boolean;
			vercelDnsError?: string | null;
			customUrl?: string | null;
			ec2?: EC2Details;
		} = {
			deployUrl: deployUrl ?? null,
			success,
			deploymentTarget: deploymentTarget ?? null,
		};
		if (serviceDetails?.ec2) payload.ec2 = serviceDetails.ec2;
		if (vercelDns) {
			payload.vercelDnsAdded = vercelDns.success;
			if (vercelDns.success) {
				payload.customUrl = vercelDns.customUrl ?? null;
			} else {
				payload.vercelDnsError = vercelDns.error ?? null;
			}
		}
		ws.send(JSON.stringify({ type: "deploy_complete", payload }));
	}
}

/**
 * Handles AWS deployment with automatic service selection
 */
async function handleAWSDeploy(
	deployConfig: DeployConfig,
	appDir: string,
	tmpDir: string,
	multiServiceConfig: MultiServiceConfig,
	dbConfig: DatabaseConfig | null,
	token: string,
	ws: any,
	userID: string | undefined,
	deployStartTime: number,
	send: (msg: string, stepId: string) => void,
	deploySteps: DeployStep[]
): Promise<string> {

	const region = deployConfig.awsRegion || config.AWS_REGION;
	const repoName = deployConfig.url.split("/").pop()?.replace(".git", "") || "app";

	// Setup AWS credentials
	send("Authenticating with AWS...", 'auth');
	await setupAWSCredentials(ws);
	send("✅ AWS credentials authenticated", 'auth');

	// EC2-only AWS deploy path
	const target: DeploymentTarget = 'ec2';
	deployConfig.deploymentTarget = target;
	sendDeploySteps(ws, AWS_DEPLOY_STEPS.ec2);

	// Handle database provisioning if needed
	let dbConnectionString: string | undefined;
	if (dbConfig) {
		send("Provisioning AWS RDS database...", 'database');
		try {
			const { connectionString } = await createRDSInstance(
				dbConfig,
				repoName,
				region,
				ws
			);
			dbConnectionString = connectionString;
			send(`Database provisioned successfully`, 'database');
		} catch (error: any) {
			send(`Database provisioning failed: ${error.message}. Continuing without database.`, 'database');
		}
	} else {
		send("✅ No database provisioning required", 'database');
	}

	let result: string;
	let deployUrl: string | undefined;
	const serviceDetails: ServiceDeployDetails = {};
	let success = false;

	const ec2Result = await handleEC2(
		deployConfig,
		appDir,
		multiServiceConfig,
		token,
		dbConnectionString,
		ws,
		send
	);
	success = ec2Result.success;

	// Extract only the serializable fields for storage (exclude Maps like serviceUrls)
	const ec2Details = deployConfig.ec2 || {};
	const ec2Typed = (ec2Details && typeof ec2Details === "object" && "instanceType" in ec2Details) 
		? (ec2Details as EC2Details)
		: null;
	serviceDetails.ec2 = {
		success: ec2Result.success,
		baseUrl: ec2Result.baseUrl,
		instanceId: ec2Result.instanceId,
		publicIp: ec2Result.publicIp,
		vpcId: ec2Result.vpcId,
		subnetId: ec2Result.subnetId,
		securityGroupId: ec2Result.securityGroupId,
		amiId: ec2Result.amiId,
		sharedAlbDns: ec2Result.sharedAlbDns || "",
		instanceType: ec2Typed?.instanceType || "t3.micro",
	};

	if (ec2Result.baseUrl == "") {
		send(`❌ Deployment failed: Server is not responding on any known ports. Please check your application and try again.`, 'deploy');
		result = "error";
	} else {
		// Build summary
		let ec2Summary = `\nDeployment completed!\n`;
		ec2Summary += `Instance ID: ${ec2Result.instanceId}\n`;
		ec2Summary += `Public IP: ${ec2Result.publicIp}\n`;
		ec2Summary += `\nService URLs:\n`;
		for (const [name, url] of ec2Result.serviceUrls.entries()) {
			ec2Summary += `  - ${name}: ${url}\n`;
		}
		send(ec2Summary, 'done');
		deployUrl = ec2Result.sharedAlbDns || ec2Result.baseUrl;
		result = "done";
	}


	let vercelResult: AddVercelDnsResult | null = null;
	if (deployUrl && deployConfig.liveUrl != deployUrl && deployConfig.serviceName?.trim() && success) {
		send("Adding Vercel DNS record...", 'done');
		vercelResult = await addVercelDnsRecord(deployUrl, deployConfig.serviceName, {
			deploymentTarget: target,
			previousCustomUrl: deployConfig.liveUrl ?? null,
		});
	}

	if (vercelResult && vercelResult.success) {
		send(`✅ Vercel DNS added successfully: ${vercelResult.customUrl}`, 'done');
	} else if (deployUrl && vercelResult && success) {
		send(`⚠️ Warning: Vercel DNS addition failed: ${vercelResult?.error ?? "Unknown error"}. Proceeding with instance IP.`, 'done');
	}

	// Mark final step by outcome
	const doneStep = deploySteps.find(s => s.id === 'done');
	if (doneStep) doneStep.status = success ? 'success' : 'error';

	// Calculate deployment duration
	const durationMs = Date.now() - deployStartTime;


	// Notify client of success and URL (include service details so client can persist for redeploy/update/delete)
	await sendDeployComplete(ws, deployUrl, success, deployConfig, deploySteps, userID, target, vercelResult, serviceDetails, durationMs);

	// Cleanup
	fs.rmSync(tmpDir, { recursive: true, force: true });
	return result;
}

/**
 * Handles AWS deployment using CodeBuild + ECR pipeline.
 * No local clone required — CodeBuild pulls source directly from GitHub.
 */
async function handleAWSCodeBuildDeploy(
	deployConfig: DeployConfig,
	token: string,
	ws: any,
	userID: string | undefined,
	deployStartTime: number,
	send: (msg: string, stepId: string) => void,
	deploySteps: DeployStep[],
): Promise<string> {
	const region = deployConfig.awsRegion || config.AWS_REGION;
	const repoUrl = deployConfig.url;
	const repoName = repoUrl.split("/").pop()?.replace(".git", "") || "app";
	const parsed = parseGithubOwnerRepo(repoUrl);
	const repoFullName = parsed ? `${parsed.owner}/${parsed.repo}` : repoName;

	const target: DeploymentTarget = "ec2";
	deployConfig.deploymentTarget = target;
	sendDeploySteps(ws, AWS_DEPLOY_STEPS["ec2-codebuild"]);

	// ── Auth: verify AWS credentials via SDK ──
	send("Authenticating with AWS...", "auth");
	if (config.AWS_ACCESS_KEY_ID && config.AWS_SECRET_ACCESS_KEY) {
		process.env.AWS_ACCESS_KEY_ID = config.AWS_ACCESS_KEY_ID;
		process.env.AWS_SECRET_ACCESS_KEY = config.AWS_SECRET_ACCESS_KEY;
	}
	process.env.AWS_DEFAULT_REGION = region;

	const stsClient = new STSClient(getAwsClientConfig(region));
	const identity = await stsClient.send(new GetCallerIdentityCommand({}));
	// if (identity.Arn) send(`Authenticated as: ${identity.Arn}`, "auth");
	// send("✅ AWS credentials verified", "auth");

	// Resolve branch
	let branch = deployConfig.branch?.trim() ?? "";
	if (!branch && parsed) {
		try {
			const { default_branch } = await fetchRepoMetadata(parsed.owner, parsed.repo, token);
			branch = default_branch;
			deployConfig.branch = default_branch;
		} catch (err) {
			const msg = err instanceof Error ? err.message : String(err);
			send(`Could not resolve default branch: ${msg}`, "auth");
			throw new Error("Missing deployment branch and could not resolve repository default");
		}
	}
	if (!branch) {
		send("Set a deployment branch in workspace settings before deploying.", "auth");
		throw new Error("Missing deployment branch");
	}
	const commitSha = deployConfig.commitSha?.trim();
	const imageTag = commitSha ? commitSha.substring(0, 6) : `deploy-${Date.now().toString(36)}`;

	// ── Build: CodeBuild + ECR ──
	const accountId = await getAwsAccountId(region);
	const ecrRegistry = getEcrRegistry(accountId, region);
	const ecrRepoName = `smartdeploy/${repoName}`;
	const ecrAuth = await getEcrAuthToken(region);
	const ecrPasswordB64 = Buffer.from(ecrAuth.password, "utf8").toString("base64");

	const scanResults = deployConfig.scanResults;
	const envBase64 = deployConfig.envVars
		? Buffer.from(deployConfig.envVars, "utf8").toString("base64")
		: undefined;

	const services = (scanResults && typeof scanResults === "object" && "services" in scanResults)
		? (scanResults as SDArtifactsResponse).services
		: [];
	const hasCompose = scanResults && typeof scanResults === "object" && "docker_compose" in scanResults && services.length > 1;
	const repoNames = new Set<string>();
	repoNames.add(ecrRepoName);
	if (hasCompose) {
		for (const svc of services) {
			const name = (svc.name || "").trim();
			if (name) repoNames.add(`${ecrRepoName}-${name}`);
		}
	}
	send("Preparing ECR repositories...", "build");
	for (const repo of repoNames) {
		await ensureEcrRepository(repo, region, send);
	}
	// Grant EC2 instances ECR pull access
	await ensureEc2EcrPullPolicy("smartdeploy-ec2-ssm-role", region);

	const hasCommit = Boolean(commitSha);
	let allTagsExist = hasCommit;
	if (hasCommit) {
		for (const repo of repoNames) {
			const exists = await ecrImageTagExists(region, repo, imageTag);
			if (!exists) {
				allTagsExist = false;
				break;
			}
		}
	}

	const dockerHubUser = config.DOCKERHUB_USERNAME?.trim();
	const dockerHubToken = config.DOCKERHUB_TOKEN?.trim();
	const dockerHub =
		dockerHubUser && dockerHubToken ? { username: dockerHubUser, token: dockerHubToken } : undefined;
	if (!dockerHub && dockerHubUser && !dockerHubToken) {
		send("⚠️ DOCKERHUB_USERNAME is set but DOCKERHUB_TOKEN is missing — Docker Hub login will be skipped.", "build");
	}

	if (!hasCommit || !allTagsExist) {
		const roleArn = await ensureCodeBuildRole(region, send);
		const projectName = await ensureCodeBuildProject(region, roleArn, send);

		// Only pass scanResults if it has the proper structure
		const scanResultsForBuild = (scanResults && "stack_summary" in scanResults) 
			? (scanResults as SDArtifactsResponse)
			: undefined;

		const buildspec = generateBuildspec({
			ecrRegistry,
			ecrRepoName,
			imageTag,
			region,
			scanResults: scanResultsForBuild,
		});

		const buildId = await startBuild({
			region,
			projectName,
			repoFullName,
			branch,
			commitSha,
			githubToken: token,
			buildspec,
			envVarsBase64: envBase64,
			dockerHub,
			send,
		});

		const buildResult = await waitForBuildAndStreamLogs({ buildId, region, send });
		if (!buildResult.success) {
			send("❌ Docker image build failed. Check build logs above.", "build");
			throw new Error("CodeBuild failed — Docker image build did not succeed");
		}
	} else {
		send(`CodeBuild skipped: image ${imageTag} already exists in ECR.`, "build");
	}

	const imageUri = getEcrImageUri(accountId, region, ecrRepoName, imageTag);
	send(`Image ready: ${imageUri}`, "build");

	// ── Setup + Deploy: EC2 from ECR ──
	send("Setting up networking...", "setup");
	const scanResultsTyped = (scanResults && typeof scanResults === "object" && "services" in scanResults)
		? (scanResults as SDArtifactsResponse)
		: null;
	const multiServiceConfig: MultiServiceConfig = {
		isMultiService: (scanResultsTyped?.services?.length || 0) > 1,
		services: (scanResultsTyped?.services || []).map(s => ({
			name: s.name,
			workdir: s.build_context || ".",
			dockerfile: s.dockerfile_path,
			port: s.port,
			build_context: s.build_context || ".",
		})),
		hasDockerCompose: !!scanResultsTyped?.docker_compose,
		isMonorepo: (scanResultsTyped?.services?.length || 0) > 1,
	};

	const ec2Result = await handleEC2FromEcr({
		deployConfig,
		imageUri,
		imageTag,
		ecrRegistry,
		ecrRepoName,
		ecrPasswordB64,
		multiServiceConfig,
		ws,
		send,
	});

	const serviceDetails: ServiceDeployDetails = {};
	const ec2Details2 = deployConfig.ec2 || {};
	const ec2Typed2 = (ec2Details2 && typeof ec2Details2 === "object" && "instanceType" in ec2Details2) 
		? (ec2Details2 as EC2Details)
		: null;
	serviceDetails.ec2 = {
		success: ec2Result.success,
		baseUrl: ec2Result.baseUrl,
		instanceId: ec2Result.instanceId,
		publicIp: ec2Result.publicIp,
		vpcId: ec2Result.vpcId,
		subnetId: ec2Result.subnetId,
		securityGroupId: ec2Result.securityGroupId,
		amiId: ec2Result.amiId,
		sharedAlbDns: ec2Result.sharedAlbDns || "",
		instanceType: ec2Typed2?.instanceType || "t3.micro",
	};

	let deployUrl: string | undefined;
	let result: string;

	if (!ec2Result.success || ec2Result.baseUrl === "") {
		send("❌ Deployment failed: Server is not responding. Check your application and try again.", "deploy");
		result = "error";
	} else {
		let ec2Summary = `\nDeployment completed!\n`;
		ec2Summary += `Instance ID: ${ec2Result.instanceId}\n`;
		ec2Summary += `Public IP: ${ec2Result.publicIp}\n`;
		ec2Summary += `\nService URLs:\n`;
		for (const [name, url] of ec2Result.serviceUrls.entries()) {
			ec2Summary += `  - ${name}: ${url}\n`;
		}
		send(ec2Summary, "done");
		deployUrl = ec2Result.sharedAlbDns || ec2Result.baseUrl;
		result = "done";
	}

	let vercelResult: AddVercelDnsResult | null = null;
		if (deployUrl && deployConfig.liveUrl !== deployUrl && deployConfig.serviceName?.trim() && ec2Result.success) {
			send("Adding Vercel DNS record...", "done");
			vercelResult = await addVercelDnsRecord(deployUrl, deployConfig.serviceName, {
				deploymentTarget: target,
				previousCustomUrl: deployConfig.liveUrl ?? null,
		});
	}

	if (vercelResult?.success) {
		send(`✅ Vercel DNS added: ${vercelResult.customUrl}`, "done");
	} else if (deployUrl && vercelResult && ec2Result.success) {
		send(`⚠️ Vercel DNS failed: ${vercelResult?.error ?? "Unknown error"}`, "done");
	}

	const doneStep = deploySteps.find(s => s.id === "done");
	if (doneStep) doneStep.status = ec2Result.success ? "success" : "error";

	const durationMs = Date.now() - deployStartTime;
	await sendDeployComplete(ws, deployUrl, ec2Result.success, deployConfig, deploySteps, userID, target, vercelResult, serviceDetails, durationMs);

	return result;
}

/**
 * Handles GCP deployment (existing Cloud Run logic)
 */
async function handleGCPDeploy(
	deployConfig: DeployConfig,
	appDir: string,
	cloneDir: string,
	tmpDir: string,
	multiServiceConfig: MultiServiceConfig,
	dbConfig: DatabaseConfig | null,
	token: string,
	ws: any,
	userID: string | undefined,
	deployStartTime: number,
	send: (msg: string, stepId: string) => void,
	deploySteps: DeployStep[]
): Promise<string> {

	const projectId = config.GCP_PROJECT_ID;
	const keyObject = JSON.parse(config.GCP_SERVICE_ACCOUNT_KEY);
	const keyPath = "/tmp/smartdeploy-key.json";
	fs.writeFileSync(keyPath, JSON.stringify(keyObject, null, 2));

	const gcpSteps = [
		{ id: "auth", label: "🔐 Authentication" },
		{ id: "clone", label: "📦 Cloning repository" },
		{ id: "detect", label: "🔍 Analyzing app" },
		{ id: "database", label: "🗄️ Database (Cloud SQL)" },
		{ id: "docker", label: "🐳 Build image (Cloud Build)" },
		{ id: "deploy", label: "🚀 Deploy to Cloud Run" },
		{ id: "done", label: "✅ Done" },
	];
	sendDeploySteps(ws, gcpSteps);

	send("Authenticating with Google Cloud...", 'auth');
	await runCommandLiveWithWebSocket("gcloud", ["auth", "activate-service-account", `--key-file=${keyPath}`], ws, 'auth', { send });
	await runCommandLiveWithWebSocket("gcloud", ["config", "set", "project", projectId, "--quiet"], ws, 'auth', { send });
	await runCommandLiveWithWebSocket("gcloud", ["auth", "configure-docker"], ws, 'auth', { send });

	const repoName = deployConfig.url.split("/").pop()?.replace(".git", "") || "default-app";
	const serviceName = `${repoName}`;

	// Handle multi-service deployment
	if (multiServiceConfig.isMultiService && multiServiceConfig.services.length > 1) {
		send(`Detected multi-service application with ${multiServiceConfig.services.length} services`, 'detect');
		send("Starting multi-service deployment...", 'detect');

		const { serviceUrls } = await handleMultiServiceDeploy(
			deployConfig,
			token,
			ws,
			cloneDir
		);

		let summary = `\nMulti-service deployment completed!\n\nDeployed services:\n`;
		for (const [name, url] of serviceUrls.entries()) {
			summary += `  - ${name}: ${url}\n`;
		}
		send(summary, 'done');
		const firstGcpUrl = serviceUrls.entries().next().value;
		const gcpDeployUrl = firstGcpUrl ? firstGcpUrl[1] : undefined;
		let vercelResult: AddVercelDnsResult | null = null;
		if (gcpDeployUrl && deployConfig.serviceName?.trim()) {
			vercelResult = await addVercelDnsRecord(gcpDeployUrl, deployConfig.serviceName, {
				deploymentTarget: "cloud_run",
				previousCustomUrl: deployConfig.liveUrl ?? null,
			});
		}
		const doneStep = deploySteps.find(s => s.id === 'done');
		if (doneStep) doneStep.status = 'success';
		const durationMs = Date.now() - deployStartTime;
		const success = gcpDeployUrl ? true : false;
		await sendDeployComplete(ws, gcpDeployUrl, success, deployConfig, deploySteps, userID, "cloud_run", vercelResult, null, durationMs);
		fs.rmSync(tmpDir, { recursive: true, force: true });
		return "done";
	}

	// Handle database provisioning for GCP
	let dbConnectionString: string | undefined;
	if (dbConfig) {
		send("Provisioning Cloud SQL database...", 'database');
		try {
			const instanceName = `${repoName}-db-${Date.now()}`.toLowerCase().replace(/[^a-z0-9-]/g, '-');
			const { connectionName, ipAddress } = await createCloudSQLInstance(
				dbConfig,
				projectId,
				instanceName,
				ws
			);
			dbConnectionString = generateCloudSQLConnectionString(dbConfig, connectionName, ipAddress, dbConfig.database);
			send(`Database provisioned successfully`, 'database');
		} catch (error: any) {
			send(`Database provisioning failed: ${error.message}. Continuing without database.`, 'database');
		}
	}

	// Single-service GCP deployment
	const dockerfilePath = path.join(appDir, "Dockerfile");

	if (!fs.existsSync(dockerfilePath)) {
		const scanResults = deployConfig.scanResults;
		const scanResultsTyped = (scanResults && typeof scanResults === "object" && "dockerfiles" in scanResults)
			? (scanResults as SDArtifactsResponse)
			: null;
		const dockerfileContent = scanResultsTyped?.dockerfiles?.["Dockerfile"] || (scanResultsTyped?.services?.[0]?.dockerfile_path ? scanResultsTyped?.dockerfiles?.[scanResultsTyped.services[0].dockerfile_path] : null);

		if (dockerfileContent) {
			send(`Using AI-generated Dockerfile`, 'clone');
			fs.writeFileSync(dockerfilePath, dockerfileContent);
		} else {
			throw new Error("No Dockerfile found in deployment config and no AI-generated Dockerfile available.");
		}
	}

	const imageName = `${repoName}-image`;
	const gcpImage = `gcr.io/${projectId}/${imageName}:latest`;

	send("Building Docker image with Cloud Build...", 'docker');
	await runCommandLiveWithWebSocket("gcloud", [
		"builds", "submit",
		"--tag", gcpImage,
		appDir
	], ws, 'docker', { send });

	send("Deploying to Cloud Run...", 'deploy');

	// Build environment variables
	const envVarsList: string[] = [];
	if (deployConfig.envVars) {
		envVarsList.push(deployConfig.envVars.replace(/\r?\n/g, ","));
	}
	if (dbConnectionString) {
		envVarsList.push(`DATABASE_URL=${dbConnectionString}`);
		envVarsList.push(`ConnectionStrings__DefaultConnection=${dbConnectionString}`);
	}

	const envArgs = envVarsList.length > 0 ? ["--set-env-vars", envVarsList.join(",")] : [];

	await runCommandLiveWithWebSocket("gcloud", [
		"run", "deploy", serviceName,
		"--image", gcpImage,
		"--platform", "managed",
		"--region", "us-central1",
		"--allow-unauthenticated",
		...envArgs
	], ws, 'deploy', { send });

	await runCommandLiveWithWebSocket("gcloud", [
		"beta", "run", "services", "add-iam-policy-binding",
		serviceName,
		"--region=us-central1",
		"--platform=managed",
		"--member=allUsers",
		"--role=roles/run.invoker",
	], ws, 'deploy', { send });

	send(`Deployment success`, 'done');

	// Cloud Run URL format; we don't have the exact URL from gcloud output, so leave deployUrl for client to show "done"
	const gcpDeployUrl = `https://console.cloud.google.com/run?project=${projectId}`;
	let vercelResult: AddVercelDnsResult | null = null;
	if (gcpDeployUrl && deployConfig.serviceName?.trim()) {
		vercelResult = await addVercelDnsRecord(gcpDeployUrl, deployConfig.serviceName, {
			deploymentTarget: "cloud_run",
			previousCustomUrl: deployConfig.liveUrl ?? null,
		});
	}
	const doneStep = deploySteps.find(s => s.id === 'done');
	if (doneStep) doneStep.status = 'success';
	const durationMs = Date.now() - deployStartTime;
	const success = gcpDeployUrl ? true : false;

	await sendDeployComplete(ws, gcpDeployUrl, success, deployConfig, deploySteps, userID, "cloud_run", vercelResult, null, durationMs);

	// Cleanup temp folder
	fs.rmSync(tmpDir, { recursive: true, force: true });

	return "done";
}

import fs from "fs";
import os from "os";
import path from "path";
import config from "../config";
import { runCommandLiveWithWebSocket } from "../server-helper";
import { DeployConfig } from "../app/types";
import { detectMultiService, ServiceDefinition } from "./multiServiceDetector";
import { detectDatabase } from "./databaseDetector";
import { createCloudSQLInstance, connectCloudRunToCloudSQL, generateCloudSQLConnectionString } from "./handleDatabaseDeploy";
import { createWebSocketLogger } from "./websocketLogger";
import {
	generateMonorepoDockerfile,
	monorepoDockerfileAbsPath,
	monorepoDockerfileRelPath,
	writeMonorepoDockerfiles,
} from "./monorepoDockerfileGenerator";

/**
 * Generates Dockerfile content for a service
 */
function generateDockerfileForService(
	service: ServiceDefinition,
	deployConfig: DeployConfig,
	serviceIndex: number
): string {
	const language = service.language || "node";
	const workdir = service.workdir || "/app";
	const port = service.port || 8080;

	let dockerfileContent = "";

	switch (language) {
		case "node":
			dockerfileContent = `
FROM node:18-alpine
WORKDIR ${workdir}
COPY . .
RUN npm install
RUN npm run build || true
EXPOSE ${port}
CMD ["npm", "start"]
			`.trim();
			break;

		case "python":
			dockerfileContent = `
FROM python:3.11-slim
WORKDIR ${workdir}
COPY . .
RUN pip install -r requirements.txt
EXPOSE ${port}
CMD ["python", "main.py"]
			`.trim();
			break;

		case "go":
			dockerfileContent = `
FROM golang:1.20-alpine
WORKDIR ${workdir}
COPY . .
RUN go mod tidy
RUN go build -o app
EXPOSE ${port}
CMD ["./app"]
			`.trim();
			break;

		case "java":
			dockerfileContent = `
FROM openjdk:17-alpine
WORKDIR ${workdir}
COPY . .
RUN ./mvnw install || mvn install
RUN ./mvnw package || mvn package
EXPOSE ${port}
CMD ["java", "-jar", "target/app.jar"]
			`.trim();
			break;

		case "rust":
			dockerfileContent = `
FROM rust:1.70-alpine
WORKDIR ${workdir}
COPY . .
RUN cargo fetch
RUN cargo build --release
EXPOSE ${port}
CMD ["./target/release/app"]
			`.trim();
			break;

		case "dotnet":
			dockerfileContent = `
FROM mcr.microsoft.com/dotnet/sdk:8.0 AS build
WORKDIR ${workdir}
COPY . .
RUN dotnet restore
RUN dotnet build -c Release
RUN dotnet publish -c Release -o /app/publish

FROM mcr.microsoft.com/dotnet/aspnet:8.0
WORKDIR /app
COPY --from=build /app/publish .
EXPOSE ${port}
CMD ["dotnet", "*.dll"]
			`.trim();
			break;

		default:
			throw new Error(`Unsupported language: ${language}`);
	}

	return dockerfileContent;
}

/**
 * Deploys a single service to Cloud Run
 */
async function deployService(
	service: ServiceDefinition,
	repoName: string,
	projectId: string,
	serviceIndex: number,
	allServiceUrls: Map<string, string>,
	dbConnectionName?: string,
	dbConnectionString?: string,
	ws?: any
): Promise<string> {
	const send = createWebSocketLogger(ws);

	const serviceName = `${repoName}-${service.name}`;
	const imageName = `${repoName}-${service.name}-image`;
	const gcpImage = `gcr.io/${projectId}/${imageName}:latest`;

	send(`🐳 Building Docker image for service "${service.name}"...`, `docker-${serviceIndex}`);

	// Build context is the service's workdir (or monorepo root for monorepo services)
	const buildContext = service.build_context || service.workdir;

	if (service.dockerfile && service.dockerfile !== "Dockerfile") {
		// For alternate Dockerfile paths (e.g. monorepo apps/web/Dockerfile with context at repo root)
		const cloudbuildConfig = {
			steps: [{
				name: "gcr.io/cloud-builders/docker",
				args: ["build", "-f", service.dockerfile, "-t", gcpImage, "."]
			}],
			images: [gcpImage]
		};
		const cloudbuildPath = path.join(buildContext, `cloudbuild-${service.name}.yaml`);
		fs.writeFileSync(cloudbuildPath, JSON.stringify(cloudbuildConfig));

		await runCommandLiveWithWebSocket("gcloud", [
			"builds", "submit",
			"--config", cloudbuildPath,
			buildContext
		], ws, `docker-${serviceIndex}`);

		// Cleanup temp cloudbuild file
		try { fs.unlinkSync(cloudbuildPath); } catch { }
	} else {
		await runCommandLiveWithWebSocket("gcloud", [
			"builds", "submit",
			"--tag", gcpImage,
			buildContext
		], ws, `docker-${serviceIndex}`);
	}

	send(`🚀 Deploying service "${service.name}" to Cloud Run...`, `deploy-${serviceIndex}`);

	// Prepare environment variables
	const envVars: string[] = [];

	// Add service's own env vars
	if (service.env_vars) {
		for (const [key, value] of Object.entries(service.env_vars)) {
			envVars.push(`${key}=${value}`);
		}
	}

	// Add service URLs for inter-service communication
	for (const [svcName, url] of allServiceUrls.entries()) {
		if (svcName !== service.name) {
			const envKey = `${svcName.toUpperCase().replace(/-/g, "_")}_URL`;
			envVars.push(`${envKey}=${url}`);
		}
	}

	// Add database connection string if available
	if (dbConnectionString) {
		envVars.push(`ConnectionStrings__DefaultConnection=${dbConnectionString}`);
		envVars.push(`DATABASE_URL=${dbConnectionString}`);
		envVars.push(`DB_CONNECTION_STRING=${dbConnectionString}`);
	}

	const envArgs = envVars.length > 0 ? ["--set-env-vars", envVars.join(",")] : [];

	await runCommandLiveWithWebSocket("gcloud", [
		"run", "deploy", serviceName,
		"--image", gcpImage,
		"--platform", "managed",
		"--region", "us-central1",
		"--allow-unauthenticated",
		"--port", String(service.port || 8080),
		...envArgs
	], ws, `deploy-${serviceIndex}`);

	await runCommandLiveWithWebSocket("gcloud", [
		"beta", "run", "services", "add-iam-policy-binding",
		serviceName,
		"--region=us-central1",
		"--platform=managed",
		"--member=allUsers",
		"--role=roles/run.invoker",
	], ws, `deploy-${serviceIndex}`);

	// Connect to Cloud SQL if database connection is available
	if (dbConnectionName) {
		await connectCloudRunToCloudSQL(serviceName, dbConnectionName, ws);
	}

	// Get the service URL
	try {
		const urlOutput = await runCommandLiveWithWebSocket("gcloud", [
			"run", "services", "describe", serviceName,
			"--region=us-central1",
			"--platform=managed",
			"--format=value(status.url)"
		], ws, `deploy-${serviceIndex}`);

		const serviceUrl = urlOutput.trim();
		if (serviceUrl) {
			send(`✅ Service "${service.name}" deployed at: ${serviceUrl}`, `deploy-${serviceIndex}`);
			return serviceUrl;
		}
	} catch (error) {
		console.error(`Failed to get URL for ${serviceName}:`, error);
	}

	// Fallback: construct URL from service name
	const serviceUrl = `https://${serviceName}-${projectId}.a.run.app`;
	send(`✅ Service "${service.name}" deployed (URL: ${serviceUrl})`, `deploy-${serviceIndex}`);
	return serviceUrl;
}

/**
 * Main function to handle multi-service deployment
 */
export async function handleMultiServiceDeploy(
	deployConfig: DeployConfig,
	token: string,
	ws: any,
	cloneDir: string
): Promise<{ serviceUrls: Map<string, string>, deployedServices: string[] }> {
	const send = createWebSocketLogger(ws);

	const projectId = config.GCP_PROJECT_ID;
	const repoUrl = deployConfig.url;
	const repoName = repoUrl.split("/").pop()?.replace(".git", "") || "default-app";

	const appDir = cloneDir;

	// Detect multi-service configuration from the repo root so docker-compose at root is honored
	send("🔍 Detecting application structure...", 'detect');
	const multiServiceConfig = detectMultiService(cloneDir);

	if (!multiServiceConfig.isMultiService || multiServiceConfig.services.length === 0) {
		throw new Error("Multi-service deployment called but no services detected");
	}

	send(`📦 Detected ${multiServiceConfig.services.length} service(s)`, 'detect');
	if (multiServiceConfig.hasDockerCompose) {
		send("📄 Using docker-compose.yml configuration", 'detect');
	} else if (multiServiceConfig.isMonorepo) {
		send(`📦 Detected monorepo structure (${multiServiceConfig.packageManager || 'npm'} workspaces)`, 'detect');
	} else {
		send("🤖 Using algorithmic service detection", 'detect');
	}

	// Detect database requirements
	send("🗄️ Detecting database requirements...", 'database');
	let dbConfig = null;
	let dbConnectionName: string | undefined;
	let dbConnectionString: string | undefined;

	// Check each service for database dependencies
	for (const service of multiServiceConfig.services) {
		const serviceDir = path.isAbsolute(service.workdir)
			? service.workdir
			: path.join(appDir, service.workdir);

		const detectedDb = detectDatabase(appDir, serviceDir);
		if (detectedDb) {
			dbConfig = detectedDb;
			send(`📊 Detected ${detectedDb.type.toUpperCase()} database requirement in ${service.name}`, 'database');
			break;
		}
	}

	// If database detected, create Cloud SQL instance
	if (dbConfig) {
		const instanceName = `${repoName}-db-${Date.now()}`.toLowerCase().replace(/[^a-z0-9-]/g, '-');
		try {
			const { connectionName, ipAddress } = await createCloudSQLInstance(
				dbConfig,
				projectId,
				instanceName,
				ws
			);
			dbConnectionName = connectionName;
			dbConnectionString = generateCloudSQLConnectionString(
				dbConfig,
				connectionName,
				ipAddress,
				dbConfig.database
			);
			send(`✅ Cloud SQL instance ready: ${instanceName}`, 'database');
		} catch (error: any) {
			send(`⚠️ Database setup failed: ${error.message}. Services will deploy without database connection.`, 'database');
		}
	} else {
		send("ℹ️ No database requirements detected", 'database');
	}

	// Generate Dockerfiles for services that don't have them
	const serviceUrls = new Map<string, string>();
	const deployedServices: string[] = [];

	// For monorepo services, generate monorepo-aware Dockerfiles at the repo root
	if (multiServiceConfig.isMonorepo) {
		send("✍️ Generating monorepo-aware Dockerfiles...", 'detect');
		writeMonorepoDockerfiles(multiServiceConfig.services, multiServiceConfig, cloneDir);
	}

	for (let i = 0; i < multiServiceConfig.services.length; i++) {
		const service = multiServiceConfig.services[i];
		send(`\n📦 Processing service: ${service.name}`, `service-${i}`);

		// Ensure workdir is absolute
		const serviceWorkdir = path.isAbsolute(service.workdir)
			? service.workdir
			: path.join(appDir, service.workdir);

		if (multiServiceConfig.isMonorepo) {
			const monoDockerfilePath = monorepoDockerfileAbsPath(cloneDir, service);
			if (!fs.existsSync(monoDockerfilePath)) {
				send(`✍️ Generating monorepo Dockerfile for ${service.name}...`, `service-${i}`);
				const content = generateMonorepoDockerfile(service, multiServiceConfig, cloneDir);
				const serviceDir = path.dirname(monoDockerfilePath);
				if (!fs.existsSync(serviceDir)) {
					fs.mkdirSync(serviceDir, { recursive: true });
				}
				fs.writeFileSync(monoDockerfilePath, content);
			} else {
				send(`✅ Found existing Dockerfile for ${service.name}`, `service-${i}`);
			}
			// For monorepo, build context is the repo root; Dockerfile lives under the service folder
			service.workdir = serviceWorkdir;
			service.build_context = cloneDir;
			service.dockerfile = monorepoDockerfileRelPath(service);
		} else {
			// Check if service has a Dockerfile
			const dockerfilePath = service.dockerfile
				? path.join(serviceWorkdir, service.dockerfile)
				: path.join(serviceWorkdir, "Dockerfile");

			if (!fs.existsSync(dockerfilePath)) {
				send(`✍️ Generating Dockerfile for ${service.name}...`, `service-${i}`);
				const dockerfileContent = generateDockerfileForService(service, deployConfig, i);
				fs.writeFileSync(dockerfilePath, dockerfileContent);
			} else {
				send(`✅ Found existing Dockerfile for ${service.name}`, `service-${i}`);
			}

			// Update service workdir to absolute path
			service.workdir = serviceWorkdir;
			if (!service.build_context) {
				service.build_context = serviceWorkdir;
			}
		}

		// Deploy the service
		const serviceUrl = await deployService(
			service,
			repoName,
			projectId,
			i,
			serviceUrls,
			dbConnectionName,
			dbConnectionString,
			ws
		);

		serviceUrls.set(service.name, serviceUrl);
		deployedServices.push(service.name);
	}

	send(`\n✅ All ${deployedServices.length} services deployed successfully!`, 'done');

	return { serviceUrls, deployedServices };
}

import fs from "fs";
import path from "path";
import { ServiceDefinition, MultiServiceConfig } from "./multiServiceDetector";

/** Relative path from monorepo root to the service Dockerfile (posix, for compose / docker -f). */
export function monorepoDockerfileRelPath(service: ServiceDefinition): string {
	const rel = (service.relativePath || service.name).replace(/\\/g, "/").replace(/^\/+|\/+$/g, "");
	return `${rel}/Dockerfile`;
}

export function monorepoDockerfileAbsPath(monorepoRoot: string, service: ServiceDefinition): string {
	const relParts = (service.relativePath || service.name).split(/[/\\]+/).filter(Boolean);
	return path.join(monorepoRoot, ...relParts, "Dockerfile");
}

/**
 * Generates a proper Dockerfile for a monorepo service.
 * 
 * Monorepo services need special handling:
 * 1. The build context must be the monorepo root (so shared packages are available)
 * 2. The Dockerfile must COPY the full workspace and install from the root
 * 3. Build/run commands target the specific service using the workspace package manager
 */
export function generateMonorepoDockerfile(
	service: ServiceDefinition,
	multiServiceConfig: MultiServiceConfig,
	monorepoRoot: string,
): string {
	const language = service.language || "node";
	const framework = service.framework;
	const relativePath = service.relativePath || path.relative(monorepoRoot, service.workdir).replace(/\\/g, "/");
	const pm = multiServiceConfig.packageManager || "npm";
	const port = service.port || 8080;

	// Read package.json of the service to get the package name and scripts
	let packageName = `@monorepo/${service.name}`;
	let hasStartScript = false;
	let hasBuildScript = false;
	const serviceDir = path.isAbsolute(service.workdir) ? service.workdir : path.join(monorepoRoot, service.workdir);
	const pkgPath = path.join(serviceDir, "package.json");
	if (fs.existsSync(pkgPath)) {
		try {
			const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));
			packageName = pkg.name || packageName;
			hasStartScript = !!pkg.scripts?.start;
			hasBuildScript = !!pkg.scripts?.build;
		} catch { /* ignore */ }
	}

	switch (language) {
		case "node":
			return generateNodeMonorepoDockerfile(pm, relativePath, packageName, port, framework, hasStartScript, hasBuildScript);
		case "python":
			return generatePythonMonorepoDockerfile(relativePath, port);
		case "go":
			return generateGoMonorepoDockerfile(relativePath, port);
		default:
			return generateNodeMonorepoDockerfile(pm, relativePath, packageName, port, framework, hasStartScript, hasBuildScript);
	}
}

function generateNodeMonorepoDockerfile(
	pm: string,
	relativePath: string,
	packageName: string,
	port: number,
	framework?: string,
	hasStartScript: boolean = true,
	hasBuildScript: boolean = false,
): string {
	const installCmd = pm === "pnpm"
		? "RUN corepack enable && corepack prepare pnpm@latest --activate && pnpm install --frozen-lockfile"
		: pm === "yarn"
			? "RUN yarn install --frozen-lockfile"
			: "RUN npm ci || npm install || (npm install -g pnpm && pnpm install)";

	const lockfiles = pm === "pnpm"
		? "COPY pnpm-lock.yaml pnpm-workspace.yaml ./"
		: pm === "yarn"
			? "COPY yarn.lock ./"
			: "COPY package-lock.json ./";

	// For pnpm, we need to filter the install to be more efficient
	const buildCmd = hasBuildScript
		? pm === "pnpm"
			? `RUN pnpm --filter ${packageName} build`
			: pm === "yarn"
				? `RUN yarn workspace ${packageName} build`
				: `RUN npm run build --workspace=${relativePath}`
		: "";

	const startCmd = pm === "pnpm"
		? `CMD ["pnpm", "--filter", "${packageName}", "start"]`
		: pm === "yarn"
			? `CMD ["yarn", "workspace", "${packageName}", "start"]`
			: `CMD ["npm", "run", "start", "--workspace=${relativePath}"]`;

	// Next.js requires standalone output for optimal Docker builds
	const nextjsNote = framework === "nextjs"
		? `# Note: For production Next.js, consider adding output: 'standalone' to next.config.js`
		: "";

	return `
FROM node:20-alpine AS base
WORKDIR /app

# Copy package files for dependency caching
COPY package.json ./
${lockfiles}

# Copy all workspace package.json files so install can resolve workspace deps
COPY ${relativePath}/package.json ./${relativePath}/package.json

${installCmd}

# Copy full monorepo source
COPY . .

${nextjsNote}
${buildCmd}

ENV PORT=${port}
ENV HOSTNAME="0.0.0.0"
EXPOSE ${port}

${startCmd}
`.trim();
}

function generatePythonMonorepoDockerfile(relativePath: string, port: number): string {
	return `
FROM python:3.11-slim
WORKDIR /app

# Copy the full monorepo
COPY . .

# Install dependencies for this service
RUN pip install --no-cache-dir -r ${relativePath}/requirements.txt

WORKDIR /app/${relativePath}

ENV PORT=${port}
EXPOSE ${port}

CMD ["python", "app.py"]
`.trim();
}

function generateGoMonorepoDockerfile(relativePath: string, port: number): string {
	return `
FROM golang:1.21-alpine AS builder
WORKDIR /app

# Copy the full monorepo (Go modules may reference local packages)
COPY . .

WORKDIR /app/${relativePath}
RUN go mod download
RUN CGO_ENABLED=0 go build -o /app/main .

FROM alpine:latest
WORKDIR /app
RUN apk --no-cache add ca-certificates
COPY --from=builder /app/main .

ENV PORT=${port}
EXPOSE ${port}

CMD ["./main"]
`.trim();
}

/**
 * Generates a docker-compose.yml for a monorepo with multiple deployable services.
 * Each service gets its own Dockerfile with the build context set to the monorepo root.
 */
export function generateMonorepoDockerCompose(
	services: ServiceDefinition[],
	multiServiceConfig: MultiServiceConfig,
	monorepoRoot: string,
	envVars?: string,
	dbConnectionString?: string,
): string {
	const composeServices: Record<string, any> = {};

	for (const service of services) {
		const relativePath = service.relativePath || path.relative(monorepoRoot, service.workdir).replace(/\\/g, "/");
		const p = service.port || 8080;
		const env: string[] = [`PORT=${p}`, "NODE_ENV=production"];
		if (dbConnectionString) env.push(`DATABASE_URL=${dbConnectionString}`);

		// Add inter-service communication URLs
		for (const otherService of services) {
			if (otherService.name !== service.name) {
				const envKey = `${otherService.name.toUpperCase().replace(/-/g, "_")}_URL`;
				env.push(`${envKey}=http://${otherService.name}:${otherService.port || 8080}`);
			}
		}

		composeServices[service.name] = {
			build: {
				context: ".",
				dockerfile: monorepoDockerfileRelPath(service),
			},
			ports: [`${p}:${p}`],
			environment: env,
			restart: "unless-stopped",
		};
	}

	return JSON.stringify({ version: "3.8", services: composeServices }, null, 2);
}

/**
 * Writes Dockerfiles for all monorepo services under each service directory (e.g. apps/web/Dockerfile).
 * Compose stays at the monorepo root with build.context "." and dockerfile pointing at that path.
 */
export function writeMonorepoDockerfiles(
	services: ServiceDefinition[],
	multiServiceConfig: MultiServiceConfig,
	monorepoRoot: string,
): void {
	for (const service of services) {
		const dockerfilePath = monorepoDockerfileAbsPath(monorepoRoot, service);
		const relForLog = monorepoDockerfileRelPath(service);

		// Don't overwrite existing Dockerfiles
		if (fs.existsSync(dockerfilePath)) {
			console.log(`Dockerfile already exists: ${relForLog}`);
			service.dockerfile = monorepoDockerfileRelPath(service);
			continue;
		}

		// Also check if the service has its own Dockerfile
		const serviceDockerfile = path.join(
			path.isAbsolute(service.workdir) ? service.workdir : path.join(monorepoRoot, service.workdir),
			"Dockerfile"
		);
		if (fs.existsSync(serviceDockerfile)) {
			console.log(`Service ${service.name} has its own Dockerfile, skipping generation`);
			service.dockerfile = monorepoDockerfileRelPath(service);
			continue;
		}

		const serviceDir = path.dirname(dockerfilePath);
		if (!fs.existsSync(serviceDir)) {
			fs.mkdirSync(serviceDir, { recursive: true });
		}

		const content = generateMonorepoDockerfile(service, multiServiceConfig, monorepoRoot);
		fs.writeFileSync(dockerfilePath, content);
		service.dockerfile = monorepoDockerfileRelPath(service);
		console.log(`Generated ${relForLog} for service ${service.name}`);
	}
}

import fs from "fs";
import path from "path";
import yaml from "js-yaml";

export interface ServiceDefinition {
	name: string;
	workdir: string;
	language?: string;
	dockerfile?: string;
	port?: number;
	env_vars?: Record<string, string>;
	depends_on?: string[];
	build_context?: string;
	/** For monorepo services: the relative path from the repo root to the service (e.g. "apps/web") */
	relativePath?: string;
	/** The framework detected for this service (e.g. "nextjs", "express") */
	framework?: string;
}

export interface MultiServiceConfig {
	isMultiService: boolean;
	services: ServiceDefinition[];
	hasDockerCompose: boolean;
	/** True when the repo uses workspace tooling (pnpm workspaces, turborepo, lerna, nx, etc.) */
	isMonorepo: boolean;
	/** The package manager used by the monorepo (pnpm, npm, yarn) */
	packageManager?: string;
	/** The monorepo root directory (usually the repo root) */
	monorepoRoot?: string;
}

/** Infer dockerfile path when compose omits build.dockerfile (legacy root Dockerfile.<name> or service-dir Dockerfile). */
function inferDockerfileFromCompose(appDir: string, serviceName: string, buildContextRaw: string | undefined): string | undefined {
	const rootLegacy = path.join(appDir, `Dockerfile.${serviceName}`);
	if (fs.existsSync(rootLegacy)) return `Dockerfile.${serviceName}`;

	const ctx = (buildContextRaw || ".").replace(/^\.\//, "").trim();
	if (ctx && ctx !== ".") {
		const nested = path.join(appDir, ctx, "Dockerfile");
		if (fs.existsSync(nested)) {
			return path.posix.join(ctx.replace(/\\/g, "/"), "Dockerfile");
		}
	}
	return undefined;
}

/**
 * Detects if a docker-compose.yml file exists and parses it
 */
export function detectDockerCompose(appDir: string): MultiServiceConfig | null {
	console.log("detectDockerCompose", appDir);
	const composeFiles = [
		"docker-compose.yml",
		"docker-compose.yaml",
		"compose.yml",
		"compose.yaml"
	];

	for (const file of composeFiles) {
		const composePath = path.join(appDir, file);
		
		if (fs.existsSync(composePath)) {
			console.log("composePath", composePath);
			try {
				const content = fs.readFileSync(composePath, "utf-8");
				const compose = yaml.load(content) as any;

				console.log("compose", compose);

				if (compose && compose.services) {
					const services: ServiceDefinition[] = [];

					for (const [serviceName, serviceConfig] of Object.entries(compose.services as any)) {
						const config = serviceConfig as any;

						console.log("serviceConfig", serviceConfig);
						
						// Skip database services (we'll handle them separately)
						if (isDatabaseService(serviceName, config)) {
							continue;
						}

						const contextFromCompose = config.build?.context;
						const workdir = contextFromCompose || appDir;
						const service: ServiceDefinition = {
							name: serviceName,
							workdir,
							dockerfile:
								config.build?.dockerfile ||
								inferDockerfileFromCompose(appDir, serviceName, contextFromCompose),
							port: extractPort(config),
							env_vars: config.environment || {},
							depends_on: config.depends_on || [],
							build_context: contextFromCompose || appDir
						};

						// Detect language if no dockerfile specified
						if (!service.dockerfile && service.workdir) {
							service.language = detectLanguage(service.workdir);
						}

						services.push(service);
					}

					if (services.length > 0) {
						return {
							isMultiService: true,
							services,
							hasDockerCompose: true,
							isMonorepo: false,
						};
					}
				}
			} catch (error) {
				console.error(`Error parsing docker-compose file: ${error}`);
			}
		}
	}

	return null;
}

/** Directories that commonly hold deployable apps inside a monorepo */
const MONOREPO_APP_ROOTS = ["apps", "services", "packages", "modules"];

/** Service directory names to skip (mobile-only, not deployable to cloud) */
const MOBILE_ONLY_DIRS = ["mobile", "ios", "android", "react-native", "flutter", "expo"];

/**
 * Detects monorepo workspace tooling at a given directory.
 * Returns the package manager and monorepo kind if found.
 */
export function detectMonorepoTooling(appDir: string): { isMonorepo: boolean; packageManager?: string; workspaceGlobs?: string[] } {
	// pnpm workspaces
	const pnpmWorkspacePath = path.join(appDir, "pnpm-workspace.yaml");
	if (fs.existsSync(pnpmWorkspacePath)) {
		try {
			const content = fs.readFileSync(pnpmWorkspacePath, "utf-8");
			const parsed = yaml.load(content) as any;
			const globs: string[] = parsed?.packages || [];
			return { isMonorepo: true, packageManager: "pnpm", workspaceGlobs: globs };
		} catch { /* ignore parse errors */ }
	}

	// npm/yarn workspaces (in package.json)
	const rootPkgPath = path.join(appDir, "package.json");
	if (fs.existsSync(rootPkgPath)) {
		try {
			const pkg = JSON.parse(fs.readFileSync(rootPkgPath, "utf-8"));
			if (pkg.workspaces) {
				const globs = Array.isArray(pkg.workspaces) ? pkg.workspaces : pkg.workspaces.packages || [];
				const pm = pkg.packageManager?.startsWith("yarn") ? "yarn" : "npm";
				return { isMonorepo: true, packageManager: pm, workspaceGlobs: globs };
			}
		} catch { /* ignore */ }
	}

	// Turborepo / Nx / Lerna
	const monorepoMarkers = ["turbo.json", "nx.json", "lerna.json"];
	for (const marker of monorepoMarkers) {
		if (fs.existsSync(path.join(appDir, marker))) {
			// Try to determine package manager from root package.json
			let pm = "npm";
			if (fs.existsSync(rootPkgPath)) {
				try {
					const pkg = JSON.parse(fs.readFileSync(rootPkgPath, "utf-8"));
					if (pkg.packageManager?.startsWith("pnpm")) pm = "pnpm";
					else if (pkg.packageManager?.startsWith("yarn")) pm = "yarn";
				} catch { /* ignore */ }
			}
			if (fs.existsSync(pnpmWorkspacePath)) pm = "pnpm";
			return { isMonorepo: true, packageManager: pm };
		}
	}

	return { isMonorepo: false };
}

/**
 * Checks if a directory is a mobile-only project (not deployable to cloud).
 */
function isMobileOnlyDir(dirName: string, dirPath: string): boolean {
	if (MOBILE_ONLY_DIRS.includes(dirName.toLowerCase())) return true;

	// Check for React Native / Expo / Flutter markers
	const pkgPath = path.join(dirPath, "package.json");
	if (fs.existsSync(pkgPath)) {
		try {
			const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));
			const deps = { ...pkg.dependencies, ...pkg.devDependencies };
			// React Native or Expo project
			if (deps["react-native"] || deps["expo"] || deps["@expo/cli"]) return true;
		} catch { /* ignore */ }
	}
	if (fs.existsSync(path.join(dirPath, "pubspec.yaml"))) return true; // Flutter
	if (fs.existsSync(path.join(dirPath, "android")) && fs.existsSync(path.join(dirPath, "ios"))) return true;

	return false;
}

/**
 * Detects the framework used in a directory.
 */
function detectFramework(dir: string): string | undefined {
	const pkgPath = path.join(dir, "package.json");
	if (fs.existsSync(pkgPath)) {
		try {
			const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));
			const deps = { ...pkg.dependencies, ...pkg.devDependencies };
			if (deps["next"]) return "nextjs";
			if (deps["express"]) return "express";
			if (deps["fastify"]) return "fastify";
			if (deps["@nestjs/core"]) return "nestjs";
			if (deps["nuxt"]) return "nuxt";
			if (deps["react"]) return "react";
			if (deps["vue"]) return "vue";
			if (deps["@angular/core"]) return "angular";
			if (deps["svelte"]) return "svelte";
		} catch { /* ignore */ }
	}
	if (fs.existsSync(path.join(dir, "requirements.txt"))) {
		try {
			const reqs = fs.readFileSync(path.join(dir, "requirements.txt"), "utf-8");
			if (reqs.includes("django")) return "django";
			if (reqs.includes("flask")) return "flask";
			if (reqs.includes("fastapi")) return "fastapi";
		} catch { /* ignore */ }
	}
	return undefined;
}

/**
 * Detects monorepo services by scanning workspace directories (apps/*, services/*, etc.).
 * This handles repos like turborepo/pnpm workspaces with apps/web, apps/backend, apps/mobile.
 */
export function detectMonorepoServices(appDir: string): MultiServiceConfig | null {
	console.log("detectMonorepoServices", appDir);

	const tooling = detectMonorepoTooling(appDir);
	if (!tooling.isMonorepo) return null;

	console.log("Monorepo detected:", tooling);

	const services: ServiceDefinition[] = [];

	// Scan known monorepo app roots (apps/, services/, etc.)
	for (const rootDir of MONOREPO_APP_ROOTS) {
		const rootPath = path.join(appDir, rootDir);
		if (!fs.existsSync(rootPath) || !fs.statSync(rootPath).isDirectory()) continue;

		try {
			const entries = fs.readdirSync(rootPath, { withFileTypes: true });
			for (const entry of entries) {
				if (!entry.isDirectory() || entry.name.startsWith(".")) continue;

				const servicePath = path.join(rootPath, entry.name);
				const relativePath = path.join(rootDir, entry.name).replace(/\\/g, "/");

				// Skip mobile-only directories
				if (isMobileOnlyDir(entry.name, servicePath)) {
					console.log(`Skipping mobile-only directory: ${relativePath}`);
					continue;
				}

				const language = detectLanguage(servicePath);
				if (!language) continue;

				// Skip shared packages that are libraries (no start/run script)
				if (rootDir === "packages") {
					const pkgPath = path.join(servicePath, "package.json");
					if (fs.existsSync(pkgPath)) {
						try {
							const pkg = JSON.parse(fs.readFileSync(pkgPath, "utf-8"));
							if (!pkg.scripts?.start && !pkg.scripts?.serve && !pkg.scripts?.dev) {
								console.log(`Skipping library package: ${relativePath}`);
								continue;
							}
						} catch { /* include it */ }
					}
				}

				const framework = detectFramework(servicePath);
				const port = framework === "nextjs" ? 3000 : getDefaultPort(language);

				services.push({
					name: entry.name,
					workdir: servicePath,
					language,
					port,
					relativePath,
					framework,
					build_context: appDir, // monorepo root is the build context
				});
			}
		} catch (error) {
			console.error(`Error scanning ${rootPath}:`, error);
		}
	}

	if (services.length > 0) {
		console.log(`Detected ${services.length} monorepo service(s):`, services.map(s => s.name));
		return {
			isMultiService: services.length > 1,
			services,
			hasDockerCompose: false,
			isMonorepo: true,
			packageManager: tooling.packageManager,
			monorepoRoot: appDir,
		};
	}

	return null;
}

/**
 * Algorithmically detects multiple services by looking for common patterns
 */
export function detectMultiServicePatterns(appDir: string): MultiServiceConfig | null {
	const services: ServiceDefinition[] = [];
	const commonServiceDirs = [
		"ui", "frontend", "web", "client",
		"api", "backend", "server",
		"app", "service"
	];

	// Check for multiple service directories
	const foundDirs: string[] = [];
	for (const dir of commonServiceDirs) {
		const dirPath = path.join(appDir, dir);
		if (fs.existsSync(dirPath) && fs.statSync(dirPath).isDirectory()) {
			// Skip mobile-only dirs
			if (isMobileOnlyDir(dir, dirPath)) continue;
			foundDirs.push(dir);
		}
	}

	// If we found multiple service directories, treat as multi-service
	if (foundDirs.length > 1) {
		for (const dir of foundDirs) {
			const serviceDir = path.join(appDir, dir);
			const language = detectLanguage(serviceDir);
			
			if (language) {
				const framework = detectFramework(serviceDir);
				services.push({
					name: dir,
					workdir: serviceDir,
					language,
					port: framework === "nextjs" ? 3000 : getDefaultPort(language),
					framework,
				});
			}
		}

		if (services.length > 1) {
			return {
				isMultiService: true,
				services,
				hasDockerCompose: false,
				isMonorepo: false,
			};
		}
	}

	// Check for multiple Dockerfiles
	const dockerfiles = findDockerfiles(appDir);
		if (dockerfiles.length > 1) {
			for (const dockerfile of dockerfiles) {
				const serviceName = extractServiceNameFromDockerfile(dockerfile);
				const dockerfileDir = path.dirname(dockerfile);
				const language = detectLanguage(dockerfileDir);

				if (language) {
					services.push({
						name: serviceName,
						workdir: dockerfileDir,
						language,
						dockerfile: path.basename(dockerfile),
						port: getDefaultPort(language)
					});
				}
			}

		if (services.length > 1) {
			return {
				isMultiService: true,
				services,
				hasDockerCompose: false,
				isMonorepo: false,
			};
		}
	}

	return null;
}

/**
 * Detects the programming language of a directory
 */
function detectLanguage(dir: string): string | undefined {
	if (fs.existsSync(path.join(dir, "package.json"))) return "node";
	if (fs.existsSync(path.join(dir, "requirements.txt"))) return "python";
	if (fs.existsSync(path.join(dir, "go.mod"))) return "go";
	if (fs.existsSync(path.join(dir, "pom.xml")) || fs.existsSync(path.join(dir, "build.gradle"))) return "java";
	if (fs.existsSync(path.join(dir, "Cargo.toml"))) return "rust";
	// Check for .NET projects
	if (globMatch(dir, "*.csproj") || globMatch(dir, "*.sln")) return "dotnet";
	if (fs.existsSync(path.join(dir, "composer.json"))) return "php";
	return undefined;
}

/**
 * Finds all Dockerfiles in a directory
 */
function findDockerfiles(dir: string): string[] {
	const dockerfiles: string[] = [];
	
	function search(currentDir: string, depth: number = 0) {
		if (depth > 3) return; // Limit search depth

		try {
			const entries = fs.readdirSync(currentDir);
			
			for (const entry of entries) {
				const fullPath = path.join(currentDir, entry);
				const stat = fs.statSync(fullPath);

				if (stat.isDirectory() && !entry.startsWith(".") && entry !== "node_modules") {
					search(fullPath, depth + 1);
				} else if (entry === "Dockerfile" || entry.startsWith("Dockerfile.")) {
					dockerfiles.push(fullPath);
				}
			}
		} catch (error) {
			// Ignore permission errors
		}
	}

	search(dir);
	return dockerfiles;
}

/**
 * Extracts service name from Dockerfile path
 */
function extractServiceNameFromDockerfile(dockerfilePath: string): string {
	const basename = path.basename(dockerfilePath);
	if (basename.startsWith("Dockerfile.")) {
		return basename.replace("Dockerfile.", "");
	}
	const dirname = path.basename(path.dirname(dockerfilePath));
	return dirname || "app";
}

/**
 * Checks if a service is a database service
 */
function isDatabaseService(serviceName: string, config: any): boolean {
	const dbKeywords = ["db", "database", "postgres", "mysql", "mssql", "mongodb", "redis", "sqlite"];
	const image = config.image || "";
	const serviceLower = serviceName.toLowerCase();
	
	return dbKeywords.some(keyword => 
		serviceLower.includes(keyword) || image.toLowerCase().includes(keyword)
	);
}

/**
 * Extracts port from docker-compose service config
 */
function extractPort(config: any): number | undefined {
	if (config.ports && Array.isArray(config.ports)) {
		const portMapping = config.ports[0];
		if (typeof portMapping === "string") {
			const match = portMapping.match(/:(\d+)/);
			return match ? parseInt(match[1]) : undefined;
		}
	}
	return undefined;
}

/**
 * Gets default port for a language
 */
function getDefaultPort(language: string): number {
	const portMap: Record<string, number> = {
		node: 3000,
		python: 8000,
		go: 8080,
		java: 8080,
		rust: 8080,
		dotnet: 5000,
		php: 8000
	};
	return portMap[language] || 8080;
}

/**
 * Simple glob matching helper
 */
function globMatch(dir: string, pattern: string): boolean {
	try {
		const files = fs.readdirSync(dir);
		const regex = new RegExp(pattern.replace("*", ".*"));
		return files.some(file => regex.test(file));
	} catch {
		return false;
	}
}

/**
 * Main function to detect multi-service configuration
 */
export function detectMultiService(appDir: string): MultiServiceConfig {
	// First, try docker-compose
	const composeConfig = detectDockerCompose(appDir);
	if (composeConfig) {
		return composeConfig;
	}

	// Then, try monorepo detection (pnpm workspaces, turborepo, nx, lerna)
	const monorepoConfig = detectMonorepoServices(appDir);
	if (monorepoConfig) {
		return monorepoConfig;
	}

	// Then, try algorithmic detection
	const patternConfig = detectMultiServicePatterns(appDir);
	if (patternConfig) {
		return patternConfig;
	}

	// Single service
	return {
		isMultiService: false,
		services: [],
		hasDockerCompose: false,
		isMonorepo: false,
	};
}

