export function formatTimestamp(isoString: string | undefined): string {
	if (!isoString) {
		return "Never";
	}

	const date = new Date(isoString);
	const now = new Date();

	// Use user's timezone automatically via Intl.DateTimeFormat
	const isSameDay = date.toDateString() === now.toDateString();

	const yesterday = new Date(now);
	yesterday.setDate(now.getDate() - 1);
	const isYesterday = date.toDateString() === yesterday.toDateString();

	const timeFormatter = new Intl.DateTimeFormat(undefined, {
		hour: 'numeric',
		minute: '2-digit',
		hour12: true,
		timeZoneName: 'short',
	});

	if (isSameDay) {
		return `Today at ${timeFormatter.format(date)}`;
	} else if (isYesterday) {
		return `Yesterday at ${timeFormatter.format(date)}`;
	} else {
		const dateFormatter = new Intl.DateTimeFormat(undefined, {
			year: 'numeric',
			month: 'short',
			day: 'numeric',
			hour: 'numeric',
			minute: '2-digit',
			hour12: true,
			timeZoneName: 'short',
		});
		return dateFormatter.format(date);
	}
}

export function formatDeploymentTargetName(target: DeploymentTarget | undefined): string {
	if (!target) return "Unknown";

	const targetNames: Record<DeploymentTarget, string> = {
		'ec2': 'AWS EC2',
		'cloud_run': 'Google Cloud Run',
	};

	return targetNames[target] || target;
}

/** Sanitize a string for use as a DNS subdomain (lowercase, a-z0-9-, max 63 chars). Exported for Vercel DNS API. */
export function sanitizeSubdomain(s: string): string {
	const out = s
		.toLowerCase()
		.replace(/[^a-z0-9-]/g, "-")
		.replace(/-+/g, "-")
		.replace(/^-|-$/g, "")
		.slice(0, 63);
	return out || "app";
}

const deploymentDomain = () =>
	(typeof process !== "undefined" && process.env.NEXT_PUBLIC_DEPLOYMENT_DOMAIN?.trim()) || "";

/** URL to show for "Visit" / "Open link". Prefers stored custom_url; else *.NEXT_PUBLIC_DEPLOYMENT_DOMAIN when set; else deployUrl. */
export function getDeploymentDisplayUrl(d: { deployUrl?: string | null; custom_url?: string | null; service_name?: string; id?: string }): string | undefined {
	const custom = (d.custom_url ?? "").trim();
	if (custom) return custom;
	const base = deploymentDomain();
	if (base) {
		const sub = sanitizeSubdomain((d.service_name ?? d.id ?? "app").toString());
		return `https://${sub}.${base.replace(/^https?:\/\//, "").replace(/\/.*$/, "")}`;
	}
	return d.deployUrl ?? undefined;
}

/** When using NEXT_PUBLIC_DEPLOYMENT_DOMAIN, this is the URL to point DNS to in Vercel (CNAME target). */
export function getDeploymentDnsTarget(d: { deployUrl?: string | null }): string | undefined {
	if (!deploymentDomain()) return undefined;
	const url = d.deployUrl?.trim();
	if (!url) return undefined;
	// Return host only for CNAME (user can copy or use as target)
	try {
		const u = new URL(url.startsWith("http") ? url : `https://${url}`);
		return u.hostname;
	} catch {
		return url;
	}
}


export function parseEnvVarsToDisplay(envVarsString: string = "") {
	const result = envVarsString
		.split(/\r?\n/)
		.map(pair => pair.trim())
		.filter(pair => pair.includes("="))
		.map(pair => {
			const [key, ...rest] = pair.split("=")
			return { name: key, value: rest.join("=") }
		})

	return result;
}

/** Legacy helper, converted to use newlines for consistency. */
export function parseEnvVarsToStore(envString: string): string {
	return envString
		.split(/\r?\n/)
		.map(line => line.trim())
		.filter(line => line && !line.startsWith("#"))
		.join("\n");
}

/** Parse newline-separated .env-style content (e.g. paste or uploaded file) into key/value entries. */
export function parseEnvLinesToEntries(text: string): { name: string; value: string }[] {
	return text
		.split(/\r?\n/)
		.map((line) => line.trim())
		.filter((line) => line && !line.startsWith("#"))
		.map((line) => {
			const eq = line.indexOf("=");
			if (eq === -1) return { name: line, value: "" };
			return { name: line.slice(0, eq).trim(), value: line.slice(eq + 1).trim() };
		})
		.filter((e) => e.name.length > 0);
}

/** Build env vars string from entries (newline-separated KEY=value) for form/deploy. */
export function buildEnvVarsString(entries: { name: string; value: string }[]): string {
	return entries
		.filter((e) => e.name.trim().length > 0)
		.map((e) => `${e.name.trim()}=${e.value}`)
		.join("\n");
}

export function readDockerfile(file: File): Promise<string> {
	return new Promise((resolve, reject) => {
		const reader = new FileReader();

		reader.onload = () => {
			resolve(reader.result as string);
		};

		reader.onerror = () => {
			reject(reader.error);
		};

		reader.readAsText(file); // 👈 Reads as plain UTF-8 text
	});
}


export function formatLogTimestamp(isoTimestamp: string) {
	const date = new Date(isoTimestamp);

	// Format: DD MMM YYYY, hh:mm AM/PM
	return date.toLocaleString('en-IN', {
		day: '2-digit',
		month: 'short',
		year: 'numeric',
		hour: '2-digit',
		minute: '2-digit',
		hour12: true,
	});
}


export function extractDeployConfigFromAI(responseObj: { response: string }): SDArtifactsResponse | null {
	try {
		const cleaned = responseObj.response.replace(/\/\/.*$/gm, "").trim();

		// Parse the cleaned string
		const config = JSON.parse(cleaned);

		return config;
	} catch (error) {
		console.error("Failed to parse AI response:", error);
		return null;
	}
}

export function sanitizeAndParseAIResponse(raw: any): SDArtifactsResponse | null {
	try {
		let jsonStr = "";

		// Step 1: If the AI returned { response: "..." }, extract it
		if (typeof raw === "object" && typeof raw.response === "string") {
			jsonStr = raw.response;
		} else if (typeof raw === "string") {
			jsonStr = raw;
		} else {
			jsonStr = JSON.stringify(raw);
		}

		// Step 2: Remove comments (// ...)
		jsonStr = jsonStr.replace(/\/\/.*$/gm, "");

		// Step 3: Remove trailing commas before closing brackets/braces
		jsonStr = jsonStr.replace(/,\s*([}\]])/g, "$1");

		// Step 4: Trim non-JSON content (attempt to isolate the first valid object)
		const firstBrace = jsonStr.indexOf("{");
		const lastBrace = jsonStr.lastIndexOf("}");
		if (firstBrace === -1 || lastBrace === -1) throw new Error("No JSON object found");

		const possibleJson = jsonStr.slice(firstBrace, lastBrace + 1);

		// Step 5: Parse
		return JSON.parse(possibleJson);

	} catch (err) {
		console.error("❌ Failed to sanitize/parse AI response:", err);
		return null;
	}
}

/** Build a serializable config snapshot for deployment history (no File/binary). */
export function configSnapshotFromDeployConfig(config: DeployConfig | null): Record<string, unknown> {
	if (!config) return {};
	return { ...config } as Record<string, unknown>;
}


export function normalizeRepoUrl(url: string): string {
	return url?.replace(/\.git$/, "").toLowerCase();
}

export function getDeploymentForService(
	deployments: DeployConfig[],
	repoUrl: string,
	serviceName: string,
	repoName: string
): DeployConfig | undefined {
	const matches: DeployConfig[] = [];

	for (const d of deployments) {
		if (d.repoName !== repoName && normalizeRepoUrl(d.url) !== normalizeRepoUrl(repoUrl)) continue;

		const dbServiceName = d.serviceName || "";
		const isExactHit = dbServiceName.toLowerCase() === serviceName.toLowerCase();
		const isRepoLevel = dbServiceName === "." || dbServiceName.toLowerCase() === repoName.toLowerCase();

		if (isExactHit || isRepoLevel) {
			matches.push(d);
		}
	}

	if (matches.length === 0) return undefined;

	const statusRank = (status?: string) => {
		if (status === "running") return 3;
		if (status === "paused" || status === "stopped") return 2;
		if (status === "didnt_deploy") return 1;
		return 0;
	};

	return matches.sort((a, b) => {
		const statusRankA = statusRank(a.status);
		const statusRankB = statusRank(b.status);
		const statusDelta = statusRankB - statusRankA;
		if (statusDelta !== 0) return statusDelta;
		const aTime = new Date(a.lastDeployment ?? 0).getTime();
		const bTime = new Date(b.lastDeployment ?? 0).getTime();
		return bTime - aTime;
	})[0];
}

export function countDeployedServicesForRepo(
	repoRecord: Pick<RepoServicesRecord, "repo_url" | "repo_name" | "services">,
	deployments: DeployConfig[]
): number {
	const services = repoRecord.services ?? [];
	if (services.length === 0) return 0;

	return services.reduce((count, svc) => {
		const deployment = getDeploymentForService(
			deployments,
			repoRecord.repo_url,
			svc.name,
			repoRecord.repo_name
		);
		return deployment && deployment.status !== "didnt_deploy" ? count + 1 : count;
	}, 0);
}

export function isDeploymentDisabled(deployment: DeployConfig): boolean {
	if (!deployment) return true;

	const scanResults = deployment.scanResults;
	const scanResultsTyped = (scanResults && typeof scanResults === "object" && "dockerfiles" in scanResults)
		? (scanResults as SDArtifactsResponse)
		: null;
	const hasDockerfile = !!(scanResultsTyped?.dockerfiles && Object.keys(scanResultsTyped.dockerfiles).length > 0);
	const hasNginxConf = !!scanResultsTyped?.nginx_conf?.trim();

	return !(hasDockerfile && hasNginxConf);
}

const VERCEL_API_BASE = "https://api.vercel.com";

function getDeployUrlHostname(deployUrl: string): string | null {
	const url = deployUrl.trim();
	try {
		const u = new URL(url.startsWith("http") ? url : `https://${url}`);
		return u.hostname;
	} catch {
		return null;
	}
}

export type AddVercelDnsResult =
	| { success: true; customUrl: string }
	| { success: false; error: string };

export type DeleteVercelDnsResult =
	| { success: true; deletedCount: number }
	| { success: false; error: string };

export type AddVercelDnsOptions = {
	/**
	 * Used to decide whether EC2 should use an A record (IP) instead of a CNAME (hostname).
	 * If omitted, we fall back to choosing A when the deployUrl hostname is an IPv4 address.
	 */
	deploymentTarget?: string | null;
	/**
	 * If present, treat conflicts as an update for the same deployment:
	 * delete the previous record (same subdomain) and recreate it with the new target.
	 */
	previousCustomUrl?: string | null;
};

export type DeleteVercelDnsOptions = {
	customUrl?: string | null;
	serviceName?: string | null;
};

function isValidIpv4(host: string): boolean {
	const parts = host.trim().split(".");
	if (parts.length !== 4) return false;
	return parts.every((p) => {
		if (!/^\d+$/.test(p)) return false;
		const n = Number(p);
		return n >= 0 && n <= 255;
	});
}

function getSubdomainFromCustomUrl(customUrl: string, baseDomain: string): string | null {
	try {
		const u = new URL(customUrl.startsWith("http") ? customUrl : `https://${customUrl}`);
		const host = u.hostname.toLowerCase();
		const base = baseDomain.toLowerCase();
		if (!host.endsWith(`.${base}`)) return null;
		const prefix = host.slice(0, -(base.length + 1)); // remove ".baseDomain"
		// Only support a single-label subdomain (what we create)
		if (!prefix || prefix.includes(".")) return null;
		return prefix;
	} catch {
		return null;
	}
}


function sanitizeSubdomain(s: string): string {
		const out = s
			.toLowerCase()
			.replace(/[^a-z0-9-]/g, "-")
			.replace(/-+/g, "-")
			.replace(/^-|-$/g, "")
			.slice(0, 63);
		return out || "app";
	}

/**
 * Add or update a DNS record in Vercel DNS for the given deploy URL and service name.
 * Call from backend (e.g. handleDeploy) after a successful deploy.
 * Returns success: false with error message if not configured or API fails.
 */
export async function addVercelDnsRecord(
	deployUrl: string,
	serviceName: string,
	options?: AddVercelDnsOptions
): Promise<AddVercelDnsResult> {
	const token = (process.env.VERCEL_TOKEN || "").trim();
	const domain = (
		process.env.VERCEL_DOMAIN ||
		process.env.NEXT_PUBLIC_DEPLOYMENT_DOMAIN ||
		""
	).trim();

	if (!token || !domain) {
		return {
			success: false,
			error:
				"Vercel DNS not configured. Set VERCEL_TOKEN and VERCEL_DOMAIN (or NEXT_PUBLIC_DEPLOYMENT_DOMAIN).",
		};
	}

	const trimmedUrl = typeof deployUrl === "string" ? deployUrl.trim() : "";
	const name = typeof serviceName === "string" ? serviceName : "app";
	if (!trimmedUrl) {
		return { success: false, error: "deployUrl is required" };
	}

	const targetHost = getDeployUrlHostname(trimmedUrl);
	if (!targetHost) {
		return { success: false, error: "Invalid deployUrl" };
	}

	const baseDomain = domain.replace(/^https?:\/\//, "").replace(/\/.*$/, "");
	const previousSubdomain =
		typeof options?.previousCustomUrl === "string" && options.previousCustomUrl.trim()
			? getSubdomainFromCustomUrl(options.previousCustomUrl.trim(), baseDomain)
			: null;
	const baseSubdomain = sanitizeSubdomain(name);
	const subdomain = previousSubdomain || baseSubdomain;

	// EC2 targets are commonly raw IPv4 addresses → use an A record.
	const shouldUseARecord = isValidIpv4(targetHost);
	const recordType: "A" | "CNAME" = shouldUseARecord ? "A" : "CNAME";

	const headers: Record<string, string> = {
		Authorization: `Bearer ${token}`,
		"Content-Type": "application/json",
	};

	const createUrl = new URL(`${VERCEL_API_BASE}/v2/domains/${encodeURIComponent(baseDomain)}/records`);
	const listUrl = new URL(`${VERCEL_API_BASE}/v4/domains/${encodeURIComponent(baseDomain)}/records`);

	async function listRecords(): Promise<any[]> {
		const listRes = await fetch(listUrl.toString(), { headers });
		if (!listRes.ok) return [];
		const listData = await listRes.json();
		return Array.isArray(listData.records) ? listData.records : Array.isArray(listData) ? listData : [];
	}

	function recordNameMatches(r: { name?: string }, wanted: string): boolean {
		// Vercel sometimes represents apex as "" (we never use apex here, but keep parity with old code)
		return r?.name === wanted || (r?.name === "" && wanted === baseDomain);
	}

	function getRecordId(r: any): string | null {
		return (r?.id ?? r?.uid) ? String(r.id ?? r.uid) : null;
	}

	async function deleteRecordById(recordId: string): Promise<boolean> {
		const delUrl = `${VERCEL_API_BASE}/v1/domains/records/${encodeURIComponent(recordId)}`;
		const delRes = await fetch(delUrl, { method: "DELETE", headers });
		return delRes.ok;
	}

	async function createRecord(recordName: string): Promise<{ ok: true; customUrl: string } | { ok: false; status: number; errMsg: string; errBody: string }> {
		const res = await fetch(createUrl.toString(), {
			method: "POST",
			headers,
			body: JSON.stringify({
				type: recordType,
				name: recordName,
				value: targetHost,
				ttl: 60,
				comment: "SmartDeploy",
			}),
		});
		if (res.ok) {
			return { ok: true, customUrl: `https://${recordName}.${baseDomain}` };
		}
		const errBody = await res.text();
		let errJson: { error?: { message?: string } } = {};
		try {
			errJson = JSON.parse(errBody);
		} catch {
			// ignore
		}
		return {
			ok: false,
			status: res.status,
			errMsg: (errJson.error?.message || "").toLowerCase(),
			errBody,
		};
	}

	try {
		// First attempt: create record for the preferred subdomain (previousCustomUrl subdomain if present)
		const first = await createRecord(subdomain);
		if (first.ok) return { success: true, customUrl: first.customUrl };

		const isConflict =
			first.status === 400 ||
			first.status === 409 ||
			first.errMsg.includes("already exists");

		if (!isConflict) {
			return { success: false, error: "Vercel API error" };
		}

		// Conflict path:
		// - If this deployment already had a custom URL, treat as update:
		//   delete existing record(s) for that subdomain and recreate with new target.
		//   Unless the existing record already points to the same target (e.g. redeploy with same custom_url) → skip delete/recreate.
		// - Otherwise, create a unique subdomain by appending -{random} and retry.
		const records = await listRecords();

		if (previousSubdomain) {
			const existing = records.filter((r: any) => recordNameMatches(r, subdomain));
			const alreadyPointsToTarget = existing.some(
				(r: any) => (r?.value ?? "").toString().trim().toLowerCase() === targetHost.toLowerCase()
			);
			if (alreadyPointsToTarget) {
				return { success: true, customUrl: `https://${subdomain}.${baseDomain}` };
			}
			for (const r of existing) {
				const id = getRecordId(r);
				if (id) {
					await deleteRecordById(id);
				}
			}
			const recreated = await createRecord(subdomain);
			if (recreated.ok) return { success: true, customUrl: recreated.customUrl };
			return { success: false, error: "Failed to recreate DNS record after deleting the previous one" };
		}

		// New deployment + name conflict: try suffixed names
		for (let attempt = 0; attempt < 6; attempt++) {
			const rand = Math.floor(1000 + Math.random() * 9000);
			const candidate = sanitizeSubdomain(`${baseSubdomain}-${rand}`);

			// Avoid re-trying names we already have in the domain
			const alreadyTaken = records.some((r: any) => recordNameMatches(r, candidate));
			if (alreadyTaken) continue;

			const created = await createRecord(candidate);
			if (created.ok) return { success: true, customUrl: created.customUrl };
		}

		return { success: false, error: `DNS name '${baseSubdomain}' already exists; failed to find an available suffix` };
	} catch (error) {
		const message =
			error instanceof Error ? error.message : "Failed to add DNS record";
		console.error("Vercel addVercelDnsRecord error:", error);
		return { success: false, error: message };
	}
}

/**
 * Delete Vercel DNS record(s) for a deployment using its custom URL or service name.
 * Returns deletedCount=0 if no matching records exist.
 */
export async function deleteVercelDnsRecord(
	options?: DeleteVercelDnsOptions
): Promise<DeleteVercelDnsResult> {
	const token = (process.env.VERCEL_TOKEN || "").trim();
	const domain = (
		process.env.VERCEL_DOMAIN ||
		process.env.NEXT_PUBLIC_DEPLOYMENT_DOMAIN ||
		""
	).trim();

	if (!token || !domain) {
		return {
			success: false,
			error:
				"Vercel DNS not configured. Set VERCEL_TOKEN and VERCEL_DOMAIN (or NEXT_PUBLIC_DEPLOYMENT_DOMAIN).",
		};
	}

	const baseDomain = domain.replace(/^https?:\/\//, "").replace(/\/.*$/, "");
	const customUrl = (options?.customUrl || "").trim();
	const serviceName = (options?.serviceName || "").trim();

	let subdomain: string | null = null;
	if (customUrl) {
		subdomain = getSubdomainFromCustomUrl(customUrl, baseDomain);
	}
	if (!subdomain && serviceName) {
		subdomain = sanitizeSubdomain(serviceName);
	}
	if (!subdomain) {
		return { success: false, error: "Unable to determine DNS record name to delete." };
	}

	const headers: Record<string, string> = {
		Authorization: `Bearer ${token}`,
		"Content-Type": "application/json",
	};
	const listUrl = new URL(`${VERCEL_API_BASE}/v4/domains/${encodeURIComponent(baseDomain)}/records`);

	async function listRecords(): Promise<any[]> {
		const listRes = await fetch(listUrl.toString(), { headers });
		if (!listRes.ok) return [];
		const listData = await listRes.json();
		return Array.isArray(listData.records) ? listData.records : Array.isArray(listData) ? listData : [];
	}

	function recordNameMatches(r: { name?: string }, wanted: string): boolean {
		return r?.name === wanted || (r?.name === "" && wanted === baseDomain);
	}

	function getRecordId(r: any): string | null {
		return (r?.id ?? r?.uid) ? String(r.id ?? r.uid) : null;
	}

	async function deleteRecordById(recordId: string): Promise<boolean> {
		const delUrl = `${VERCEL_API_BASE}/v2/domains/${encodeURIComponent(baseDomain)}/records/${encodeURIComponent(recordId)}`;
		const delRes = await fetch(delUrl, { method: "DELETE", headers });
		return delRes.ok;
	}

	try {
		const records = await listRecords();
		const toDelete = records.filter((r: any) => recordNameMatches(r, subdomain as string));
		if (toDelete.length === 0) return { success: true, deletedCount: 0 };

		let deletedCount = 0;
		for (const r of toDelete) {
			const id = getRecordId(r);
			if (!id) continue;
			const ok = await deleteRecordById(id);
			if (ok) deletedCount += 1;
		}

		return { success: true, deletedCount };
	} catch (error) {
		const message = error instanceof Error ? error.message : "Failed to delete DNS record";
		console.error("Vercel deleteVercelDnsRecord error:", error);
		return { success: false, error: message };
	}
}

import { DeployStep } from "../app/types";

/**
 * Creates a simple WebSocket logger function that sends messages to the client
 * @param ws - WebSocket connection
 * @returns A send function that logs messages to the WebSocket
 */
export function createWebSocketLogger(ws: any) {
	return (msg: string, id: string) => {
		const trackedSend = ws ? (ws as any).__deploySend : undefined;
		if (trackedSend && typeof trackedSend === "function") {
			trackedSend(msg, id);
			return;
		}

		if (ws && ws.readyState === ws.OPEN) {
			const object = {
				type: 'deploy_logs',
				payload: { id, msg, time: new Date().toISOString() }
			};
			ws.send(JSON.stringify(object));
		}
	};
}

/**
 * Creates a WebSocket logger function that also tracks deployment steps.
 * Includes duplicate suppression: consecutive identical messages within 5s
 * are collapsed into a single entry with a repeat counter.
 */
export function createDeployStepsLogger(
	ws: any,
	deploySteps: DeployStep[],
	options?: {
		onStepsChange?: (steps: DeployStep[]) => void;
		broadcast?: (id: string, msg: string) => void;
	}
) {
	const { onStepsChange, broadcast } = options ?? {};

	// Dedup state: track last message per step to collapse rapid repeats
	const lastMsg = new Map<string, { text: string; count: number; ts: number }>();
	const DEDUP_WINDOW_MS = 5000;

	return (msg: string, id: string) => {
		const now = new Date().toISOString();
		const nowMs = Date.now();
		const trimmed = msg.trim();

		// Duplicate suppression: skip identical consecutive messages within window
		const prev = lastMsg.get(id);
		if (prev && prev.text === trimmed && nowMs - prev.ts < DEDUP_WINDOW_MS) {
			prev.count++;
			prev.ts = nowMs;
			return;
		}

		// Flush pending repeat count from previous message before moving on
		if (prev && prev.count > 1) {
			const repeatNote = `  [repeated x${prev.count}]`;
			const lastStep = deploySteps.find(s => s.id === id);
			if (lastStep) lastStep.logs.push(repeatNote);
			broadcast?.(id, repeatNote);
		}
		lastMsg.set(id, { text: trimmed, count: 1, ts: nowMs });

		let stepIndex = deploySteps.findIndex(s => s.id === id);
		if (stepIndex === -1) {
			deploySteps.push({ id, label: msg, logs: [msg], status: 'in_progress', startedAt: now });
			stepIndex = deploySteps.length - 1;
		} else {
			deploySteps[stepIndex].logs.push(msg);
			if (msg.startsWith('✅')) {
				deploySteps[stepIndex].status = 'success';
				deploySteps[stepIndex].endedAt = now;
			} else if (msg.startsWith('❌')) {
				deploySteps[stepIndex].status = 'error';
				deploySteps[stepIndex].endedAt = now;
			}
		}

		onStepsChange?.(deploySteps);
		broadcast?.(id, msg);
	};
}

