import { spawn } from "child_process";

/**
 * On Windows, the terminal often uses a codec that can't display Unicode (e.g. ✓).
 * Sanitize so process.stdout.write doesn't throw 'charmap' codec errors.
 */
function safeForWindowsConsole(str: string): string {
	if (process.platform !== "win32") return str;
	// Replace common Unicode symbols with ASCII equivalents; strip other non-ASCII
	return str
		.replace(/\u2713/g, "[OK]")
		.replace(/\u2714/g, "[OK]")
		.replace(/\u274C/g, "[X]")
		.replace(/\u26A0/g, "[!]")
		.replace(/[^\x00-\x7F]/g, "?");
}

export async function runCommandLive(cmd: string, args: string[]) {
	return new Promise<void>((resolve, reject) => {
		const child = spawn(cmd, args, { stdio: "inherit", shell: true });

		child.on("exit", (code) => {
			if (code === 0) resolve();
			else reject(new Error(`${cmd} ${args.join(" ")} exited with code ${code}`));
		});
	});
}

export async function runCommandLiveWithOutput(cmd: string, args: string[]): Promise<string> {
	return new Promise((resolve, reject) => {
		let output = "";
		const child = spawn(cmd, args, { shell: true });

		child.stdout.on("data", (data) => {
			const str = data.toString('utf8');
			output += str;
			process.stdout.write(safeForWindowsConsole(str)); // Live stream
		});

		child.stderr.on("data", (data) => {
			const str = data.toString('utf8');
			output += str;
			process.stderr.write(safeForWindowsConsole(str));
		});

		child.on("exit", (code) => {
			if (code === 0) {
				resolve(output);
			} else {
				reject(new Error(`${cmd} ${args.join(" ")} exited with code ${code}\n${output}`));
			}
		});
	});
}


export async function runCommandLiveWithWebSocket(
	cmd: string,
	args: string[],
	ws?: WebSocket,
	id?: string,
	opts?: { cwd?: string; env?: NodeJS.ProcessEnv; send?: (msg: string, stepId: string) => void }
): Promise<string> {
	return new Promise((resolve, reject) => {
		let output = "";
		let stderrOutput = "";
		// Create isolated environment - don't inherit parent NODE_PATH or other module resolution paths
		const isolatedEnv = {
			...process.env,
			...opts?.env,
			// Clear NODE_PATH to prevent module resolution from parent directories
			NODE_PATH: undefined,
			// Ensure we use the cwd's node_modules
			...(opts?.cwd && {
				// Set PWD to ensure relative paths resolve correctly
				PWD: opts.cwd
			})
		};
		const child = spawn(cmd, args, { 
			shell: true, 
			cwd: opts?.cwd,
			env: isolatedEnv
		});

		const sendWS = (msg: string) => {
			const trackedSend = id
				? opts?.send ?? (ws as any)?.__deploySend
				: undefined;

			if (trackedSend && id) {
				trackedSend(msg, id);
				return;
			}

			if (ws && ws.readyState === ws.OPEN) {
				const object = {
					type: 'deploy_logs',
					payload: {
						id,
						msg,
						time: new Date().toISOString()
					}
				};
				ws.send(JSON.stringify(object));
			}
		};

		sendWS(`🔄 Running: ${cmd} ${args.join(" ")}`);

		child.stdout.on("data", (data) => {
			const str = data.toString('utf8');
			output += str;
			sendWS(str);
		});

		child.stderr.on("data", (data) => {
			const err = data.toString('utf8');
			stderrOutput += err;
			sendWS(err);
		});

		child.on("exit", (code) => {
			if (code === 0) {
				sendWS(`Done: ${cmd}`);
				resolve(output);
			}
			else {
				// Include the last portion of stderr in the error message so callers
				// (and deployment history) capture the actual failure reason, not just the exit code.
				const stderrTail = stderrOutput.trim().slice(-1000);
				const errorDetail = stderrTail ? `\n${stderrTail}` : '';
				sendWS(`Failed: ${cmd} ${args.join(" ")} (exit ${code})`);
				reject(new Error(`${cmd} ${args.join(" ")} exited with code ${code}${errorDetail}`));
			}
		});

		child.on("error", (err) => {
			sendWS(`❌ Process error: ${err.message}`);
			reject(err);
		});
	});
}

import dotenv from "dotenv";
dotenv.config();

import { WebSocketServer } from "ws";
import http from "http";
import { deploy, serviceLogs } from "./websocket-types";
import * as deployLogsStore from "./lib/deployLogsStore";
import { dbHelper } from "./db-helper";

async function getSnapshotFromHistory(repoName: string, serviceName: string, userID?: string) {
	let resolvedUserId = userID;
	let currentDeployment: any = null;
	if (!resolvedUserId) {
		const deploymentResponse = await dbHelper.getDeployment(repoName, serviceName);
		currentDeployment = deploymentResponse.deployment;
		resolvedUserId = currentDeployment?.ownerID;
	} else {
		// Also fetch the current deployment to check its status
		const deploymentResponse = await dbHelper.getDeployment(repoName, serviceName);
		currentDeployment = deploymentResponse.deployment;
	}
	if (!resolvedUserId) return null;

	// If the current deployment is in "didnt_deploy" status (fresh/draft), don't show old history
	if (currentDeployment?.status === "didnt_deploy") {
		return null;
	}

	const historyResponse = await dbHelper.getDeploymentHistory(repoName, serviceName, resolvedUserId);
	if (historyResponse.error || !historyResponse.history || historyResponse.history.length === 0) {
		return null;
	}

	const latest = historyResponse.history[0];
	// Preserve actual failure details from the deploy steps instead of generic message
	let errorDetail: string | null = null;
	if (!latest.success) {
		const errorSteps = (latest.steps ?? []).filter((s: any) => s.status === "error");
		const errorLogs = errorSteps.flatMap((s: any) => (s.logs || []).filter((l: string) => l.includes("❌") || l.toLowerCase().includes("error") || l.toLowerCase().includes("failed")));
		errorDetail = errorLogs.length > 0 ? errorLogs.slice(-3).join("\n") : "Deployment failed";
	}
	return {
		steps: latest.steps ?? [],
		status: (latest.success ? "success" : "error") as "success" | "error",
		error: errorDetail,
	};
}

// Setup HTTP server to attach WebSocket to
const server = http.createServer();
const wss = new WebSocketServer({ server });
const port = Number(process.env.WS_PORT) || 4001;

function sendDeployComplete(ws: any, success: boolean, error?: string) {
	if (ws?.readyState === 1) {
		ws.send(JSON.stringify({
			type: "deploy_complete",
			payload: { success, deployUrl: null, error: error ?? null, time: new Date().toISOString() },
		}));
	}
}

wss.on("connection", (ws) => {
	console.log("Client connected");

	ws.on("message", async (data) => {
		try {
			const response = JSON.parse(data.toString());
			const type = response.type;

			switch (type) {
				case "deploy":
					try {
						await deploy(response.payload, ws);
					} catch (err: any) {
						console.error("Deploy error:", err);
						sendDeployComplete(ws, false, err?.message ?? "Deployment failed");
					}
					break;
				case "service_logs":
					serviceLogs(response.payload, ws);
					break;
				case "get_deploy_logs": {
					const { repoName, serviceName, userID } = response.payload ?? {};
					if (!repoName || !serviceName) {
						if (ws?.readyState === 1) {
							ws.send(JSON.stringify({ type: "deploy_logs_snapshot", payload: { error: "repoName and serviceName required", time: new Date().toISOString() } }));
						}
						break;
					}
					let snapshot = deployLogsStore.getSnapshot(userID, repoName, serviceName);
					if (!snapshot) {
						snapshot = await getSnapshotFromHistory(repoName, serviceName, userID);
					}
					const time = new Date().toISOString();
					if (snapshot) {
						if (ws?.readyState === 1) {
							ws.send(JSON.stringify({ type: "deploy_logs_snapshot", payload: { ...snapshot, time } }));
						}
						deployLogsStore.addSubscriber(userID, repoName, serviceName, ws);
					} else if (ws?.readyState === 1) {
						ws.send(JSON.stringify({
							type: "deploy_logs_snapshot",
							payload: { steps: [], status: "not-started", error: null, time },
						}));
					}
					break;
				}
				default:
					break;
			}
		} catch (err: any) {
			// JSON parse error or other sync error: send structured deploy_complete so client can show it
			sendDeployComplete(ws, false, err?.message ?? "Request failed");
		}
	});

	ws.on("close", () => {
		console.log("Client disconnected");
		deployLogsStore.removeSubscriberFromAll(ws);
	});
});

// When the process is about to crash, notify connected clients so they can show "connection lost"
function broadcastDeployFailed(reason: string) {
	const payload = JSON.stringify({
		type: "deploy_complete",
		payload: { success: false, deployUrl: null, error: reason, time: new Date().toISOString() },
	});
	wss.clients.forEach((client) => {
		if (client.readyState === 1) client.send(payload);
	});
}

server.listen(port, () => {
	console.log(`WebSocket server running on ws://localhost:${port}`);
});

// Log uncaught exceptions and rejections, but don't broadcast to clients
// These aren't necessarily deployment failures
process.on("uncaughtException", (err) => {
	console.error("Uncaught exception:", err);
});

process.on("unhandledRejection", (reason) => {
	console.error("Unhandled rejection:", reason);
});

import { DeployConfig, DeployStep, EC2Details } from "./app/types";
import config from "./config";
import { getInitialLogs } from "./gcloud-logs/getInitialLogs";
import { streamLogs } from "./gcloud-logs/streamLogs";
import { handleDeploy } from "./lib/handleDeploy";
import { dbHelper } from "./db-helper";
import { getInitialEc2ServiceLogs, streamEc2ServiceLogs } from "./lib/aws/ec2ServiceLogs";
import * as deployLogsStore from "./lib/deployLogsStore";

export async function deploy(payload: { deployConfig: DeployConfig; token: string; userID?: string }, ws: any) {
	const {
		deployConfig,
		token,
		userID,
	}: { deployConfig: DeployConfig; token: string; userID?: string } = payload;

	const repoName = deployConfig.repoName;
	const serviceName = deployConfig.serviceName;
	deployLogsStore.createEntry(userID, repoName, serviceName, ws);

	const options = {
		onStepsChange: (steps: DeployStep[]) => {
			deployLogsStore.updateSteps(userID, repoName, serviceName, steps);
		},
		broadcast: (id: string, msg: string) => {
			deployLogsStore.broadcastLog(userID, repoName, serviceName, id, msg);
		},
	};

	try {
		await handleDeploy(deployConfig, token, ws, userID, options);
		deployLogsStore.setStatus(userID, repoName, serviceName, "success");
	} catch (err: any) {
		deployLogsStore.setStatus(userID, repoName, serviceName, "error", err?.message ?? "Deployment failed");
		throw err;
	}
}

export async function serviceLogs(payload: { serviceName?: string; repoName?: string }, ws: any) {
	const serviceName = payload?.serviceName?.trim();
	const repoName = payload?.repoName?.trim();

	if (!serviceName && !repoName) {
		if (ws?.readyState === ws?.OPEN) {
			ws.send(JSON.stringify({ type: "initial_logs", payload: { logs: [] } }));
		}
		return;
	}

	let deployConfig: DeployConfig | undefined;
	if (repoName && serviceName) {
		const deployment = await dbHelper.getDeployment(repoName, serviceName);
		if (deployment.deployment) {
			deployConfig = deployment.deployment;
		}
	}

	if (deployConfig?.status !== "running") return;

	if (deployConfig?.ec2 && typeof deployConfig.ec2 === "object") {
		const ec2Details = deployConfig.ec2 as EC2Details;
		const region = deployConfig.awsRegion || config.AWS_REGION;
		const logs = await getInitialEc2ServiceLogs({
			instanceId: ec2Details.instanceId,
			region,
			serviceName,
			limit: 200,
		});

		if (ws?.readyState === ws?.OPEN) {
			ws.send(
				JSON.stringify({
					type: "initial_logs",
					payload: { logs },
				})
			);
		}

		streamEc2ServiceLogs({
			instanceId: deployConfig.ec2.instanceId,
			region,
			serviceName,
			ws,
		});
		return;
	}

	// Only stream gcloud logs for Cloud Run deployments
	if (!serviceName || deployConfig?.deploymentTarget !== "cloud_run") {
		if (ws?.readyState === ws?.OPEN) {
			ws.send(JSON.stringify({ type: "initial_logs", payload: { logs: [] } }));
		}
		return;
	}

	const logs = await getInitialLogs(serviceName);
	if (ws?.readyState === ws?.OPEN) {
		ws.send(
			JSON.stringify({
				type: "initial_logs",
				payload: {
					logs,
				},
			})
		);
	}

	streamLogs(serviceName, ws);
}

